// Catálogo D&D 5e — PT-BR (gerado via export-seed.ts)

type SpellSeed = {
  name: string; level: number; school: string;
  castingTime: string; range: string; duration: string;
  componentV: boolean; componentS: boolean; componentM: boolean;
  materialComponent?: string; description: string; classes: string[];
  ritual: boolean; concentration: boolean; higherLevel?: string;
};

function sp(
  name: string, level: number, school: string,
  castingTime: string, range: string, duration: string,
  v: boolean, s: boolean, m: boolean, material: string,
  description: string, classes: string[],
  ritual: boolean, concentration: boolean, higherLevel: string,
): SpellSeed {
  return { name, level, school, castingTime, range, duration,
    componentV: v, componentS: s, componentM: m,
    ...(material ? { materialComponent: material } : {}),
    description, classes, ritual, concentration,
    ...(higherLevel ? { higherLevel } : {}) };
}

export const DND_SPELLS_SEED: SpellSeed[] = [
  sp("Ataque Certeiro", 0, "Adivinhação", "1 ação", "30 pés", "Até 1 rodada", false, true, false, "", "Você estende a mão e aponta o dedo para um alvo ao alcance. Sua magia lhe concede uma breve visão sobre as defesas do alvo. No seu próximo turno, você ganha vantagem no seu primeiro ataque contra o alvo, desde que este feitiço não tenha terminado.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, true, ""),
  sp("Bastão da Natureza", 0, "Transmutação", "1 ação bônus", "Toque", "1 minuto", true, true, true, "Visco, uma folha de trevo e um bastão ou quarterstaff.", "A madeira de um bastão ou quarterstaff que você está segurando é imbuída com o poder da natureza. Pela duração, você pode usar sua habilidade de lançamento de magia no lugar de Força para os testes de ataque e dano de ataques corpo a corpo usando essa arma, e o dado de dano da arma se torna um d8. A arma também se torna mágica, se ainda não for. A magia termina se você a lançar novamente ou se soltar a arma.", ["Druida"], false, false, ""),
  sp("Chama Sagrada", 0, "Evocação", "1 ação", "60 pés", "Instantâneo", true, true, false, "", "Uma radiância semelhante a chamas desce sobre uma criatura que você possa ver dentro do alcance. O alvo deve fazer um teste de salvação de destreza ou sofrer 1d8 de dano radiante. O alvo não ganha nenhum benefício de cobertura para este teste de salvação. O dano do feitiço aumenta em 1d8 quando você atinge o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).", ["Clérico"], false, false, ""),
  sp("Consertar", 0, "Transmutação", "1 minuto", "Toque", "Instantânea", true, true, true, "Dois ímãs.", "Esta magia repara uma única quebra ou rasgadura em um objeto que você toca, como uma chave quebrada, uma capa rasgada ou um odre com vazamento. Contanto que a quebra ou rasgadura não seja maior que 1 pé em qualquer dimensão, você a conserta, deixando nenhum vestígio do dano anterior. Esta magia pode reparar fisicamente um item mágico ou construto, mas a magia não consegue restaurar magia a tal objeto.", ["Clérico", "Bardo", "Druida", "Feiticeiro", "Mago"], false, false, ""),
  sp("Explosão Sobrenatural", 0, "Evocação", "1 ação", "120 pés", "Instantâneo", true, true, false, "", "Um raio de energia crepitante passa em direção a uma criatura dentro do alcance. Faça um ataque de magia à distância contra o alvo. Em um acerto, o alvo sofre 1d10 de dano de força.", ["Bruxo"], false, false, "A magia cria mais de um raio quando você atinge níveis mais altos: dois raios no 5º nível, três raios no 11º nível e quatro raios no 17º nível. Você pode direcionar os raios para o mesmo alvo ou para alvo diferentes. Faça um teste de ataque separado para cada raio."),
  sp("Ilusão Menor", 0, "Ilusão", "1 ação", "30 pés", "1 minuto", false, true, true, "Um pouco de lã.", "Você cria um som ou a imagem de um objeto dentro do alcance que dura pela duração. A ilusão também termina se você a descartar como uma ação ou lançar este feitiço novamente. Se você criar um som, seu volume pode variar de um sussurro a um grito. Pode ser sua voz, a voz de outra pessoa, o rugido de um leão, o bater de tambores, ou qualquer outro som que você escolha. O som continua ininterrupto durante a duração, ou você pode fazer sons discretos em momentos diferentes antes do feitiço terminar. Se você criar a imagem de um objeto—como uma cadeira, pegadas enlameadas ou um pequeno baú—ela não deve ser maior que um cubo de 5 pés. A imagem não pode criar som, luz, cheiro ou qualquer outro efeito sensorial. A interação física com a imagem a revela como uma ilusão, porque as coisas podem passar através dela. Se uma criatura usar sua ação para examinar o som ou a imagem, a criatura pode determinar que é uma ilusão com um teste bem-sucedido de Inteligência (Investigação) contra sua CD de salvação de feitiço. Se uma criatura discerne a ilusão pelo que é, a ilusão se torna fraca para a criatura.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Luz", 0, "Evocação", "1 ação", "Toque", "1 hora", true, false, true, "Um vaga-lume ou musgo fosforescente.", "Você toca um objeto que não é maior que 10 pés em nenhuma dimensão. Até o término do feitiço, o objeto emite luz brilhante em um raio de 20 pés e luz fraca por mais 20 pés adicionais. A luz pode ser colorida como você desejar. Cobrir completamente o objeto com algo opaco bloqueia a luz. O feitiço termina se você o lançar novamente ou o dispensar como uma ação. Se você alvejar um objeto mantido ou usado por uma criatura hostil, essa criatura deve ser bem-sucedida em um teste de salvamento de destreza para evitar o feitiço.", ["Bardo", "Clérico", "Feiticeiro", "Mago"], false, false, ""),
  sp("Luzes Dançantes", 0, "Evocação", "1 ação", "120 pés", "Até 1 minuto", true, true, true, "Um pouco de fósforo ou wychwood, ou uma vaga-lume.", "Você cria até quatro luzes do tamanho de uma tocha ao alcance, fazendo-as aparecer como tochas, lanternas, ou orbes brilhantes que flutuam no ar pela duração. Você também pode combinar as quatro luzes em uma forma vaguamente humanóide brilhante de tamanho Médio. Qualquer que seja a forma que você escolha, cada luz emite luz fraca em um raio de 10 pés. Como uma ação bônus em seu turno, você pode mover as luzes até 60 pés para um novo local ao alcance. Uma luz deve estar dentro de 20 pés de outra luz criada por este feitiço, e uma luz pisca se exceder o alcance do feitiço.", ["Bardo", "Feiticeiro", "Mago"], false, true, ""),
  sp("Magia Druídica", 0, "Transmutação", "1 ação", "30 pés", "Instantâneo", true, true, false, "", "Sussurrando aos espíritos da natureza, você cria um dos seguintes efeitos dentro do alcance: - Você cria um efeito sensorial minúsculo e inofensivo que prediz como será o clima em sua localização nas próximas 24 horas. O efeito pode se manifestar como uma esfera dourada para céus claros, uma nuvem para chuva, flocos de neve caindo para neve e assim por diante. Este efeito persiste por 1 rodada. - Você instantaneamente faz uma flor desabrochar, uma vagem se abrir ou um broto de folha desabrochar. - Você cria um efeito sensorial instantâneo e inofensivo, como folhas caindo, uma rajada de vento, o som de um pequeno animal ou o odor fraco de gambá. O efeito deve caber em um cubo de 5 pés. - Você instantaneamente acende ou apaga uma vela, uma tocha ou uma pequena fogueira.", ["Druida"], false, false, ""),
  sp("Mão Mágica", 0, "Conjuração", "1 ação", "30 pés", "1 minuto", true, true, false, "", "Uma mão espectral flutuante aparece em um ponto de sua escolha dentro do alcance. A mão persiste pela duração ou até você dispensá-la como uma ação. A mão desaparece se ficar a mais de 30 pés de você ou se você lançar este feitiço novamente. Você pode usar sua ação para controlar a mão. Você pode usar a mão para manipular um objeto, abrir uma porta ou recipiente destrancado, guardar ou recuperar um item de um recipiente aberto ou despejar o conteúdo de um frasco. Você pode mover a mão até 30 pés cada vez que a usa. A mão não pode atacar, ativar itens mágicos ou carregar mais de 10 libras.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Mensagem", 0, "Transmutação", "1 ação", "120 pés", "1 rodada", true, true, true, "Um pedaço curto de arame de cobre.", "Você aponta seu dedo para uma criatura dentro do alcance e sussurra uma mensagem. O alvo (e somente o alvo) ouve a mensagem e pode responder em um sussurro que apenas você consegue ouvir. Você pode lançar esta magia através de objetos sólidos se você for familiar com o alvo e souber que está além da barreira. Silêncio mágico, 1 pé de pedra, 1 polegada de metal comum, uma fina folha de chumbo, ou 3 pés de madeira bloqueiam a magia. A magia não precisa seguir uma linha reta e pode viajar livremente ao redor de esquinas ou através de aberturas.", ["Bardo", "Feiticeiro", "Mago"], false, false, ""),
  sp("Orientação", 0, "Adivinhação", "1 ação", "Toque", "Até 1 minuto", true, true, false, "", "Você toca uma criatura voluntária. Uma vez antes da magia terminar, o alvo pode rolar um d4 e adicionar o número rolado a uma verificação de habilidade de sua escolha. Ele pode rolar o dado antes ou depois de fazer a verificação de habilidade. A magia termina então.", ["Clérico", "Druida"], false, true, ""),
  sp("Poupar o Morrente", 0, "Necromancia", "1 ação", "Toque", "Instantâneo", true, true, false, "", "Você toca uma criatura viva que tem 0 pontos de vida. A criatura fica estável. Esta magia não tem efeito em mortos-vivos ou constructos.", ["Clérico"], false, false, ""),
  sp("Produzir Chama", 0, "Conjuração", "1 ação", "Self", "10 minutos", true, true, false, "", "Uma chama cintilante aparece em sua mão. A chama permanece lá pela duração e não prejudica você nem seu equipamento. A chama emite luz brilhante em um raio de 10 pés e luz fraca por mais 10 pés. A magia termina se você a dispensar como uma ação ou se a conjurar novamente. Você também pode atacar com a chama, embora fazer isso termine a magia. Quando você conjura esta magia, ou como uma ação em um turno posterior, você pode arremessar a chama contra uma criatura dentro de 30 pés de você. Faça um ataque de magia à distância. Em um acerto, o alvo sofre 1d8 de dano de fogo. O dano desta magia aumenta em 1d8 quando você alcança o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).", ["Druida"], false, false, ""),
  sp("Raio de Fogo", 0, "Evocação", "1 ação", "120 pés", "Instantâneo", true, true, false, "", "Você lança uma centelha de fogo contra uma criatura ou objeto ao alcance. Faça um ataque de magia à distância contra o alvo. Em um acerto, o alvo sofre 1d10 de dano de fogo. Um objeto inflamável atingido por esta magia pega fogo se não estiver sendo usado ou carregado. O dano desta magia aumenta em 1d10 quando você atinge o 5º nível (2d10), 11º nível (3d10) e 17º nível (4d10).", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Raio de Gelo", 0, "Evocação", "1 ação", "60 pés", "Instantâneo", true, true, false, "", "Um raio gelado de luz azul-branca avança em direção a uma criatura dentro do alcance. Faça um teste de ataque de magia à distância contra o alvo. Em um acerto, ele sofre 1d8 de dano frio, e sua velocidade é reduzida em 10 pés até o início de seu próximo turno. O dano da magia aumenta em 1d8 quando você atinge o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Resistência", 0, "Abjuração", "1 ação", "Toque", "Até 1 minuto", true, true, true, "Uma capa em miniatura.", "Você toca uma criatura disposta. Uma vez antes de a magia terminar, o alvo pode lançar um d4 e adicionar o número obtido a um teste de salvação de sua escolha. Pode lançar o dado antes ou depois de fazer o teste de salvação. A magia então termina.", ["Clérico", "Druida"], false, true, ""),
  sp("Respingo Ácido", 0, "Conjuração", "1 ação", "60 pés", "Instantâneo", true, true, false, "", "Você lança uma bolha de ácido. Escolha uma criatura dentro do alcance, ou escolha duas criaturas dentro do alcance que estejam a até 5 pés uma da outra. Um alvo deve fazer um teste de salvação de Destreza ou sofrer 1d6 de dano de ácido. O dano desta magia aumenta em 1d6 quando você atinge o 5º nível (2d6), 11º nível (3d6) e 17º nível (4d6).", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Spray de Veneno", 0, "Conjuração", "1 ação", "10 pés", "Instantâneo", true, true, false, "", "Você estende a mão em direção a uma criatura que pode ver dentro do alcance e projeta uma nuvem de gás nocivo de sua palma. A criatura deve ter sucesso em um teste de resistência de constituição ou sofrer 1d12 de dano de veneno. O dano desta magia aumenta em 1d12 quando você atinge 5º nível (2d12), 11º nível (3d12) e 17º nível (4d12).", ["Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Taumaturgia", 0, "Transmutação", "1 ação", "9 metros", "1 minuto", true, false, false, "", "Você manifesta um pequeno prodígio, um sinal de poder sobrenatural, no alcance. Você cria um dos seguintes efeitos mágicos no alcance. - Sua voz soa até três vezes mais alta do que o normal por 1 minuto. - Você faz chamas tremulearem, brilharem, escurecerem ou mudarem de cor por 1 minuto. - Você causa tremores inofensivos no chão por 1 minuto. - Você cria um som instantâneo que origina de um ponto de sua escolha no alcance, como um trovão, o grito de um corvo, ou sussurros sinistros. - Você faz instantaneamente uma porta ou janela destrancada voar aberta ou bater fechada. - Você altera a aparência de seus olhos por 1 minuto. Se você lançar este feitiço múltiplas vezes, você pode ter até três de seus efeitos de 1 minuto ativos ao mesmo tempo, e você pode dispensar tal efeito como uma ação.", ["Clérico"], false, false, ""),
  sp("Toque Elétrico", 0, "Evocação", "1 ação", "Toque", "Instantâneo", true, true, false, "", "Eletricidade salta de sua mão para desferir um choque em uma criatura que você tenta tocar. Faça um teste de ataque corpo a corpo com magia contra o alvo. Você tem vantagem no teste de ataque se o alvo estiver usando armadura feita de metal. Se acertar, o alvo sofre 1d8 de dano de eletricidade, e não pode realizar reações até o início do seu próximo turno. O dano da magia aumenta em 1d8 quando você atinge o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Toque Glacial", 0, "Necromancia", "1 ação", "36 metros", "1 rodada", true, true, false, "", "Você cria uma mão espectral e esquelética no espaço de uma criatura dentro do alcance. Faça um ataque de feitiço à distância contra a criatura para atacá-la com o frio da tumba. Em um acerto, o alvo recebe 1d8 de dano necrótico e não pode recuperar pontos de vida até o início do seu próximo turno. Até então, a mão se agarra ao alvo. Se você acertar um alvo morto-vivo, ele também tem desvantagem em testes de ataque contra você até o final do seu próximo turno. O dano deste feitiço aumenta em 1d8 quando você atinge o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).", ["Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Truque de Prestidigitação", 0, "Transmutação", "1 ação", "10 pés", "1 hora", true, true, false, "", "Esta magia é um truque mágico menor que aprendizes de lançadores de magia usam para praticar. Você cria um dos seguintes efeitos mágicos dentro do alcance: Você cria um efeito sensorial instantâneo e inofensivo, como um chuveiro de faíscas, uma rajada de vento, notas musicais fracas ou um odor estranho. Você acende ou apaga instantaneamente uma vela, uma tocha ou uma pequena fogueira. Você limpa ou suja instantaneamente um objeto não maior que 1 pé cúbico. Você resfria, aquece ou tempera até 1 pé cúbico de material não vivo por 1 hora. Você faz uma cor, uma pequena marca ou um símbolo aparecer em um objeto ou superfície por 1 hora. Você cria uma bugigangas não mágica ou uma imagem ilusória que cabe em sua mão e que dura até o final de seu próximo turno. Se você lançar esta magia várias vezes, você pode ter até três de seus efeitos não instantâneos ativos ao mesmo tempo, e você pode descartar tal efeito como uma ação.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Zombaria Venenosa", 0, "Encantamento", "1 ação", "60 pés", "Instantâneo", true, false, false, "", "Você solta uma série de insultos carregados com sutis encantamentos contra uma criatura que você pode ver ao alcance. Se o alvo conseguir ouvi-lo (embora não precise entendê-lo), ele deve fazer um teste de Sabedoria ou receber 1d4 de dano psíquico e sofrer desvantagem no próximo ataque que fizer antes do fim do seu próximo turno. O dano deste feitiço aumenta em 1d4 quando você alcança o 5º nível (2d4), 11º nível (3d4) e 17º nível (4d4).", ["Bardo"], false, false, ""),
  sp("Alarme", 1, "Abjuração", "1 minuto", "30 pés", "8 horas", true, true, true, "Um sino minúsculo e um pedaço de fio de prata fino.", "Você configura um alarme contra intrusão indesejada. Escolha uma porta, janela ou uma área dentro do alcance que não seja maior que um cubo de 20 pés. Até o término da magia, um alarme o alerta sempre que uma criatura Minúscula ou maior toca ou entra na área protegida. Quando você lança a magia, pode designar criaturas que não acionarão o alarme. Você também escolhe se o alarme é mental ou audível. Um alarme mental o alerta com um ping em sua mente se você estiver a até 1 milha da área protegida. Este ping o desperta se você estiver dormindo. Um alarme audível produz o som de um sino de mão por 10 segundos em um raio de 60 pés.", ["Patrulheiro", "Mago"], true, false, ""),
  sp("Amizade Animal", 1, "Encantamento", "1 ação", "30 pés", "24 horas", true, true, true, "Um bocado de comida.", "Esta magia permite que você convença uma besta de que você não lhe quer mal. Escolha uma besta que você possa ver dentro do alcance. Ela deve vê-lo e ouvi-lo. Se a Inteligência da besta for 4 ou superior, a magia falha. Caso contrário, a besta deve fazer um teste de salvação de Sabedoria ou ser enfeitiçada por você pela duração da magia. Se você ou um de seus companheiros ferir o alvo, a magia termina.", ["Bardo", "Clérico", "Druida", "Patrulheiro"], false, false, ""),
  sp("Armadura Mágica", 1, "Abjuração", "1 ação", "Toque", "8 horas", true, true, true, "Um pedaço de couro curtido.", "Você toca uma criatura disposta que não esteja usando armadura, e uma força mágica protetora a envolve até o fim da magia. A CA base do alvo se torna 13 + seu modificador de Destreza. A magia termina se o alvo vestir uma armadura ou se você descartar a magia com uma ação.", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Bênção", 1, "Encantamento", "1 ação", "30 pés", "Até 1 minuto", true, true, true, "Um polvilho de água benta.", "Você abençoa até três criaturas de sua escolha dentro do alcance. Sempre que um alvo fizer um teste de ataque ou um teste de resistência antes da magia terminar, o alvo pode rolar um d4 e adicionar o número rolado ao teste de ataque ou teste de resistência.", ["Clérico", "Paladino"], false, true, "Quando você lança esta magia usando um espaço de magia de 2º nível ou superior, você pode designar uma criatura adicional para cada nível de espaço acima do 1º."),
  sp("Chuva Colorida", 1, "Ilusão", "1 ação", "Self", "1 rodada", true, true, true, "Um punhado de pó ou areia que é colorido de vermelho, amarelo e azul.", "Uma gama deslumbrante de luzes coloridas piscantes brotam de sua mão. Role 6d10; o total é quantos pontos de vida de criaturas esta magia pode afetar. Criaturas em um cone de 15 pés originário de você são afetadas em ordem crescente de seus pontos de vida atuais (ignorando criaturas inconscientes e criaturas que não podem ver). Começando com a criatura que tem o menor número de pontos de vida atuais, cada criatura afetada por esta magia fica cega até a magia acabar. Subtraia os pontos de vida de cada criatura do total antes de passar para a criatura com o próximo número mais baixo de pontos de vida. Os pontos de vida de uma criatura devem ser iguais ou menores que o total restante para que essa criatura seja afetada.", ["Feiticeiro", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 2º nível ou superior, role 2d10 adicionais para cada nível de espaço acima do 1º."),
  sp("Comando", 1, "Encantamento", "1 ação", "60 pés", "1 rodada", true, false, false, "", "Você fala um comando de uma palavra para uma criatura que você possa ver dentro do alcance. O alvo deve ser bem-sucedido em um teste de resistência de Sabedoria ou seguir o comando em seu próximo turno. A magia não tem efeito se o alvo for morto-vivo, se não entender seu idioma, ou se seu comando for diretamente prejudicial a ele. Alguns comandos típicos e seus efeitos seguem. Você pode emitir um comando diferente daquele descrito aqui. Se o fizer, o Mestre determina como o alvo se comporta. Se o alvo não puder seguir seu comando, a magia termina. Aproxime-se. O alvo se move em sua direção pelo caminho mais curto e direto, terminando seu turno se se mover para 5 pés de você. Solte. O alvo solta o que está segurando e então termina seu turno. Fuja. O alvo gasta seu turno se afastando de você pelos meios disponíveis mais rápidos. Rastejar. O alvo cai de bruços e então termina seu turno. Halt. O alvo não se move e não toma ações. Uma criatura voadora permanece no ar, desde que seja capaz de fazê-lo. Se precisar se mover para permanecer no ar, voa a distância mínima necessária para permanecer no ar.", ["Clérico", "Paladino"], false, false, "Quando você lança esta magia usando um espaço de magia de 2º nível ou superior, você pode afetar uma criatura adicional para cada nível de espaço acima do 1º. As criaturas devem estar dentro de 30 pés uma da outra quando você as alvo."),
  sp("Compreender Idiomas", 1, "Adivinhação", "1 ação", "Pessoal", "1 hora", true, true, true, "Uma pitada de fuligem e sal", "Pela duração da magia, você compreende o significado literal de qualquer idioma falado que ouve. Você também compreende qualquer idioma escrito que vê, mas deve estar tocando a superfície na qual as palavras estão escritas. Leva aproximadamente 1 minuto para ler uma página de texto. Esta magia não decodifica mensagens secretas em um texto ou um glifo, como um sigilo arcano, que não faz parte de um idioma escrito.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], true, false, ""),
  sp("Criar ou Destruir Água", 1, "Transmutação", "1 ação", "30 pés", "Instantâneo", true, true, true, "Uma gota de água se criando água, ou alguns grãos de areia se destruindo.", "Você cria ou destrói água. Criar Água. Você cria até 10 galões de água limpa ao alcance em um recipiente aberto. Alternativamente, a água cai como chuva em um cubo de 30 pés ao alcance. Destruir Água. Você destrói até 10 galões de água em um recipiente aberto ao alcance. Alternativamente, você destrói neblina em um cubo de 30 pés ao alcance.", ["Clérico", "Druida"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 2º nível ou superior, você cria ou destrói 10 galões adicionais de água, ou o tamanho do cubo aumenta em 5 pés, para cada nível de espaço acima do 1º."),
  sp("Curar Ferimentos", 1, "Evocação", "1 ação", "Toque", "Instantâneo", true, true, false, "", "Uma criatura que você toca recupera um número de pontos de vida igual a 1d8 + seu modificador de habilidade de lançamento de feitiços. Este feitiço não tem efeito em mortos-vivos ou construtos.", ["Bardo", "Clérico", "Druida", "Paladino", "Patrulheiro"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 2º nível ou superior, a cura aumenta em 1d8 para cada nível de espaço acima do 1º."),
  sp("Detectar Bem e Mal", 1, "Adivinhação", "1 ação", "Pessoal", "Até 10 minutos", true, true, false, "", "Pela duração, você sabe se há uma aberração, celestial, elemental, fada, fiend ou morto-vivo dentro de 9 metros de você, bem como onde a criatura está localizada. Da mesma forma, você sabe se há um lugar ou objeto dentro de 9 metros de você que foi magicamente consagrado ou desacralizado. O feitiço pode penetrar a maioria das barreiras, mas é bloqueado por 30 centímetros de pedra, 2,5 centímetros de metal comum, uma folha fina de chumbo, ou 90 centímetros de madeira ou terra.", ["Clérico", "Paladino"], false, true, ""),
  sp("Detectar Magia", 1, "Adivinhação", "1 ação", "Pessoal", "Até 10 minutos", true, true, false, "", "Pela duração, você sente a presença de magia dentro de 30 pés de você. Se sentir magia dessa forma, pode usar sua ação para ver uma aura fraca ao redor de qualquer criatura ou objeto visível na área que possua magia, e aprende sua escola de magia, se houver. A magia pode penetrar a maioria das barreiras, mas é bloqueada por 1 pé de pedra, 1 polegada de metal comum, uma folha fina de chumbo, ou 3 pés de madeira ou terra.", ["Bardo", "Clérico", "Druida", "Paladino", "Patrulheiro", "Feiticeiro", "Mago"], true, true, ""),
  sp("Detectar Veneno e Doença", 1, "Adivinhação", "1 ação", "Pessoal", "Até 10 minutos", true, true, true, "Uma folha de teixo.", "Pela duração, você pode sentir a presença e localização de venenos, criaturas venenosas e doenças dentro de 30 pés de você. Você também identifica o tipo de veneno, criatura venenosa ou doença em cada caso. A magia pode penetrar a maioria das barreiras, mas é bloqueada por 1 pé de pedra, 1 polegada de metal comum, uma folha fina de chumbo, ou 3 pés de madeira ou terra.", ["Clérico", "Druida", "Paladino", "Patrulheiro"], true, true, ""),
  sp("Disco Flutuante", 1, "Conjuração", "1 ação", "30 pés", "1 hora", true, true, true, "Uma gota de mercúrio.", "Esta magia cria um plano circular e horizontal de força, com 3 pés de diâmetro e 1 polegada de espessura, que flutua 3 pés acima do solo em um espaço desocupado de sua escolha que você possa ver dentro do alcance. O disco permanece pela duração e pode suportar até 500 libras. Se mais peso for colocado nele, a magia termina e tudo no disco cai para o solo. O disco é imóvel enquanto você está dentro de 20 pés dele. Se você se afastar mais de 20 pés, o disco o segue para permanecer dentro de 20 pés de você. Ele pode se mover sobre terreno irregular, subir ou descer escadas, encostas e assim por diante, mas não pode atravessar uma mudança de elevação de 10 pés ou mais. Por exemplo, o disco não pode se mover através de um fosso de 10 pés de profundidade, nem poderia sair de tal fosso se fosse criado no fundo. Se você se afastar mais de 100 pés do disco (normalmente porque ele não consegue se mover ao redor de um obstáculo para segui-lo), a magia termina.", ["Mago"], true, false, ""),
  sp("Disfarçar-se", 1, "Ilusão", "1 ação", "Pessoal", "1 hora", true, true, false, "", "Você faz a si mesmo -- incluindo suas roupas, armadura, armas e outros pertences em sua pessoa -- parecer diferente até que a magia termine ou até que você use sua ação para dispensá-la. Você pode parecer 1 pé mais baixo ou mais alto e pode parecer fino, gordo, ou no meio termo. Você não pode mudar seu tipo de corpo, então deve adotar uma forma que tenha o mesmo arranjo básico de membros. Caso contrário, a extensão da ilusão é até você. As mudanças feitas por esta magia falham em resistir a uma inspeção física. Por exemplo, se usar esta magia para adicionar um chapéu ao seu traje, objetos passam através do chapéu, e qualquer um que o toque não sentiria nada ou sentiria sua cabeça e cabelo. Se usar esta magia para parecer mais fino do que é, a mão de alguém que se estenda para tocá-lo colidiria com você enquanto ainda estivesse aparentemente no ar. Para discernir que você está disfarçado, uma criatura pode usar sua ação para inspecionar sua aparência e deve ter sucesso em um teste de Inteligência (Investigação) contra seu CD de teste de magia.", ["Bardo", "Feiticeiro", "Mago"], false, false, ""),
  sp("Encontrar Familiar", 1, "Conjuração", "1 hora", "3 metros", "Instantâneo", true, true, true, "10 peças de ouro em carvão, incenso e ervas que devem ser consumidas pelo fogo em um braseiro de latão.", "Você ganha o serviço de um familiar, um espírito que toma a forma de um animal que você escolhe: morcego, gato, caranguejo, sapo, falcão, lagarto, polvo, coruja, cobra venenosa, peixe (peixe-agulha), rato, corvo, cavalo-marinho, aranha ou doninha. Aparecendo em um espaço desocupado dentro do alcance, o familiar tem as estatísticas da forma escolhida, mas é uma criatura celestial, feérica ou fiend (sua escolha) em vez de uma besta. Seu familiar age independentemente de você, mas sempre obedece seus comandos. Em combate, ele tira sua própria iniciativa e age em seu turno. Um familiar não pode atacar, mas pode executar outras ações normalmente. Quando o familiar chega a 0 pontos de vida, ele desaparece, sem deixar forma física. Ele reaparece quando você lança essa magia novamente. Enquanto seu familiar está a até 30 metros de você, você pode se comunicar com ele telepaticamente. Além disso, como uma ação, você pode ver através dos olhos de seu familiar e ouvir o que ele ouve até o início de seu próximo turno, ganhando os benefícios de qualquer sentido especial que o familiar tenha. Durante esse tempo, você fica surdo e cego em relação aos seus próprios sentidos. Como uma ação, você pode dispensar temporariamente seu familiar. Ele desaparece em uma dimensão de bolso onde espera seus comandos. Como alternativa, você pode dispensá-lo para sempre. Como uma ação enquanto está temporariamente dispensado, você pode fazê-lo reaparecer em qualquer espaço desocupado a até 9 metros de você. Você não pode ter mais de um familiar por vez. Se você lançar essa magia enquanto já tem um familiar, você o faz adotar uma nova forma. Escolha uma das formas da lista acima. Seu familiar se transforma na criatura escolhida. Por fim, quando você lança uma magia com alcance de toque, seu familiar pode entregar a magia como se a tivesse lançado. Seu familiar deve estar a até 30 metros de você e deve usar sua reação para entregar a magia quando você a lança. Se a magia exigir um ataque, você usa seu modificador de ação para o teste.", ["Mago"], true, false, ""),
  sp("Enfeitiçar Pessoa", 1, "Encantamento", "1 ação", "9 metros", "1 hora", true, true, false, "", "Você tenta enfeitiçar um humanóide que você possa ver dentro do alcance. Ele deve fazer um teste de salvação de Sabedoria, e o faz com vantagem se você ou seus companheiros estão lutando com ele. Se ele falhar no teste de salvação, ele fica enfeitiçado por você até o feitiço terminar ou até que você ou seus companheiros façam algo prejudicial a ele. A criatura enfeitiçada o considera um conhecido amigável. Quando o feitiço termina, a criatura sabe que foi enfeitiçada por você.", ["Bardo", "Druida", "Feiticeiro", "Bruxo", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 2º nível ou superior, você pode designar uma criatura adicional para cada nível de espaço acima do 1º. As criaturas devem estar a até 9 metros uma da outra quando você as designa."),
  sp("Enredar", 1, "Conjuração", "1 ação", "90 pés", "Até 1 minuto", true, true, false, "", "Ervas e vinhas apreensivas brotam do solo em um quadrado de 20 pés começando a partir de um ponto ao alcance. Pela duração, essas plantas transformam o solo na área em terreno difícil. Uma criatura na área quando você lança a magia deve ter sucesso em um teste de resistência de Força ou fica contida pelas plantas enredantes até o final da magia. Uma criatura contida pelas plantas pode usar sua ação para fazer um teste de Força contra sua CD de resistência de magia. Se bem-sucedida, se liberta. Quando a magia termina, as plantas invocadas murcham.", ["Druida"], false, true, ""),
  sp("Escrita Ilusória", 1, "Ilusão", "1 minuto", "Toque", "10 dias", false, true, true, "Uma tinta à base de chumbo no valor de pelo menos 10 po, que esta magia consome.", "Você escreve em pergaminho, papel ou outro material de escrita adequado e o impregna com uma ilusão potente que dura pela duração. Para você e qualquer criatura que designar quando lançar a magia, a escrita aparece normal, escrita em sua letra, e transmite o significado que pretendeu ao escrever o texto. Para todos os outros, a escrita aparece como se fosse escrita em uma escrita desconhecida ou mágica que é ininteligível. Alternativamente, você pode fazer a escrita parecer uma mensagem completamente diferente, escrita em letra e idioma diferentes, embora o idioma deva ser um que conhece. Se a magia for dissipada, a escrita original e a ilusão desaparecem. Uma criatura com visão verdadeira pode ler a mensagem oculta.", ["Bardo", "Bruxo", "Mago"], true, false, ""),
  sp("Escudo", 1, "Abjuração", "1 reação", "Pessoal", "1 rodada", true, true, false, "", "Uma barreira invisível de força mágica aparece e o protege. Até o início do seu próximo turno, você tem um bônus de +5 para CA, inclusive contra o ataque desencadeador, e você não sofre dano de Míssil Mágico.", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Escudo da Fé", 1, "Abjuração", "1 ação bônus", "60 pés", "Até 10 minutos", true, true, true, "Um pequeno pergaminho com um trecho de texto sagrado escrito nele.", "Um campo brilhante aparece e envolve uma criatura de sua escolha ao alcance, concedendo a ela um bônus de +2 para CA pela duração.", ["Clérico", "Paladino"], false, true, ""),
  sp("Falar com Animais", 1, "Adivinhação", "1 ação", "Pessoal", "10 minutos", true, true, false, "", "Você ganha a capacidade de compreender e se comunicar verbalmente com bestas pela duração. O conhecimento e a percepção de muitas bestas são limitados por sua inteligência, mas no mínimo, bestas podem lhe dar informações sobre locais e monstros próximos, incluindo tudo que possam perceber ou tenham percebido no último dia. Você pode ser capaz de persuadir uma besta a executar um pequeno favor para você, a critério do Mestre.", ["Bardo", "Druida", "Patrulheiro"], true, false, ""),
  sp("Favor Divino", 1, "Evocação", "1 ação bônus", "Pessoal", "Até 1 minuto", true, true, false, "", "Sua prece o empodera com radiância divina. Até a magia terminar, seus ataques com arma causam 1d4 de dano radiante adicional em um acerto.", ["Paladino"], false, true, ""),
  sp("Fogo Féerico", 1, "Evocação", "1 ação", "60 pés", "Até 1 minuto", true, false, false, "", "Cada objeto em um cubo de 20 pés dentro do alcance é delineado em luz azul, verde ou violeta (sua escolha). Qualquer criatura na área quando a magia é lançada também é delineada em luz se falhar em um teste de resistência de Destreza. Pela duração, objetos e criaturas afetadas emitem luz fraca em um raio de 10 pés. Qualquer teste de ataque contra uma criatura ou objeto afetado tem vantagem se o atacante conseguir vê-lo, e a criatura ou objeto afetado não pode se beneficiar de ser invisível.", ["Druida"], false, true, ""),
  sp("Fruto Benção", 1, "Transmutação", "1 ação", "Toque", "Instantânea", true, true, true, "Um ramo de visco.", "Até dez bagas aparecem em sua mão e são imbuídas de magia pela duração. Uma criatura pode usar sua ação para comer uma baga. Comer uma baga restaura 1 ponto de vida e a baga fornece nutrição suficiente para sustentar uma criatura por um dia. As bagas perdem sua potência se não forem consumidas dentro de 24 horas do lançamento desta magia.", ["Druida", "Patrulheiro"], false, false, ""),
  sp("Graxa", 1, "Conjuração", "1 ação", "60 pés", "1 minuto", true, true, true, "Um pouco de couro de porco ou manteiga.", "Graxa escorregadia cobre o chão em um quadrado de 10 pés centrado em um ponto dentro do alcance e o transforma em terreno difícil pela duração. Quando a graxa aparece, cada criatura em pé em sua área deve ter sucesso em um teste de resistência de Destreza ou cai derrubada. Uma criatura que entra na área ou termina seu turno lá também deve ter sucesso em um teste de resistência de Destreza ou cai derrubada.", ["Mago"], false, false, ""),
  sp("Heroísmo", 1, "Encantamento", "1 ação", "Toque", "Até 1 minuto", true, true, false, "", "Uma criatura disposta que você toca é imbuída de coragem. Até o fim da magia, a criatura é imune a medo e ganha pontos de vida temporários iguais ao seu modificador de habilidade de conjuração no início de cada um de seus turnos. Quando a magia termina, o alvo perde quaisquer pontos de vida temporários restantes dessa magia.", ["Bardo", "Paladino"], false, true, ""),
  sp("Identificar", 1, "Adivinhação", "1 minuto", "Toque", "Instantâneo", true, true, true, "Uma pérola no valor de pelo menos 100 po e uma pena de coruja.", "Você escolhe um objeto que deve tocar durante todo o tempo de lançamento da magia. Se for um item mágico ou outro objeto imbuído de magia, você aprende suas propriedades e como usá-las, se requer sintonização para usar e quantas cargas tem, se houver. Você aprende se alguma magia está afetando o item e quais são elas. Se o item foi criado por uma magia, você aprende qual magia o criou. Se tocar uma criatura durante todo o tempo de lançamento, você aprende quais magias, se houver, a estão afetando.", ["Bardo", "Mago"], true, false, ""),
  sp("Imagem Silenciosa", 1, "Ilusão", "1 ação", "60 pés", "Até 10 minutos", true, true, true, "Um pedaço de lã.", "Você cria a imagem de um objeto, uma criatura ou algum outro fenômeno visível que não é maior do que um cubo de 15 pés. A imagem aparece em um local dentro do alcance e dura pela duração. A imagem é puramente visual; não é acompanhada por som, cheiro ou outros efeitos sensoriais. Você pode usar sua ação para fazer a imagem se mover para qualquer local dentro do alcance. Conforme a imagem muda de localização, você pode alterar sua aparência para que seus movimentos pareçam naturais para a imagem. Por exemplo, se você criar a imagem de uma criatura e a mover, você pode alterar a imagem para que pareça estar andando. A interação física com a imagem a revela ser uma ilusão, porque as coisas podem passar através dela. Uma criatura que usa sua ação para examinar a imagem pode determinar que é uma ilusão com um teste bem-sucedido de Inteligência (Investigação) contra sua CD de salvamento de magia. Se uma criatura discerne a ilusão pelo que ela é, a criatura pode ver através da imagem.", ["Bardo", "Feiticeiro", "Mago"], false, true, ""),
  sp("Infligir Ferimentos", 1, "Necromancia", "1 ação", "Toque", "Instantâneo", true, true, false, "", "Faça um ataque de magia corpo a corpo contra uma criatura que você possa alcançar. Em um acerto, o alvo sofre 3d10 de dano necrótico.", ["Clérico"], false, false, "Quando você lança esta magia usando um espaço de magia de 2º nível ou superior, o dano aumenta em 1d10 para cada nível de espaço acima do 1º."),
  sp("Mãos Ardentes", 1, "Evocação", "1 ação", "Pessoal", "Instantâneo", true, true, false, "", "Enquanto você segura as mãos com os polegares se tocando e os dedos abertos, uma fina folha de chamas dispara das pontas dos seus dedos estendidos. Cada criatura em um cone de 15 pés deve fazer um teste de resistência de Destreza. Uma criatura sofre 3d6 de dano de fogo com uma falha, ou metade do dano com um sucesso. O fogo acende qualquer objeto inflamável na área que não esteja sendo vestido ou carregado.", ["Feiticeiro", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 2º nível ou superior, o dano aumenta em 1d6 para cada nível de espaço acima do 1º."),
  sp("Marca da Caça", 1, "Adivinhação", "1 ação bônus", "90 pés", "Até 1 hora", true, false, false, "", "Você escolhe uma criatura que possa ver ao alcance e a marca misticamente como sua presa. Até o final da magia, você causa 1d6 de dano adicional ao alvo sempre que o acerta com um ataque de arma, e você tem vantagem em qualquer teste de Sabedoria (Percepção) ou Sabedoria (Sobrevivência) que fizer para encontrá-lo. Se o alvo cair para 0 pontos de vida antes da magia terminar, você pode usar uma ação bônus em um turno subsequente seu para marcar uma nova criatura.", ["Paladino", "Patrulheiro"], false, true, ""),
  sp("Míssil Mágico", 1, "Evocação", "1 ação", "120 pés", "Instantâneo", true, true, false, "", "Você cria três dardos brilhantes de força mágica. Cada dardo atinge uma criatura de sua escolha que você possa ver dentro do alcance. Um dardo causa 1d4 + 1 de dano de força a seu alvo. Os dardos atingem simultaneamente, e você pode dirigi-los para atingir uma criatura ou várias.", ["Feiticeiro", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 2º nível ou superior, o feitiço cria um dardo adicional para cada nível de espaço acima do 1º."),
  sp("Nuvem de Neblina", 1, "Conjuração", "1 ação", "120 pés", "Até 1 hora", true, true, false, "", "Você cria uma esfera de neblina com raio de 20 pés centrada em um ponto dentro do alcance. A esfera se espalha ao redor de cantos, e sua área fica muito obscurecida. Dura pela duração ou até que um vento de velocidade moderada ou maior (pelo menos 10 milhas por hora) a dispersa.", ["Druida", "Patrulheiro", "Feiticeiro", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 2º nível ou superior, o raio da neblina aumenta em 20 pés para cada nível de espaço acima do 1º."),
  sp("Onda Trovejante", 1, "Evocação", "1 ação", "Pessoal", "Instantâneo", true, true, false, "", "Uma onda de força trovejante varre para longe de você. Cada criatura em um cubo de 4,5 metros originado de você deve fazer um teste de resistência de Constituição. Se falhar, uma criatura sofre 2d8 de dano de trovão e é empurrada 3 metros para longe de você. Se tiver sucesso, a criatura sofre metade do dano e não é empurrada. Além disso, objetos não garantidos que estão completamente dentro da área de efeito são automaticamente empurrados 3 metros para longe de você pelo efeito do feitiço, e o feitiço emite um estrondo trovejante audível até 90 metros de distância.", ["Bardo", "Druida", "Feiticeiro", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 2º nível ou superior, o dano aumenta em 1d8 para cada nível de espaço acima de 1º."),
  sp("Palavra de Cura", 1, "Evocação", "1 ação bônus", "60 pés", "Instantâneo", true, false, false, "", "Uma criatura à sua escolha que você possa ver dentro do alcance recupera pontos de vida iguais a 1d4 + seu modificador de habilidade de lançamento de magias. Esta magia não tem efeito em mortos-vivos ou constructos.", ["Bardo", "Clérico", "Druida"], false, false, "Quando você lança essa magia usando um espaço de magia de 2º nível ou superior, a cura aumenta em 1d4 para cada nível de espaço acima do 1º."),
  sp("Passada Gigante", 1, "Transmutação", "1 ação", "Toque", "1 hora", true, true, true, "Um pouco de terra.", "Você toca uma criatura. A velocidade do alvo aumenta em 3 metros até o fim da magia.", ["Bardo", "Druida", "Patrulheiro", "Mago"], false, false, "Quando você lança essa magia usando um espaço de magia de 2º nível ou superior, você pode afetar uma criatura adicional para cada nível acima do 1º."),
  sp("Perdição", 1, "Encantamento", "1 ação", "30 pés", "Até 1 minuto", true, true, true, "Uma gota de sangue.", "Até três criaturas de sua escolha que você possa ver em alcance devem fazer testes de resistência de Carisma. Sempre que um alvo que falha neste teste de resistência faz uma jogada de ataque ou um teste de resistência antes da magia terminar, o alvo deve rolar um d4 e subtrair o número rolado da jogada de ataque ou teste de resistência.", ["Bardo", "Clérico"], false, true, "Quando você lança esta magia usando um espaço de magia de 2º nível ou superior, você pode alvejar uma criatura adicional para cada nível de espaço acima do 1º."),
  sp("Proteção contra o Mal e o Bem", 1, "Abjuração", "1 ação", "Toque", "Até 10 minutos", true, true, true, "Água benta ou prata e ferro em pó, que a magia consome.", "Até o término da magia, uma criatura disposta que você toca fica protegida contra certos tipos de criaturas: aberrações, celestiais, elementais, fadas, diabos e mortos-vivos. A proteção oferece vários benefícios. Criaturas desses tipos têm desvantagem em testes de ataque contra o alvo. O alvo também não pode ser enfeitiçado, assustado ou possuído por elas. Se o alvo já está enfeitiçado, assustado ou possuído por tal criatura, o alvo tem vantagem em qualquer novo teste de resistência contra o efeito relevante.", ["Clérico", "Paladino", "Bruxo", "Mago"], false, true, ""),
  sp("Purificar Comida e Bebida", 1, "Transmutação", "1 ação", "10 pés", "Instantâneo", true, true, false, "", "Toda comida e bebida não mágica dentro de uma esfera de raio de 5 pés centrada em um ponto à sua escolha dentro do alcance é purificada e fica livre de veneno e doença.", ["Clérico", "Druida", "Paladino"], true, false, ""),
  sp("Queda Suave", 1, "Transmutação", "1 reação", "18 metros", "1 minuto", true, false, true, "Uma pequena pena ou um pedaço de penugem.", "Escolha até cinco criaturas caindo dentro do alcance. A velocidade de queda de uma criatura caindo diminui para 18 metros por rodada até o final da magia. Se a criatura pousar antes do final da magia, ela não sofre dano de queda e pode pousar em seus pés, e a magia termina para essa criatura.", ["Bardo", "Feiticeiro", "Mago"], false, false, ""),
  sp("Raio Orientador", 1, "Evocação", "1 ação", "120 pés", "1 rodada", true, true, false, "", "Um lampejo de luz segue na direção de uma criatura de sua escolha ao alcance. Faça um ataque de magia à distância contra o alvo. Em um acerto, o alvo sofre 4d6 de dano radiante, e o próximo ataque feito contra este alvo antes do final de seu próximo turno tem vantagem, graças à luz mística brilhando no alvo até então.", ["Clérico"], false, false, "Quando você lança esta magia usando um espaço de magia de 2º nível ou superior, o dano aumenta em 1d6 para cada nível de espaço acima do 1º."),
  sp("Retaliação Infernal", 1, "Evocação", "1 reação", "60 pés", "Instantâneo", true, true, false, "", "Você aponta o dedo, e a criatura que o feriu é momentaneamente cercada por chamas infernais. A criatura deve fazer um teste de resistência de Destreza. Ela sofre 2d10 de dano de fogo se falhar na resistência, ou metade desse dano se tiver sucesso.", ["Bruxo"], false, false, ""),
  sp("Retirada Apressada", 1, "Transmutação", "1 ação bônus", "Pessoal", "Até 10 minutos", true, true, false, "", "Essa magia permite que você se mova em um ritmo incrível. Quando você lança essa magia, e então como uma ação bônus em cada um de seus turnos até a magia terminar, você pode usar a ação Disparada.", ["Feiticeiro", "Bruxo", "Mago"], false, true, ""),
  sp("Riso Hediondo", 1, "Encantamento", "1 ação", "30 pés", "Até 1 minuto", true, true, true, "Pequenas tortas e uma pena que é agitada no ar.", "Uma criatura à sua escolha que você possa ver no alcance percebe tudo como hilariamente engraçado e cai em ataques de riso se essa magia a afetar. O alvo deve ter sucesso em um teste de resistência de Sabedoria ou cair deitado, ficando incapacitado e incapaz de se levantar pela duração. Uma criatura com uma pontuação de Inteligência de 4 ou menos não é afetada. Ao final de cada um de seus turnos, e cada vez que sofre dano, o alvo pode fazer outro teste de resistência de Sabedoria. O alvo tem vantagem no teste de resistência se for desencadeado por dano. Com sucesso, a magia termina.", ["Bardo", "Mago"], false, true, ""),
  sp("Salto", 1, "Transmutação", "1 ação", "Toque", "1 minuto", true, true, true, "A perna traseira de um gafanhoto.", "Você toca uma criatura. A distância de salto da criatura é triplicada até o término do feitiço.", ["Druida", "Patrulheiro", "Feiticeiro", "Mago"], false, false, ""),
  sp("Santuário", 1, "Abjuração", "1 ação bônus", "30 pés", "1 minuto", true, true, true, "Um pequeno espelho de prata.", "Você protege uma criatura dentro do alcance contra ataques. Até o feitiço acabar, qualquer criatura que atacar a criatura protegida com um ataque ou um feitiço prejudicial deve primeiro fazer um teste de salvação de sabedoria. Em um teste falhado, a criatura deve escolher um novo alvo ou perder o ataque ou feitiço. Este feitiço não protege a criatura protegida de efeitos em área, como a explosão de uma Bola de Fogo. Se a criatura protegida fizer um ataque ou lançar um feitiço que afete uma criatura inimiga, este feitiço acaba.", ["Clérico"], false, false, ""),
  sp("Servo Invisível", 1, "Conjuração", "1 ação", "60 pés", "1 hora", true, true, true, "Um pedaço de corda e um pouco de madeira.", "Este feitiço cria uma força invisível, sem mente e sem forma que realiza tarefas simples sob seu comando até que o feitiço termine. O servo aparece em um espaço desocupado no chão ao alcance. Ele tem CA 10, 1 ponto de vida e Força 2, e não pode atacar. Se cair para 0 pontos de vida, o feitiço termina. Uma vez a cada turno seu como uma ação bônus, você pode mentalmente comandar o servo para se mover até 15 pés e interagir com um objeto. O servo pode realizar tarefas simples que um servo humano poderia fazer, como buscar coisas, limpar, consertar, dobrar roupas, acender fogueiras, servir comida e derramar vinho. Uma vez que você dá o comando, o servo realiza a tarefa do melhor modo possível até completá-la, então aguarda seu próximo comando. Se você comandar o servo a realizar uma tarefa que o moveria mais de 60 pés de você, o feitiço termina.", ["Bardo", "Bruxo", "Mago"], true, false, ""),
  sp("Sono", 1, "Encantamento", "1 ação", "90 pés", "1 minuto", true, true, true, "Um polegar de areia fina, pétalas de rosa ou um grilo.", "Essa magia envia criaturas para um sono mágico. Role 5d8; o total é quantos pontos de vida de criaturas essa magia pode afetar. Criaturas dentro de 20 pés de um ponto de sua escolha dentro do alcance são afetadas em ordem crescente de seus pontos de vida atuais (ignorando criaturas inconscientes). Começando com a criatura que tem o menor número de pontos de vida atuais, cada criatura afetada por essa magia cai inconsciente até a magia terminar, o adormecido sofrer dano ou alguém usar uma ação para sacudir ou bater no adormecido para acordá-lo. Subtraia os pontos de vida de cada criatura do total antes de passar para a criatura com o próximo menor número de pontos de vida. Os pontos de vida de uma criatura devem ser iguais ou menores do que o total restante para que essa criatura seja afetada. Mortos-vivos e criaturas imunes a serem enfeitiçadas não são afetadas por essa magia.", ["Bardo", "Feiticeiro", "Mago"], false, false, "Quando você lança essa magia usando um espaço de magia de 2º nível ou superior, role 2d8 adicionais para cada nível de espaço acima do 1º."),
  sp("Vida Falsa", 1, "Necromancia", "1 ação", "Pessoal", "1 hora", true, true, true, "Uma pequena quantidade de álcool ou destilado", "Reforçando-se com um facsímile necromântico de vida, você ganha 1d4 + 4 pontos de vida temporários pela duração.", ["Feiticeiro", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 2º nível ou superior, você ganha 5 pontos de vida temporários adicionais para cada nível de espaço acima do 1º."),
  sp("Acalmar Emoções", 2, "Encantamento", "1 ação", "18 metros", "Até 1 minuto", true, true, false, "", "Você tenta suprimir emoções fortes em um grupo de pessoas. Cada humanóide em uma esfera de 6 metros de raio centrada em um ponto à sua escolha dentro do alcance deve fazer um teste de salvação de Carisma; uma criatura pode escolher falhar neste teste de salvação se desejar. Se uma criatura falhar no teste de salvação, escolha um dos dois efeitos a seguir. Você pode suprimir qualquer efeito que cause encantamento ou medo em um alvo. Quando este feitiço termina, qualquer efeito suprimido retoma, desde que sua duração não tenha expirado enquanto isso. Alternativamente, você pode fazer um alvo se tornar indiferente a criaturas à sua escolha contra as quais estava hostil. Esta indiferença termina se o alvo for atacado ou ferido por um feitiço ou se testemunhar qualquer um de seus aliados sendo ferido. Quando o feitiço termina, a criatura fica hostil novamente, a menos que o Mestre determine o contrário.", ["Bardo", "Clérico"], false, true, ""),
  sp("Alterar a Si Mesmo", 2, "Transmutação", "1 ação", "Pessoal", "Até 1 hora", true, true, false, "", "Você assume uma forma diferente. Quando você lança a magia, escolha uma das seguintes opções, cujos efeitos perduram pela duração da magia. Enquanto a magia vigorar, você pode terminar uma opção como uma ação para ganhar os benefícios de outra. Adaptação Aquática. Você adapta seu corpo a um ambiente aquático, brotando brânquias e desenvolvendo membrana entre seus dedos. Você pode respirar debaixo d\\'água e ganha uma velocidade de nado igual à sua velocidade de caminhada. Alterar Aparência. Você transforma sua aparência. Você decide como se parece, incluindo sua altura, peso, feições faciais, som de sua voz, comprimento do cabelo, coloração e características distintivas, se houver. Você pode se fazer parecer um membro de outra raça, embora nenhuma de suas estatísticas mude. Você também não pode se parecer com uma criatura de tamanho diferente do seu, e sua forma básica permanece a mesma; se você é bípede, você não pode usar esta magia para se tornar quadrúpede, por exemplo. A qualquer momento pela duração da magia, você pode usar sua ação para alterar sua aparência desta forma novamente. Armas Naturais. Você desenvolve garras, presas, espinhos, chifres ou uma arma natural diferente de sua escolha. Seus ataques desarmados causam 1d6 de dano de esmagamento, perfuração ou corte, conforme apropriado para a arma natural que você escolheu, e você é proficiente com seus ataques desarmados. Finalmente, a arma natural é mágica e você tem um bônus de +1 nos testes de ataque e dano que faz com ela.", ["Feiticeiro", "Mago"], false, true, ""),
  sp("Ampliar/Reduzir", 2, "Transmutação", "1 ação", "30 pés", "Até 1 minuto", true, true, true, "Um polegar de pó de ferro.", "Ampliar ou reduzir o tamanho de uma criatura ou objeto que você possa ver e que esteja ao alcance pela duração da magia. Escolha uma criatura ou objeto que não esteja vestido ou carregado. Se o alvo não consentir, poderá fazer um teste de resistência de Constituição. Se bem-sucedido, a magia não tem efeito. Se o alvo for uma criatura, tudo que ela veste e carrega muda de tamanho. Qualquer item deixado pela criatura afetada retorna ao seu tamanho normal. Ampliação. O alvo dobra em todas as dimensões e seu peso é multiplicado por oito. Isso aumenta o tamanho de uma categoria de M para G, por exemplo. Se não houver espaço suficiente na sala para o tamanho do alvo dobrado, a criatura ou objeto atinge o tamanho máximo possível no espaço disponível. Até o final da magia, o alvo também tem vantagem em seus testes de Força e testes de resistência de Força. As armas do alvo também crescem. Enquanto essas armas estiverem ampliadas, os ataques do alvo causam 1d4 de dano adicional. Redução. O tamanho do alvo é reduzido pela metade em todas as dimensões e seu peso é dividido por oito. Essa redução diminui o tamanho de uma categoria de M para P, por exemplo. Até o final da magia, o alvo tem desvantagem em seus testes de Força e testes de resistência de Força. As armas do alvo também encolhem. Enquanto essas armas estiverem reduzidas, os ataques do alvo causam 1d4 de dano a menos (mínimo 1 ponto de dano).", ["Feiticeiro", "Mago"], false, true, ""),
  sp("Arma Espiritual", 2, "Evocação", "1 ação bônus", "60 pés", "1 minuto", true, true, false, "", "Você cria uma arma espectral flutuante dentro do alcance que dura pela duração ou até você lançar este feitiço novamente. Quando você lança o feitiço, você pode fazer um ataque de feitiço corpo a corpo contra uma criatura dentro de 5 pés da arma. Em um acerto, o alvo sofre dano de força igual a 1d8 + seu modificador de habilidade de lançamento de feitiços. Como uma ação bônus em seu turno, você pode mover a arma até 20 pés e repetir o ataque contra uma criatura dentro de 5 pés dela. A arma pode ter qualquer forma que você escolha. Clérigos de divindades associadas a uma arma particular (como Santo Cuthbert é conhecido por seu tacape e Thor por seu martelo) fazem o efeito deste feitiço se assemelhar àquela arma.", ["Clérico"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 3º nível ou superior, o dano aumenta em 1d8 para cada dois níveis de espaço acima do 2º."),
  sp("Arma Mágica", 2, "Transmutação", "1 ação bônus", "Toque", "Até 1 hora", true, true, false, "", "Você toca uma arma não mágica. Até o feitiço terminar, essa arma se torna uma arma mágica com um bônus de +1 em testes de ataque e testes de dano.", ["Paladino", "Mago"], false, true, "Quando você lança este feitiço usando um espaço de feitiço de 4º nível ou superior, o bônus aumenta para +2. Quando você usa um espaço de feitiço de 6º nível ou superior, o bônus aumenta para +3."),
  sp("Augúrio", 2, "Adivinhação", "1 minuto", "Pessoal", "Instantâneo", true, true, true, "Varetas, ossos ou tokens semelhantes especialmente marcados no valor de pelo menos 25 po.", "Lançando varetas incrustadas de gemas, rolando ossos de dragão, espalhando cartas ornadas ou empregando alguma outra ferramenta de adivinhação, você recebe um presságio de uma entidade de outro mundo sobre os resultados de um curso de ação específico que você planeja tomar nos próximos 30 minutos. O mestre escolhe entre os seguintes presságios possíveis: - Bem, para bons resultados - Mal, para maus resultados - Bem e Mal, para resultados bons e ruins - Nada, para resultados que não são especialmente bons ou ruins A magia não leva em conta nenhuma circunstância possível que possa mudar o resultado, como o lançamento de magias adicionais ou a perda ou ganho de um companheiro. Se você lançar a magia duas ou mais vezes antes de completar seu próximo repouso longo, há uma chance cumulativa de 25% para cada lançamento após o primeiro de que você obtenha uma leitura aleatória. O mestre faz este teste em segredo.", ["Clérico"], true, false, ""),
  sp("Aura Mágica do Arcanista", 2, "Ilusão", "1 ação", "Toque", "24 horas", true, true, true, "Um pequeno quadrado de seda.", "Você coloca uma ilusão em uma criatura ou objeto que você toca para que magias de adivinhação revelem informações falsas sobre ele. O alvo pode ser uma criatura voluntária ou um objeto que não está sendo carregado ou usado por outra criatura. Quando você lança a magia, escolha um ou ambos os efeitos a seguir. O efeito dura pela duração. Se você lançar esta magia na mesma criatura ou objeto todos os dias por 30 dias, colocando o mesmo efeito nele cada vez, a ilusão dura até ser dissipada. Aura Falsa. Você altera a forma como o alvo aparece para magias e efeitos mágicos, como detectar magia, que detectam auras mágicas. Você pode fazer um objeto não mágico parecer mágico, um objeto mágico parecer não mágico, ou alterar a aura mágica do objeto para que pareça pertencer a uma escola de magia específica à sua escolha. Quando você usa este efeito em um objeto, você pode tornar a magia falsa aparente para qualquer criatura que manusear o item. Máscara. Você altera a forma como o alvo aparece para magias e efeitos mágicos que detectam tipos de criatura, como Sentido Divino de um paladino ou o gatilho de uma magia símbolo. Você escolhe um tipo de criatura e outras magias e efeitos mágicos tratam o alvo como se fosse uma criatura daquele tipo ou daquele alinhamento.", ["Mago"], false, false, ""),
  sp("Auxílio", 2, "Abjuração", "1 ação", "30 pés", "8 horas", true, true, true, "Uma tira minúscula de pano branco.", "Sua magia fortalece seus aliados com resistência e determinação. Escolha até três criaturas dentro do alcance. O máximo de pontos de vida e os pontos de vida atuais de cada alvo aumentam em 5 pela duração.", ["Clérico", "Paladino"], false, false, "Quando você lança esta magia usando um espaço de magia de 3º nível ou superior, os pontos de vida de um alvo aumentam em 5 adicionais para cada nível de espaço acima do 2º."),
  sp("Batida", 2, "Transmutação", "1 ação", "60 pés", "Instantâneo", true, false, false, "", "Escolha um objeto que você possa ver dentro do alcance. O objeto pode ser uma porta, uma caixa, um baú, um par de algemas, um cadeado ou outro objeto que contenha um meio mundano ou mágico que impeça o acesso. Um alvo mantido fechado por um cadeado mundano ou que está preso ou bloqueado fica destrancado, solto ou desobstruído. Se o objeto tiver múltiplos cadeados, apenas um deles é destrancado. Se você escolher um alvo mantido fechado com fechadura arcana, esse feitiço é suprimido por 10 minutos, durante o qual o alvo pode ser aberto e fechado normalmente. Quando você lança o feitiço, uma batida alta, audível de tão longe quanto 300 pés, emana do objeto alvo.", ["Bardo", "Feiticeiro", "Mago"], false, false, ""),
  sp("Boca Mágica", 2, "Ilusão", "1 minuto", "30 pés", "Até ser dissipado", true, true, true, "Um favo de mel e pó de jade de pelo menos 10 polegadas, que o feitiço consome.", "Você planta uma mensagem em um objeto dentro do alcance do feitiço. A mensagem é verbalizada quando as condições de disparo são atendidas. Escolha um objeto que você veja e que não seja usado ou carregado por outra criatura. Então diga a mensagem, que não deve exceder 25 palavras, mas a escuta pode levar até 10 minutos. Finalmente, estabeleça as circunstâncias que disparam o feitiço para entregar sua mensagem. Quando essas condições são satisfeitas, uma boca mágica aparece no objeto e articula a mensagem imitando sua voz, o mesmo tom usado durante a implantação da mensagem. Se o objeto selecionado tem uma boca ou algo que se aproxime, como a boca de uma estátua, a boca mágica ganha vida neste ponto, dando a ilusão de que as palavras vêm da boca do objeto. Quando você lança este feitiço, você pode decidir que o feitiço termina quando a mensagem é entregue ou pode persistir e repetir a mensagem sempre que as circunstâncias ocorrem. A circunstância de disparo pode ser tão geral ou detalhada quanto você quiser, embora deva ser baseada em condições visuais ou audíveis que ocorram dentro de 30 pés do objeto. Por exemplo, você pode instruir a boca para falar quando qualquer criatura se move dentro de 30 pés do objeto ou quando um sino de prata toca dentro de 30 pés dele.", ["Bardo", "Mago"], true, false, ""),
  sp("Cegueira/Surdez", 2, "Necromancia", "1 ação", "30 pés", "1 minuto", true, false, false, "", "Você pode cegar ou ensurdecer um inimigo. Escolha uma criatura que você possa ver dentro do alcance para fazer um teste de resistência de Constituição. Se falhar, o alvo fica cego ou surdo (sua escolha) pela duração. No final de cada um de seus turnos, o alvo pode fazer um teste de resistência de Constituição. Se tiver sucesso, o feitiço termina.", ["Bardo", "Clérico", "Feiticeiro", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 3º nível ou superior, você pode atingir uma criatura adicional para cada nível de espaço acima do 2º."),
  sp("Chama Contínua", 2, "Evocação", "1 ação", "Toque", "Até ser dissipada", true, true, true, "Pó de rubi no valor de 50 po, que a magia consome", "Uma chama, equivalente em brilho a uma tocha, brota de um objeto que você toca. O efeito parece uma chama comum, mas não produz calor e não consome oxigênio. Uma chama contínua pode ser coberta ou escondida, mas não pode ser sufocada ou extinguida.", ["Clérico", "Mago"], false, false, ""),
  sp("Crescimento de Espinhos", 2, "Transmutação", "1 ação", "45 metros", "Até 10 minutos", true, true, true, "Sete espinhos afiados ou sete galhos cortados no topo", "O solo em um raio de 6 metros centrado em um ponto dentro do alcance se contorce e brota espinhos duros e espinhos. A área se torna terreno difícil pela duração. Quando uma criatura se move para dentro ou dentro da área, ela sofre 2d4 de dano perfurante para cada 1,5 metros que viaja. O desenvolvimento da terra é camuflado para parecer natural. Qualquer criatura que não veja a área quando a magia é lançada deve fazer um teste de Sabedoria (Percepção) contra a CD da magia ou não reconhece a natureza perigosa do solo antes de entrar.", ["Druida", "Patrulheiro"], false, true, ""),
  sp("Desfoque", 2, "Ilusão", "1 ação", "Pessoal", "Até 1 minuto", true, false, false, "", "Seu corpo fica desfocado, se deslocando e ondulando para todos que podem vê-lo. Pela duração, qualquer criatura tem desvantagem em testes de ataque contra você. Um atacante é imune a este efeito se não depender da visão, como com visão cega, ou puder ver através de ilusões, como com visão verdadeira.", ["Feiticeiro", "Mago"], false, true, ""),
  sp("Detectar Pensamentos", 2, "Adivinhação", "1 ação", "Pessoal", "Até 1 minuto", true, true, true, "Uma moeda de cobre.", "Pela duração da magia, você pode ler os pensamentos de algumas criaturas. Enquanto lança a magia e em sua ação em cada rodada até o fim da magia, você pode focar sua mente em uma criatura que você possa ver a 30 pés de você. Se a criatura escolhida tiver Inteligência 3 ou menos, ou se não falar nenhuma língua, a criatura não é afetada. Você primeiro lê os pensamentos superficiais da criatura, que ocupam sua mente no momento. Em uma ação, você pode direcionar sua atenção para os pensamentos de outra criatura ou tentar aprofundar sua leitura dos pensamentos da mesma criatura. Se aprofundar sua leitura, o alvo deve fazer um teste de Sabedoria, caso contrário você obtém acesso aos seus argumentos (se houver), seu estado emocional e pensamento que preocupam sua mente em um espectro mais amplo, como uma preocupação, amor ou ódio. Se bem-sucedido, a magia termina. Em todos os casos, o alvo está ciente de que sua mente está sob seus olhos. A menos que você esteja direcionando sua atenção para os pensamentos de outra criatura, o alvo pode usar sua ação no turno para fazer um teste de Inteligência contra seu teste de Inteligência. Se tiver vantagem, a magia termina. As perguntas verbalmente dirigidas ao alvo guiam o curso do pensamento. Esta magia é especialmente eficaz durante um interrogatório. Você também pode usar esta magia para detectar a presença de criaturas pensantes que são invisíveis para você. Quando lança esta magia, ou em uma ação pela duração da magia, você pode encontrar pensamentos a 30 pés de você. A magia pode ultrapassar a maioria dos obstáculos, mas é bloqueada por 2 pés de pedra, 2 polegadas de metal precioso, ou uma folha fina de chumbo. Você não pode detectar uma criatura com Inteligência 3 ou menos ou que não fale nenhuma língua. Depois de detectar a presença de uma criatura dessa forma, você pode ler seus pensamentos pelo restante da duração da magia conforme descrito acima, mesmo que não possa vê-la, mas apenas se permanecer no alcance da magia.", ["Bardo", "Feiticeiro", "Mago"], false, true, ""),
  sp("Encontrar Armadilhas", 2, "Adivinhação", "1 ação", "36 metros", "Instantâneo", true, true, false, "", "Você sente a presença de qualquer armadilha dentro do alcance que está em sua linha de visão. Uma armadilha, para o propósito dessa magia, inclui qualquer coisa que infligisse um efeito súbito ou inesperado que você considera prejudicial ou indesejável, que foi especificamente intencionado como tal por seu criador. Assim, a magia sentiria uma área afetada pela magia alarme, um glifo de ruína ou uma armadilha de poço mecânico, mas não revelaria uma fraqueza natural no chão, um teto instável ou um sumidouro oculto. Esta magia apenas revela que uma armadilha está presente. Você não descobre a localização de cada armadilha, mas aprende a natureza geral do perigo apresentado por uma armadilha que você sente.", ["Clérico", "Druida", "Patrulheiro"], false, false, ""),
  sp("Encontrar Montaria", 2, "Conjuração", "10 minutos", "9 metros", "Instantâneo", true, true, false, "", "Você convoca um espírito que assume a forma de uma montaria incomumente inteligente, forte e leal, criando um vínculo duradouro com ela. Aparecendo em um espaço desocupado dentro do alcance, a montaria assume uma forma que você escolhe, como um cavalo de guerra, um pônei, um camelo, um alce ou um mastim. (Seu DM pode permitir outros animais serem convocados como montarias.) A montaria tem as estatísticas da forma escolhida, mas é uma criatura celestial, feérica ou fiend (sua escolha) em vez de seu tipo normal. Além disso, se sua montaria tiver uma Inteligência de 5 ou menos, sua Inteligência se torna 6 e ela ganha a capacidade de entender um idioma de sua escolha que você fala. Sua montaria o serve como montaria, tanto em combate quanto fora dele, e você tem um vínculo instintivo com ela que permite lutar como uma unidade integrada. Enquanto montado em sua montaria, você pode fazer qualquer magia que você lance que o alvo apenas também alvejar sua montaria. Quando a montaria chega a 0 pontos de vida, ela desaparece, sem deixar forma física. Você também pode dispensar sua montaria a qualquer momento como uma ação, fazendo-a desaparecer. Em ambos os casos, lançar essa magia novamente convoca a mesma montaria, restaurada ao máximo de pontos de vida. Enquanto sua montaria está a até 1,5 quilômetro de você, você pode se comunicar com ela telepaticamente. Você não pode ter mais de uma montaria vinculada por essa magia por vez. Como uma ação, você pode liberar a montaria de seu vínculo a qualquer momento, fazendo-a desaparecer.", ["Paladino"], false, false, ""),
  sp("Escalada de Aranha", 2, "Transmutação", "1 ação", "Toque", "Até 1 hora", true, true, true, "Uma gota de betume e uma aranha", "Até que a magia termine, uma criatura disposta que você toca ganha a capacidade de se mover para cima, para baixo e através de superfícies verticais e de cabeça para baixo ao longo de tetos, deixando suas mãos livres. O alvo também ganha uma velocidade de escalada igual à sua velocidade de caminhada.", ["Feiticeiro", "Bruxo", "Mago"], false, true, ""),
  sp("Escuridão", 2, "Evocação", "1 ação", "60 pés", "Até 10 minutos", true, false, true, "Pelo de morcego e uma gota de piche ou pedaço de carvão.", "A escuridão mágica se espalha a partir de um ponto que você escolhe ao alcance para preencher uma esfera de raio de 15 pés pela duração. A escuridão se espalha ao redor de cantos. Uma criatura com visão no escuro não consegue ver através desta escuridão, e luz não-mágica não consegue iluminá-la. Se o ponto que você escolhe está em um objeto que você está segurando ou que não está sendo vestido ou carregado, a escuridão emana do objeto e se move com ele. Cobrir completamente a fonte da escuridão com um objeto opaco, como uma tigela ou um elmo, bloqueia a escuridão. Se alguma área deste feitiço se sobrepor com uma área de luz criada por um feitiço de 2º nível ou inferior, o feitiço que criou a luz é dissipado.", ["Feiticeiro", "Bruxo", "Mago"], false, true, ""),
  sp("Esfera Flamejante", 2, "Conjuração", "1 ação", "60 pés", "Até 1 minuto", true, true, true, "Um pouco de sebo, uma pitada de enxofre e um polvilho de pó de ferro.", "Uma esfera de fogo com 5 pés de diâmetro aparece em um espaço desocupado de sua escolha dentro do alcance e dura pela duração. Qualquer criatura que termine seu turno dentro de 5 pés da esfera deve fazer um teste de resistência de Destreza. A criatura recebe 2d6 de dano de fogo em um teste falhado, ou metade do dano em um teste bem-sucedido. Como uma ação bônus, você pode mover a esfera até 30 pés. Se você arremessar a esfera contra uma criatura, essa criatura deve fazer o teste de resistência contra o dano da esfera, e a esfera para de se mover neste turno. Quando você move a esfera, pode dirigi-la sobre barreiras de até 5 pés de altura e pular sobre fossas de até 10 pés de largura. A esfera incendeia objetos inflamáveis que não estão sendo usados ou carregados, e projeta luz brilhante em um raio de 20 pés e luz fraca por mais 20 pés.", ["Druida", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 3º nível ou superior, o dano aumenta em 1d6 para cada nível de espaço acima do 2º."),
  sp("Estrondo", 2, "Evocação", "1 ação", "60 pés", "Instantâneo", true, true, true, "Uma rajada de mica.", "Um som ressonante forte e dolorosamente intenso emana de um ponto de sua escolha ao alcance da magia. Cada criatura em uma esfera de 10 pés de raio centrada naquele ponto deve fazer um teste de resistência de Constituição ou sofre 3d8 de dano de trovão. Se bem-sucedida, o dano é reduzido à metade. Uma criatura feita de materiais inorgânicos, como pedra, cristal ou metal, faz seu teste de resistência com desvantagem. Um item não mágico que não está sendo usado ou carregado também sofre dano se estiver na área da magia.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 3º nível ou superior, o dano da magia aumenta em 1d8 para cada nível acima do 2º."),
  sp("Fascinar", 2, "Encantamento", "1 ação", "60 pés", "1 minuto", true, true, false, "", "Você tece uma sequência de palavras distrativa, fazendo com que criaturas de sua escolha que você possa ver ao alcance e que possam ouvi-lo façam um teste de resistência de Sabedoria. Qualquer criatura que não possa ser enfeitiçada tem sucesso automaticamente nesse teste de resistência e, se você ou seus companheiros estão lutando contra uma criatura, ela tem vantagem na resistência. Se falhar, o alvo tem desvantagem em testes de Sabedoria (Percepção) feitos para perceber qualquer criatura que não seja você até o final da magia ou até que o alvo não possa mais ouvi-lo. A magia termina se você estiver incapacitado ou não conseguir mais falar.", ["Bardo", "Bruxo"], false, false, ""),
  sp("Fechadura Arcana", 2, "Abjuração", "1 ação", "Toque", "Até ser dissipada", true, true, true, "Pó de ouro valendo pelo menos 250 PO, que a magia consome.", "Você toca uma porta fechada, janela, portão, baú ou outra entrada, e ela fica trancada pela duração. Você e as criaturas que você designar quando lançar esta magia podem abrir o objeto normalmente. Você também pode definir uma senha que, quando falada a 1,5 metros do objeto, suprime esta magia por 1 minuto. Caso contrário, é intransponível até ser quebrada ou a magia ser dissipada ou suprimida. Lançar Pancada no objeto suprime fechadura arcana por 10 minutos. Enquanto afetado por esta magia, o objeto é mais difícil de quebrar ou forçar abrir; a CD para quebrá-lo ou arrombar qualquer fechadura nele aumenta em 10.", ["Mago"], false, false, ""),
  sp("Golpe da Marca", 2, "Evocação", "1 ação bônus", "Pessoal", "Até 1 minuto", true, false, false, "", "A próxima vez que você acertar uma criatura com um ataque com arma antes deste feitiço terminar, a arma brilha com radiosidade astral quando você golpeia. O ataque causa 2d6 de dano radiante adicional ao alvo, que se torna visível se for invisível, e o alvo emite luz fraca em um raio de 5 pés e não pode se tornar invisível até o feitiço terminar.", ["Paladino"], false, true, ""),
  sp("Imagem Espelhada", 2, "Ilusão", "1 ação", "Pessoal", "1 minuto", true, true, false, "", "Três duplicatas ilusórias de você aparecem em seu espaço. Até o final do feitiço, as duplicatas se movem com você e imitam suas ações, trocando de posição de modo que é impossível determinar qual imagem é real. Você pode usar sua ação para dissipar as duplicatas ilusórias. Sempre que uma criatura o visa com um ataque durante a duração do feitiço, role 1d20 para determinar se o ataque não visa uma de suas duplicatas. Se você tiver três duplicatas, você precisa de 6 ou mais no seu lance para levar o alvo do ataque a uma duplicata. Com duas duplicatas, você precisa de 8 ou mais. Com uma duplicata, você precisa de 11 ou mais. A CA de uma duplicata é 10 + seu modificador de Destreza. Se um ataque atingir uma duplicata, ela é destruída. Uma duplicata pode ser destruída não apenas por um ataque. Ela ignora outros danos e efeitos. O feitiço termina se as três duplicatas são destruídas. Uma criatura não é afetada por este destino se não puder ver ou se depender de um significado diferente de visão, como visão cega, ou se puder perceber ilusões como falsas, como com visão verdadeira.", ["Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Invisibilidade", 2, "Ilusão", "1 ação", "Toque", "Até 1 hora", true, true, true, "Um cílio envolvido em goma-arábica.", "Uma criatura que você toca se torna invisível até a magia terminar. Qualquer coisa que o alvo esteja vestindo ou carregando fica invisível enquanto estiver sobre a pessoa do alvo. A magia termina para um alvo que atacar ou lançar uma magia.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 3º nível ou superior, você pode escolher uma criatura adicional para cada nível de espaço acima do 2º."),
  sp("Lâmina Flamejante", 2, "Evocação", "1 ação bônus", "Self", "Até 10 minutos", true, true, true, "Folha de sumagre.", "Você evoca uma lâmina ardente em sua mão livre. A lâmina é similar em tamanho e forma a um cimitarra e dura pela duração. Se você soltar a lâmina, ela desaparece, mas você pode evocar a lâmina novamente como uma ação bônus. Você pode usar sua ação para fazer um ataque de magia corpo a corpo com a lâmina ardente. Em um acerto, o alvo sofre 3d6 de dano de fogo. A lâmina flamejante emite luz brilhante em um raio de 10 pés e luz fraca para 10 pés adicionais.", ["Druida"], false, true, "Quando você conjura esta magia usando um espaço de magia de 4º nível ou superior, o dano aumenta em 1d6 para cada dois níveis de espaço acima do 2º."),
  sp("Levitar", 2, "Transmutação", "1 ação", "60 pés", "Até 10 minutos", true, true, true, "Um pequeno laço de couro ou um fio dourado dobrado em formato de copo com um cabo longo em uma extremidade.", "Uma criatura ou objeto de sua escolha que você possa ver dentro do alcance sobe verticalmente, até 20 pés, e permanece suspenso lá pela duração. O feitiço pode levitar um alvo que pesa até 500 libras. Uma criatura relutante que é bem-sucedida em um teste de salvamento de constituição não é afetada. O alvo pode se mover apenas empurrando ou puxando contra um objeto ou superfície fixa dentro do alcance (como uma parede ou um teto), o que permite que ele se mova como se estivesse escalando. Você pode alterar a altitude do alvo em até 20 pés em qualquer direção em seu turno. Se você é o alvo, você pode se mover para cima ou para baixo como parte de seu movimento. Caso contrário, você pode usar sua ação para mover o alvo, que deve permanecer dentro do alcance do feitiço. Quando o feitiço termina, o alvo flutua suavemente até o chão se ainda estiver no ar.", ["Feiticeiro", "Mago"], false, true, ""),
  sp("Localizar Animais ou Plantas", 2, "Adivinhação", "1 ação", "Pessoal", "Instantâneo", true, true, true, "Um pouco de pelo de um sabujo.", "Descreva ou nomeie um tipo específico de besta ou planta. Concentrando-se na voz da natureza ao seu redor, você aprende a direção e a distância até a criatura ou planta mais próxima daquele tipo em um raio de 8 quilômetros, se houver alguma presente.", ["Bardo", "Druida", "Patrulheiro"], true, false, ""),
  sp("Localizar Objeto", 2, "Adivinhação", "1 ação", "Pessoal", "Até 10 minutos", true, true, true, "Um galho bifurcado.", "Descreva ou nomeie um objeto que lhe é familiar. Você sente a direção da localização do objeto, enquanto esse objeto estiver a até 300 metros de você. Se o objeto estiver em movimento, você saberá a direção de seu movimento. A magia pode localizar um objeto específico conhecido por você, contanto que você o tenha visto de perto (a até 9 metros) pelo menos uma vez. Alternativamente, a magia pode localizar o objeto mais próximo de um tipo particular, como um tipo específico de vestuário, joia, móvel, ferramenta ou arma. Essa magia não pode localizar um objeto se qualquer espessura de chumbo, mesmo uma folha fina, bloqueia um caminho direto entre você e o objeto.", ["Bardo", "Clérico", "Druida", "Paladino", "Patrulheiro", "Mago"], false, true, ""),
  sp("Melhorar Habilidade", 2, "Transmutação", "1 ação", "Toque", "Até 1 hora", true, true, true, "Pele ou uma pena de uma besta.", "Você toca uma criatura e a concede um aprimoramento mágico. Escolha um dos seguintes efeitos; o alvo ganha esse efeito até o final da magia. Resistência do Urso. O alvo tem vantagem em testes de Constituição. Também ganha 2d6 pontos de vida temporários, que são perdidos quando a magia termina. Força do Touro. O alvo tem vantagem em testes de Força e sua capacidade de carga dobra. Graça do Gato. O alvo tem vantagem em testes de Destreza. Também não sofre dano ao cair 20 pés ou menos se não estiver incapacitado. Esplendor da Águia. O alvo tem vantagem em testes de Carisma. Astúcia da Raposa. O alvo tem vantagem em testes de Inteligência. Sabedoria da Coruja. O alvo tem vantagem em testes de Sabedoria.", ["Bardo", "Clérico", "Druida", "Feiticeiro"], false, true, "Quando você lança essa magia usando um espaço de magia de 3º nível ou superior, você pode atingir uma criatura adicional para cada nível de espaço acima do 2º."),
  sp("Mensageiro Animal", 2, "Encantamento", "1 ação", "9 metros", "24 horas", true, true, true, "Um bocado de comida", "Por meio desta magia, você usa um animal para entregar uma mensagem. Escolha uma besta Minúscula que você possa ver dentro do alcance, como um esquilo, um gaio-azul ou um morcego. Você especifica um local, que você deve ter visitado, e um destinatário que corresponda a uma descrição geral, como \"um homem ou mulher vestido com o uniforme da guarda da cidade\" ou \"um anão ruivo usando um chapéu pontiagudo\". Você também fala uma mensagem de até vinte e cinco palavras. A besta alvo viaja pela duração da magia em direção ao local especificado, cobrindo cerca de 50 milhas a cada 24 horas para um mensageiro voador, ou 25 milhas para outros animais. Quando o mensageiro chega, entrega sua mensagem à criatura que você descreveu, replicando o som de sua voz. O mensageiro fala apenas para uma criatura que corresponda à descrição que você deu. Se o mensageiro não chegar ao seu destino antes da magia terminar, a mensagem é perdida, e a besta volta para o local onde você lançou esta magia.", ["Bardo", "Druida", "Patrulheiro"], true, false, "Se você lançar esta magia usando um espaço de magia de 3º nível ou superior, a duração da magia aumenta em 48 horas para cada nível de espaço acima do 2º."),
  sp("Metal Incandescente", 2, "Transmutação", "1 ação", "60 pés", "Até 1 minuto", true, true, true, "Um pedaço de ferro e uma chama.", "Escolha um objeto de metal fabricado, como uma arma de metal ou uma armadura de metal pesada ou média, que você possa ver dentro do alcance. Você faz o objeto brilhar em vermelho incandescente. Qualquer criatura em contato físico com o objeto sofre 2d8 de dano de fogo quando você lança a magia. Até a magia terminar, você pode usar uma ação bônus em cada um de seus turnos subsequentes para causar esse dano novamente. Se uma criatura está segurando ou vestindo o objeto e sofre o dano dele, a criatura deve ter sucesso em um teste de resistência de Constituição ou soltar o objeto se conseguir. Se não soltá-lo, tem desvantagem em testes de ataque e testes de habilidade até o início de seu próximo turno.", ["Bardo", "Druida"], false, true, "Quando você lança essa magia usando um espaço de magia de 3º nível ou superior, o dano aumenta em 1d8 para cada nível de espaço acima do 2º."),
  sp("Oração de Cura", 2, "Evocação", "10 minutos", "30 pés", "Instantâneo", true, false, false, "", "Até seis criaturas à sua escolha que você pode ver dentro do alcance recuperam cada uma pontos de vida iguais a 2d8 + seu modificador de habilidade de lançamento de magia. Esta magia não tem efeito em mortos-vivos ou constructos.", ["Clérico"], false, false, "Quando você lança esta magia usando um espaço de magia de 3º nível ou superior, a cura aumenta em 1d8 para cada nível de espaço acima do 2º."),
  sp("Passar sem Deixar Rastros", 2, "Abjuração", "1 ação", "Self", "Até 1 hora", true, true, true, "Cinzas de uma folha de visco queimada e um broto de abeto.", "Um véu de sombras e silêncio irradia de você, encobrindo você e seus companheiros da detecção. Durante a duração, cada criatura que você escolher a 30 pés de você (incluindo você) recebe um bônus +10 em testes de Destreza (Furtividade) e não pode ser rastreada exceto por meios mágicos. Uma criatura que recebe este bônus não deixa rastros ou outros sinais de sua passagem.", ["Druida", "Patrulheiro"], false, true, ""),
  sp("Passo Fantasmagórico", 2, "Conjuração", "1 ação bônus", "Pessoal", "Instantâneo", true, false, false, "", "Brevemente cercado por neblina prateada, você se teleporta até 30 pés para um espaço desocupado que você possa ver.", ["Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Pele de Árvore", 2, "Transmutação", "1 ação", "Toque", "Até 1 hora", true, true, true, "Um punhado de casca de carvalho.", "Você toca uma criatura disposta. Até a magia terminar, a pele do alvo tem uma aparência áspera e semelhante à casca, e a CA do alvo não pode ser menor que 16, independentemente de que tipo de armadura ele esteja vestindo.", ["Druida", "Patrulheiro"], false, true, ""),
  sp("Prender Pessoa", 2, "Encantamento", "1 ação", "60 pés", "Até 1 minuto", true, true, true, "Um pequeno e reto pedaço de ferro.", "Escolha um humanoide que você possa ver no alcance. O alvo deve ter sucesso em um teste de resistência de Sabedoria ou ser paralisado pela duração. Ao final de cada um de seus turnos, o alvo pode fazer outro teste de resistência de Sabedoria. Com sucesso, a magia termina no alvo.", ["Bardo", "Clérico", "Druida", "Feiticeiro", "Bruxo", "Mago"], false, true, "Quando você conjura essa magia usando um espaço de magia de 3º nível ou superior, você pode atingir um humanoide adicional para cada nível de espaço acima do 2º. Os humanoides devem estar a 30 pés um do outro quando você os atinge."),
  sp("Proteção contra Veneno", 2, "Abjuração", "1 ação", "Toque", "1 hora", true, true, false, "", "Você toca uma criatura. Se ela está envenenada, você neutraliza o veneno. Se mais de um veneno afeta o alvo, você neutraliza um veneno que você sabe estar presente, ou neutraliza um aleatoriamente. Durante o tempo de duração, o alvo tem vantagem em testes de resistência contra ficar envenenado e tem resistência a dano de veneno.", ["Clérico", "Druida", "Paladino", "Patrulheiro"], false, false, ""),
  sp("Raio Abrasador", 2, "Evocação", "1 ação", "120 pés", "Instantâneo", true, true, false, "", "Você gera três raios de fogo e os arremessa contra alvos dentro do alcance do feitiço. Você pode dirigi-los contra um ou mais alvos. Faça um teste de ataque de feitiço à distância para cada raio. Se acertar, o alvo sofre 2d6 de dano de fogo.", ["Feiticeiro", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 3º nível ou superior, você gera um raio adicional para cada nível acima do 2º."),
  sp("Raio de Fraqueza", 2, "Necromancia", "1 ação", "60 pés", "Até 1 minuto", true, true, false, "", "Um raio negro de energia enervante parte de seu dedo em direção a uma criatura dentro do alcance. Faça um teste de ataque de magia à distância contra o alvo. Em um acerto, o alvo causa apenas metade do dano com ataques com armas que usam Força até o término da magia. No final de cada turno do alvo, ele pode fazer um teste de resistência de Constituição contra a magia. Em um sucesso, a magia termina.", ["Bruxo", "Mago"], false, true, ""),
  sp("Raio de Lua", 2, "Evocação", "1 ação", "120 pés", "Até 1 minuto", true, true, true, "Várias sementes de qualquer planta lunária e um pedaço de feldspato opalescente.", "Um raio prateado de luz pálida brilha para baixo em um cilindro de 5 pés de raio e 40 pés de altura, centrado em um ponto dentro do alcance. Até o final do feitiço, luz fraca preence o cilindro. Quando uma criatura entra na área do feitiço pela primeira vez em um turno ou começa seu turno lá, ela é envolvida em chamas fantasmagóricas que causam dor ardente, e ela deve fazer um teste de resistência de Constituição. Ela sofre 2d10 de dano radiante em uma falha, ou metade em um sucesso. Um metamorfo faz seu teste de resistência com desvantagem. Se falhar, ele também reverte instantaneamente para sua forma original e não pode assumir uma forma diferente até sair da luz do feitiço. Em cada um de seus turnos depois de lançar este feitiço, você pode usar uma ação para mover o raio até 60 pés em qualquer direção.", ["Druida"], false, true, "Quando você lança este feitiço usando um espaço de feitiço de 3º nível ou superior, o dano aumenta em 1d10 para cada nível de espaço acima do 2º."),
  sp("Rajada de Vento", 2, "Evocação", "1 ação", "Pessoal", "Até 1 minuto", true, true, true, "Uma semente de legume.", "Uma linha de vento forte com 60 pés de comprimento e 10 pés de largura sopra de você em uma direção à sua escolha pela duração da magia. Cada criatura que começar seu turno na linha deve ter sucesso em um teste de resistência de Força ou ser empurrada 15 pés para longe de você na direção seguindo a linha. Qualquer criatura na linha deve gastar 2 pés de movimento para cada 1 pé que se move quando se aproxima de você. A rajada dispersa gás ou vapor, e extingue velas, tochas e chamas desprotegidas similares na área. Faz com que chamas protegidas, como as de lanternas, dancem selvagemente e tem 50% de chance de apagá-las. Como uma ação de bônus em cada um de seus turnos antes da magia terminar, você pode mudar a direção em que a linha sopra de você.", ["Druida", "Feiticeiro", "Mago"], false, true, ""),
  sp("Repouso Tranquilo", 2, "Necromancia", "1 ação", "Toque", "10 dias", true, true, true, "Um pitada de sal e uma moeda de cobre colocada em cada um dos olhos do cadáver, que devem permanecer lá pela duração.", "Você toca um cadáver ou outros restos. Pela duração, o alvo é protegido do apodrecimento e não pode se tornar um morto-vivo. A magia também estende efetivamente o limite de tempo para ressuscitar o alvo dos mortos, já que dias gastos sob a influência desta magia não contam contra o limite de tempo de magias como ressurreição.", ["Clérico", "Mago"], true, false, ""),
  sp("Restauração Menor", 2, "Abjuração", "1 ação", "Toque", "Instantâneo", true, true, false, "", "Você toca uma criatura e pode terminar uma doença ou uma condição afligindo-a. A condição pode ser cegueira, surdez, paralisia ou envenenamento.", ["Bardo", "Clérico", "Druida", "Paladino", "Patrulheiro"], false, false, ""),
  sp("Seta Ácida", 2, "Evocação", "1 ação", "90 pés", "Instantâneo", true, true, true, "Pó de folha de ruibarbo e um estômago de víbora.", "Uma seta verde cintilante avança rapidamente em direção a um alvo dentro do alcance e explode em um jato de ácido. Faça um ataque de magia à distância contra o alvo. Se acertar, o alvo sofre 4d4 de dano de ácido imediatamente e 2d4 de dano de ácido no final do próximo turno. Se errar, a seta espirra o alvo com ácido, causando metade do dano inicial e nenhum dano no final do próximo turno.", ["Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 3º nível ou superior, o dano (inicial e posterior) aumenta em 1d4 para cada nível de espaço acima do 2º."),
  sp("Silêncio", 2, "Ilusão", "1 ação", "120 pés", "Até 10 minutos", true, true, false, "", "Pela duração, nenhum som pode ser criado dentro ou passar através de uma esfera com raio de 20 pés centrada em um ponto de sua escolha dentro do alcance. Qualquer criatura ou objeto inteiramente dentro da esfera é imune a dano de trovão, e criaturas ficam ensurdecidas enquanto inteiramente dentro dela. Lançar uma magia que inclui um componente verbal é impossível lá.", ["Bardo", "Clérico", "Patrulheiro"], true, true, ""),
  sp("Sugestão", 2, "Encantamento", "1 ação", "30 pés", "Até 8 horas", true, false, true, "A língua de uma cobra e um pouco de favo de mel ou uma gota de óleo doce.", "Você sugere um curso de ação (limitado a uma ou duas frases) e influencia magicamente uma criatura que você pode ver dentro do alcance que pode ouvir e entender você. Criaturas que não podem ser enfeitiçadas são imunes a esse efeito. A sugestão deve ser formulada de forma que o curso de ação pareça razoável. Pedir à criatura que se esfaqueie, se lance sobre uma lança, se incendeie ou faça algum outro ato obviamente prejudicial encerra o feitiço. O alvo deve fazer um teste de resistência de Sabedoria. Se falhar na resistência, persegue o curso de ação descrito o melhor que pode. O curso de ação sugerido pode continuar durante toda a duração. Se a atividade sugerida puder ser concluída em menos tempo, o feitiço termina quando o assunto termina o que lhe foi pedido. Você também pode especificar condições que acionarão uma atividade especial durante a duração. Por exemplo, você pode sugerir que um cavaleiro dê seu cavalo de guerra ao primeiro mendigo que encontrar. Se a condição não for atendida antes do feitiço expirar, a atividade não é realizada. Se você ou qualquer um de seus companheiros danificar o alvo, o feitiço termina.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, true, ""),
  sp("Teia", 2, "Conjuração", "1 ação", "60 pés", "Até 1 hora", true, true, true, "Um pedaço de teia de aranha.", "Você conjura uma massa de teia espessa e pegajosa em um ponto à sua escolha dentro do alcance. As teias preenchem um cubo de 20 pés a partir daquele ponto pela duração. As teias são terreno difícil e obscurecem levemente sua área. Se as teias não estiverem ancoradas entre duas massas sólidas (como paredes ou árvores) ou dispostas em camadas sobre um piso, parede ou teto, a teia conjurada desaba sobre si mesma e a magia termina no início do seu próximo turno. Teias dispostas em camadas sobre uma superfície plana têm uma profundidade de 5 pés. Cada criatura que inicia seu turno nas teias ou que entra nelas durante seu turno deve fazer um teste de salvação de Destreza. Em uma falha, a criatura fica contida enquanto permanecer nas teias ou até que se liberte. Uma criatura contida pelas teias pode usar sua ação para fazer um teste de Força contra sua CD de salvação de magia. Se tiver sucesso, deixa de estar contida. As teias são inflamáveis. Qualquer cubo de 5 pés de teias exposto ao fogo queima em 1 rodada, causando 2d4 de dano de fogo para qualquer criatura que inicia seu turno no fogo.", ["Feiticeiro", "Mago"], false, true, ""),
  sp("Truque da Corda", 2, "Transmutação", "1 ação", "Toque", "1 hora", true, true, true, "Pó de extrato de milho e um laço torcido de pergaminho.", "Você toca um comprimento de corda de até 60 pés. Uma extremidade da corda então sobe no ar até que a corda toda fique pendurada perpendicular ao solo. Na extremidade superior da corda, uma entrada invisível se abre para um espaço extradimensional que dura até o feitiço acabar. O espaço extradimensional pode ser alcançado subindo até o topo da corda. O espaço pode conter até oito criaturas de tamanho Médio ou menor. A corda pode ser puxada para dentro do espaço, fazendo a corda desaparecer da vista do lado de fora do espaço. Ataques e feitiços não podem atravessar a entrada para dentro ou para fora do espaço extradimensional, mas aqueles dentro podem ver para fora como através de uma janela de 3 pés por 5 pés centrada na corda. Qualquer coisa dentro do espaço extradimensional cai para fora quando o feitiço acaba.", ["Mago"], false, false, ""),
  sp("Ver a Invisibilidade", 2, "Adivinhação", "1 ação", "Pessoal", "1 hora", true, true, true, "Um toque de talco e uma pequena quantidade de pó de prata.", "Pela duração do feitiço, você vê criaturas e objetos invisíveis como se fossem visíveis e pode ver através do Etéreo. Os objetos e criaturas etéreos aparecem espectrais e translúcidos.", ["Bardo", "Feiticeiro", "Mago"], false, false, ""),
  sp("Vínculo de Proteção", 2, "Abjuração", "1 ação", "Toque", "1 hora", true, true, true, "Um par de anéis de platina no valor de pelo menos 50 po cada, que você e o alvo devem usar pela duração.", "Essa magia protege uma criatura disposta que você toca e cria uma conexão mística entre você e o alvo até a magia terminar. Enquanto o alvo estiver a 18 metros de você, ele ganha um bônus de +1 em CA e testes de salvamento, e tem resistência a todos os danos. Além disso, cada vez que sofre dano, você sofre a mesma quantidade de dano. A magia termina se você cair a 0 pontos de vida ou se você e o alvo se separarem por mais de 18 metros. Também termina se a magia for lançada novamente em uma das criaturas conectadas. Você também pode descartar a magia como uma ação.", ["Clérico"], false, false, ""),
  sp("Visão no Escuro", 2, "Transmutação", "1 ação", "Toque", "8 horas", true, true, true, "Um punhado de cenoura seca ou uma ágata.", "Você toca uma criatura disposta para conceder a ela a habilidade de ver no escuro. Pela duração, essa criatura tem visão no escuro até um alcance de 18 metros.", ["Druida", "Patrulheiro", "Feiticeiro", "Mago"], false, false, ""),
  sp("Zona da Verdade", 2, "Encantamento", "1 ação", "18 metros", "10 minutos", true, true, false, "", "Você cria uma zona mágica que protege contra enganos em uma esfera com raio de 4,5 metros centrada em um ponto à sua escolha dentro do alcance. Até o término da magia, uma criatura que entra pela primeira vez na área da magia em um turno ou inicia o seu turno ali deve fazer um teste de resistência de Carisma. Se falhar na resistência, uma criatura não consegue falar uma mentira deliberada enquanto estiver no raio. Você sabe se cada criatura conseguiu ou falhou no teste de resistência. Uma criatura afetada está ciente dessa limitação e pode evitar responder perguntas que ela normalmente teria respondido com uma mentira. Essa criatura pode permanecer evasiva em suas respostas, contanto que permaneça dentro dos limites da verdade.", ["Bardo", "Clérico", "Paladino"], false, false, ""),
  sp("Aceleração", 3, "Transmutação", "1 ação", "30 pés", "Até 1 minuto", true, true, true, "Um pedaço de raiz de alcaçuz.", "Escolha uma criatura disposta que você possa ver dentro do alcance. Até o fim da magia, a velocidade do alvo é dobrada, ele ganha um bônus de +2 na CA, tem vantagem em testes de resistência de Destreza e ganha uma ação adicional em cada um de seus turnos. Essa ação pode ser usada apenas para fazer um ataque (apenas um ataque com arma), Disparada, Desvio, Esconder-se ou Usar um Objeto. Quando a magia termina, o alvo não pode se mover ou tomar ações até depois de seu próximo turno, enquanto uma onda de letargia o envolve.", ["Feiticeiro", "Mago"], false, true, ""),
  sp("Animar Mortos", 3, "Necromancia", "1 minuto", "3 metros", "Instantânea", true, true, true, "Uma gota de sangue, um pedaço de carne e uma pitada de pó de osso", "Esta magia cria um servo morto-vivo. Escolha uma pilha de ossos ou um corpo de um humanoide Médio ou Pequeno dentro do alcance. Sua magia impregna o alvo com uma imitação perversa de vida, levantando-o como uma criatura morta-viva. O alvo se torna um esqueleto se você escolheu ossos ou um zumbi se escolheu um corpo (o Mestre tem as estatísticas do jogo da criatura). Em cada um de seus turnos, você pode usar uma ação bônus para comandar mentalmente qualquer criatura que você criou com esta magia se a criatura estiver dentro de 18 metros de você (se você controlar múltiplas criaturas, você pode comandar qualquer ou todas elas ao mesmo tempo, emitindo o mesmo comando para cada uma). Você decide qual ação a criatura realizará e para onde se moverá durante seu próximo turno, ou pode emitir um comando geral, como guardar uma câmara ou corredor específico. Se você não emitir nenhum comando, a criatura apenas se defende contra criaturas hostis. Uma vez recebida uma ordem, a criatura continua a segui-la até que sua tarefa seja concluída. A criatura está sob seu controle por 24 horas, após o qual para de obedecer qualquer comando que você tenha dado. Para manter o controle da criatura por outras 24 horas, você deve lançar esta magia na criatura novamente antes do período de 24 horas atual terminar. Este uso da magia reafirma seu controle sobre até quatro criaturas que você animou com esta magia, em vez de animar uma nova.", ["Clérico", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 4º nível ou superior, você anima ou reafirma controle sobre duas criaturas mortas-vivas adicionais para cada nível de espaço acima do 3º. Cada uma das criaturas deve vir de um corpo ou pilha de ossos diferente."),
  sp("Bola de Fogo", 3, "Evocação", "1 ação", "150 pés", "Instantâneo", true, true, true, "Uma pequena bola de guano de morcego e enxofre.", "Um brilho intenso surge do seu dedo apontado até um ponto de sua escolha ao alcance e então floresce com um rugido baixo em uma explosão de chamas. Cada criatura em uma esfera de 20 pés de raio centrada naquele ponto deve fazer um teste de resistência de Destreza. Um alvo sofre 8d6 de dano de fogo em uma falha, ou metade do dano em um sucesso. O fogo se espalha ao redor de cantos. Ele incendeia objetos inflamáveis na área que não estão sendo usados ou carregados.", ["Feiticeiro", "Mago"], false, false, "Quando você conjura esta magia usando um espaço de magia de 4º nível ou superior, o dano aumenta em 1d6 para cada nível de espaço acima do 3º."),
  sp("Cabana Minúscula", 3, "Evocação", "1 minuto", "Pessoal", "8 horas", true, true, true, "Uma pequena conta de cristal.", "Um domo imóvel de força com raio de 3 metros brota em existência ao seu redor e acima de você e permanece estacionário pela duração. O feitiço termina se você sair de sua área. Nove criaturas de tamanho Médio ou menor podem caber dentro do domo com você. O feitiço falha se sua área inclui uma criatura maior ou mais de nove criaturas. Criaturas e objetos dentro do domo quando você lança este feitiço podem se mover através dele livremente. Todas as outras criaturas e objetos são impedidos de passar por ele. Feitiços e outros efeitos mágicos não podem se estender através do domo ou ser lançados através dele. A atmosfera dentro do espaço é confortável e seca, independentemente do clima fora. Até o feitiço terminar, você pode comandar o interior para se tornar fracamente iluminado ou escuro. O domo é opaco de fora, de qualquer cor que você escolha, mas é transparente de dentro.", ["Bardo", "Mago"], true, false, ""),
  sp("Caminhar sobre a Água", 3, "Transmutação", "1 ação", "30 pés", "1 hora", true, true, true, "Um pedaço de cortiça.", "Essa magia concede a habilidade de se mover através de qualquer superfície líquida--como água, ácido, lama, neve, areia movediça ou lava--como se fosse um solo sólido e inofensivo (criaturas que atravessam lava derretida ainda podem sofrer dano do calor). Até dez criaturas dispostas que você pode ver dentro do alcance ganham essa habilidade pela duração. Se você alvejar uma criatura submersa em um líquido, a magia carrega o alvo até a superfície do líquido a uma taxa de 18 metros por rodada.", ["Clérico", "Druida", "Patrulheiro", "Feiticeiro"], true, false, ""),
  sp("Círculo Mágico", 3, "Abjuração", "1 minuto", "10 pés", "1 hora", true, true, true, "Água benta ou prata em pó e ferro no valor de pelo menos 100 po, que o feitiço consome.", "Escolha um ou mais dos seguintes tipos de criaturas: celestiais, elementais, fadas, fiendas ou mortos-vivos. O círculo afeta uma criatura do tipo escolhido das seguintes maneiras: A criatura não pode entrar voluntariamente no cilindro por meios não mágicos. Se a criatura tentar usar teleportação ou viagem interplanar para fazê-lo, ela deve primeiro fazer um teste de salvação de carisma bem-sucedido. A criatura tem desvantagem em testes de ataque contra alvos dentro do cilindro. Alvos dentro do cilindro não podem ser enfeitiçados, assustados ou possuídos pela criatura. Quando você lança este feitiço, você pode optar por fazer sua magia funcionar na direção oposta, impedindo uma criatura do tipo especificado de sair do cilindro e protegendo alvos fora dele.", ["Clérico", "Paladino", "Bruxo", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 4º nível ou superior, a duração aumenta em 1 hora para cada nível de espaço acima do 3º."),
  sp("Clarividência", 3, "Adivinhação", "10 minutos", "1,5 quilômetro", "Até 10 minutos", true, true, true, "Um foco no valor de pelo menos 100 pe, uma corneta cravejada para audição ou um olho de vidro para visão.", "Você cria um sensor invisível dentro do alcance em um local familiar a você (um lugar que você visitou ou viu antes) ou em um local óbvio que é desconhecido para você (como atrás de uma porta, ao redor de um canto ou em um bosque de árvores). O sensor permanece no lugar pela duração e não pode ser atacado ou interagido de outra forma. Quando você lança o feitiço, escolhe visão ou audição. Você pode usar o sentido escolhido através do sensor como se estivesse em seu espaço. Como sua ação, você pode alternar entre visão e audição. Uma criatura que pode ver o sensor (como uma criatura se beneficiando de visão invisível ou visão verdadeira) vê uma esfera luminosa e intangível aproximadamente do tamanho de seu punho.", ["Bardo", "Clérico", "Feiticeiro", "Mago"], false, true, ""),
  sp("Contramágia", 3, "Abjuração", "1 reação", "60 pés", "Instantâneo", false, true, false, "", "Você tenta interromper uma criatura no processo de lançar uma magia. Se a criatura está lançando uma magia de 3º nível ou inferior, sua magia falha e não tem efeito. Se está lançando uma magia de 4º nível ou superior, faça um teste de habilidade usando sua habilidade de lançador de magias. O CD é igual a 10 + o nível da magia. Se conseguir, a magia da criatura falha e não tem efeito.", ["Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Convocar Animais", 3, "Conjuração", "1 ação", "18 metros", "Até 1 hora", true, true, false, "", "Você convoca espíritos feéricos que assumem a forma de bestas e aparecem em espaços desocupados que você possa ver dentro do alcance. Escolha uma das seguintes opções para o que aparece: - Uma besta com nível de desafio 2 ou menor - Duas bestas com nível de desafio 1 ou menor - Quatro bestas com nível de desafio 1/2 ou menor - Oito bestas com nível de desafio 1/4 ou menor - Cada besta também é considerada feérica, e desaparece quando cai a 0 pontos de vida ou quando a magia termina. As criaturas convocadas são amigas suas e de seus companheiros. Role iniciativa para as criaturas convocadas como um grupo, que tem seus próprios turnos. Obedecem a qualquer comando verbal que você emita (não requer ação sua). Se não emitir comandos, elas se defendem de criaturas hostis, mas caso contrário não realizam ações. O Mestre tem as estatísticas das criaturas.", ["Druida", "Patrulheiro"], false, true, "Quando você lança esta magia usando certos espaços de magia de nível superior, escolhe uma das opções de invocação acima, e mais criaturas aparecem: duas vezes mais com um espaço de 5º nível, três vezes mais com um espaço de 7º nível."),
  sp("Corcel Fantasmagórico", 3, "Ilusão", "1 minuto", "30 pés", "1 hora", true, true, false, "", "Uma criatura grande quase real e parecida com um cavalo aparece no chão em um espaço desocupado à sua escolha dentro do alcance. Você decide a aparência da criatura, mas ela está equipada com sela, freio e brida. Qualquer equipamento criado pela magia desaparece em uma nuvem de fumaça se for carregado a mais de 10 pés do corcel. Pela duração, você ou uma criatura à sua escolha pode cavalgar o corcel. A criatura usa as estatísticas de um cavalo de montaria, exceto que possui uma velocidade de 100 pés e pode viajar 10 milhas em uma hora, ou 13 milhas em ritmo acelerado. Quando a magia termina, o corcel desvanece gradualmente, dando ao cavaleiro 1 minuto para desmontar. A magia termina se você usar uma ação para dissipá-la ou se o corcel sofrer qualquer dano.", ["Mago"], true, false, ""),
  sp("Crescimento de Plantas", 3, "Transmutação", "1 ação", "150 pés", "Instantâneo", true, true, false, "", "Esta magia canaliza vitalidade para plantas em uma área específica. Existem dois usos possíveis para a magia, concedendo benefícios imediatos ou de longo prazo. Se você lançar esta magia usando 1 ação, escolha um ponto dentro do alcance. Todas as plantas normais em um raio de 100 pés centrado naquele ponto se tornam espessas e crescidas demais. Uma criatura se movendo pela área deve gastar 4 pés de movimento para cada 1 pé que se move. Você pode excluir uma ou mais áreas de qualquer tamanho dentro da área da magia de serem afetadas. Se você lançar esta magia durante 8 horas, você enriquece a terra. Todas as plantas em um raio de meia milha centrado em um ponto dentro do alcance se tornam enriquecidas por 1 ano. As plantas produzem o dobro da quantidade normal de alimento quando colhidas.", ["Bardo", "Druida", "Patrulheiro"], false, false, ""),
  sp("Criar Comida e Água", 3, "Conjuração", "1 ação", "30 pés", "Instantâneo", true, true, false, "", "Você cria 45 quilos de comida e 30 galões de água no chão ou em recipientes dentro do alcance, o suficiente para sustentar até quinze humanoides ou cinco cavalos por 24 horas. A comida é simples mas nutritiva, e estraga se não for comida após 24 horas. A água é limpa e não estraga.", ["Clérico", "Druida", "Paladino"], false, false, ""),
  sp("Dissipar Magia", 3, "Abjuração", "1 ação", "120 pés", "Instantâneo", true, true, false, "", "Escolha uma criatura, objeto ou efeito mágico ao alcance. Qualquer magia de 3º nível ou menor no alvo termina. Para cada magia de 4º nível ou maior no alvo, você faz um teste de habilidade usando sua habilidade de lançar magias. A CD é igual a 10 + o nível da magia. Se o teste for bem-sucedido, a magia termina.", ["Bardo", "Clérico", "Druida", "Paladino", "Feiticeiro", "Bruxo", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 4º nível ou superior, você termina automaticamente os efeitos de uma magia no alvo se o nível da magia for igual ou menor que o nível do espaço de magia que você usou."),
  sp("Falar com Mortos", 3, "Necromancia", "1 ação", "3 metros", "10 minutos", true, true, true, "Incenso queimando", "Você concede a semelhança de vida e inteligência a um cadáver de sua escolha dentro do alcance, permitindo que ele responda às perguntas que você fizer. O cadáver ainda deve ter uma boca e não pode ser um morto-vivo. A magia falha se o cadáver foi o alvo desta magia nos últimos 10 dias. Até que a magia termine, você pode fazer ao cadáver até cinco perguntas. O cadáver só conhece o que sabia em vida, incluindo as línguas que falava. As respostas são geralmente breves, crípticas ou repetitivas, e o cadáver não é obrigado a oferecer uma resposta verdadeira se você for hostil a ele ou se ele o reconhecer como um inimigo. Esta magia não devolve a alma da criatura ao seu corpo, apenas seu espírito animador. Assim, o cadáver não pode aprender novas informações, não compreende nada que tenha acontecido desde sua morte e não pode especular sobre eventos futuros.", ["Bardo", "Clérico"], false, false, ""),
  sp("Falar com Plantas", 3, "Transmutação", "1 ação", "Pessoal", "10 minutos", true, true, false, "", "Você imbui plantas dentro de 9 metros de você com senciência e animação limitadas, dando-lhes a capacidade de se comunicar com você e seguir seus comandos simples. Você pode questionar plantas sobre eventos na área da magia no último dia, obtendo informações sobre criaturas que passaram, clima e outras circunstâncias. Você também pode transformar terreno difícil causado pelo crescimento de plantas (como moitas e vegetação densa) em terreno comum que dura pela duração. Ou você pode transformar terreno comum onde plantas estão presentes em terreno difícil que dura pela duração, causando vinhas e galhos para impedir perseguidores, por exemplo. Plantas podem ser capazes de executar outras tarefas em seu nome, a critério do Mestre. A magia não permite que plantas se desenraízem e se movam, mas podem mover livremente galhos, gavinhas e caules. Se uma criatura vegetal estiver na área, você pode se comunicar com ela como se compartilhasse uma língua comum, mas não ganha habilidade mágica para influenciá-la. Esta magia pode fazer com que plantas criadas pela magia Emaranhar se libertem de uma criatura contida.", ["Bardo", "Druida", "Patrulheiro"], false, false, ""),
  sp("Farol de Esperança", 3, "Abjuração", "1 ação", "30 pés", "Até 1 minuto", true, true, false, "", "Esta magia concede esperança e vitalidade. Escolha qualquer número de criaturas dentro do alcance. Pela duração, cada alvo tem vantagem em testes de sabedoria e testes de morte, e recupera o número máximo de pontos de vida possível de qualquer cura.", ["Clérico"], false, true, ""),
  sp("Forma Gasosa", 3, "Transmutação", "1 ação", "Toque", "Até 1 hora", true, true, true, "Um pouco de gaze e uma lufada de fumaça.", "Você transforma uma criatura disposta que você toca, junto com tudo que ela está vestindo e carregando, em uma nuvem de névoa pela duração. A magia termina se a criatura cair para 0 pontos de vida. Uma criatura incorpórea não é afetada. Nesta forma, o único método de movimento do alvo é uma velocidade de voo de 10 pés. O alvo pode entrar e ocupar o espaço de outra criatura. O alvo tem resistência a dano não-mágico e tem vantagem em testes de salvação de Força, Destreza e Constituição. O alvo pode passar através de pequenos furos, aberturas estreitas e até simples rachaduras, embora trate líquidos como se fossem superfícies sólidas. O alvo não consegue cair e permanece flutuando no ar mesmo quando atordoado ou incapacitado. Enquanto na forma de uma nuvem de névoa, o alvo não consegue falar ou manipular objetos, e qualquer objeto que estava carregando ou segurando não consegue ser solto, usado ou de outra forma interagido. O alvo não consegue atacar ou lançar magias.", ["Feiticeiro", "Bruxo", "Mago"], false, true, ""),
  sp("Fundir-se na Pedra", 3, "Transmutação", "1 ação", "Toque", "8 horas", true, true, false, "", "Você entra em um objeto de pedra ou superfície grande o suficiente para conter completamente seu corpo, fundindo você e todos os equipamentos que carrega com a pedra durante a duração. Usando seu movimento, você entra na pedra em um ponto que pode tocar. Nada de sua presença permanece visível ou detectável de outra forma pelos sentidos não mágicos. Enquanto fundido com a pedra, você não consegue ver o que ocorre fora dela, e qualquer teste de Sabedoria (Percepção) que você fizer para ouvir sons fora dela é feito com desvantagem. Você permanece ciente da passagem do tempo e pode lançar magias em você mesmo enquanto fundido na pedra. Você pode usar seu movimento para sair da pedra onde entrou, o que termina a magia. Caso contrário, não consegue se mover. Dano físico menor à pedra não o prejudica, mas sua destruição parcial ou uma mudança em sua forma (na medida em que você não cabe mais nela) o expulsa e causa 6d6 de dano de concussão a você. A destruição completa da pedra (ou transmutação em uma substância diferente) o expulsa e causa 50 de dano de concussão a você. Se expulso, você cai propenso em um espaço desocupado mais próximo de onde entrou primeiro.", ["Clérico"], true, false, ""),
  sp("Glifo de Proteção", 3, "Abjuração", "1 hora", "Toque", "Até ser dissipada", true, true, true, "Incenso e diamante em pó no valor de pelo menos 200 po, a magia consome.", "Quando você lança esta magia, você inscreve um glifo que machuca outras criaturas, seja em uma superfície (como uma mesa ou uma porção de chão ou parede) ou dentro de um objeto que possa ser fechado (como um livro, pergaminho ou armário) para esconder o glifo. Se você optar por uma superfície, o glifo pode cobrir uma área de 10 pés ou menos de diâmetro. Se você selecionar um objeto, ele deve permanecer no lugar. Se o objeto for movido para mais de 10 pés de onde a magia foi lançada, o glifo desaparece e a magia expira sem ser acionada. O glifo é praticamente invisível e é necessário um teste de Inteligência (Investigação) contra seu CD de resistência para descobri-lo. Você determina o gatilho do glifo enquanto lança a magia. Para glifos inscritos em uma superfície, os gatilhos são tipicamente pisar no glifo, remover um objeto colocado no glifo, aproximar-se a uma certa distância do glifo ou manipular um objeto no qual o glifo está inscrito. Para glifos inscritos em um objeto, os gatilhos são tipicamente abrir o objeto, aproximar-se a uma distância do objeto, ver ou ler o glifo. Quando o glifo é acionado, a magia termina. Você pode refinar as condições de gatilho para que a magia funcione apenas em certas circunstâncias ou atributos físicos (altura ou peso), tipo de criatura (por exemplo, apenas aberrações ou Elfos Negros disparam o glifo) ou alinhamento. Você também pode determinar condições para que certas criaturas não disparem o glifo, usando uma senha, por exemplo. Quando você inscreve o glifo, faça uma escolha entre runas explosivas ou glifo de magia. Runas Explosivas: Quando acionadas, energia mágica brota do glifo em uma esfera de raio de 20 pés centrada no glifo. A esfera ignora cantos. Cada criatura na área deve fazer um teste de resistência de Destreza ou sofre 5d8 de dano de ácido, relâmpago, fogo, frio ou trovão (a ser determinado durante a criação do glifo). Se bem-sucedida, o dano é reduzido pela metade. Glifo de Magia: Você pode armazenar uma magia de nível 3 ou menor preparada no glifo para ser lançada durante a criação do glifo. A magia deve atingir uma criatura ou área. A magia armazenada não tem efeito imediato quando lançada dessa maneira. Quando o glifo é acionado, a magia armazenada é lançada. Se a magia tiver alvo, ela atingirá a criatura que acionou o glifo. Se a magia afeta uma área, a área é centrada naquela criatura. Se a magia invoca criaturas hostis ou cria objetos afiados ou armadilhas, elas também aparecem o mais próximo possível do invasor e atacam. Se a magia requer concentração, ela persiste pela duração da magia.", ["Bardo", "Clérico", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de nível 4 ou superior, o dano das runas explosivas aumenta em 1d8 para cada nível acima do 3º. Se você criar um glifo de magia, você pode armazenar uma magia cujo nível seja equivalente ou menor ao espaço de magia usado para inscrever o glifo."),
  sp("Guardiões Espirituais", 3, "Conjuração", "1 ação", "Pessoal", "Até 10 minutos", true, true, true, "Um símbolo sagrado.", "Você convoca espíritos para protegê-lo. Eles voam ao seu redor a uma distância de 15 pés pela duração. Se você é bom ou neutro, sua forma espectral aparenta ser angelical ou feérica (sua escolha). Se você é maligno, eles aparecem demoníacos. Quando você lança este feitiço, você pode designar qualquer número de criaturas que você possa ver para não serem afetadas por ele. A velocidade de uma criatura afetada é reduzida à metade na área, e quando a criatura entra na área pela primeira vez em um turno ou começa seu turno lá, ela deve fazer um teste de resistência de Sabedoria. Em uma falha, a criatura sofre 3d8 de dano radiante (se você é bom ou neutro) ou 3d8 de dano necrótico (se você é maligno). Em um sucesso, a criatura sofre metade do dano.", ["Clérico"], false, true, "Quando você lança este feitiço usando um espaço de feitiço de 4º nível ou superior, o dano aumenta em 1d8 para cada nível de espaço acima do 3º."),
  sp("Imagem Maior", 3, "Ilusão", "1 ação", "120 pés", "Até 10 minutos", true, true, true, "Um pouco de lã.", "Você cria a imagem de um objeto, criatura ou outro fenômeno visível que não é maior que um cubo de 20 pés. A imagem aparece em um local que você pode ver ao alcance e dura pela duração. Parece completamente real, incluindo sons, cheiros e temperatura apropriados à coisa representada. Você não pode criar calor ou frio suficientes para causar dano, um som alto o suficiente para causar dano de trovão ou surdez em uma criatura, ou um cheiro que pudesse deixar uma criatura doente (como o fedor de um troglodita). Enquanto você estiver ao alcance da ilusão, você pode usar sua ação para fazer a imagem se mover para qualquer outro local ao alcance. Conforme a imagem muda de local, você pode alterar sua aparência para que seus movimentos pareçam naturais para a imagem. Por exemplo, se você criar a imagem de uma criatura e a mover, você pode alterar a imagem para que pareça estar caminhando. Da mesma forma, você pode fazer a ilusão fazer diferentes sons em diferentes momentos, até mesmo levando a cabo uma conversa, por exemplo. A interação física com a imagem a revela como sendo uma ilusão, porque as coisas podem passar através dela. Uma criatura que usa sua ação para examinar a imagem pode determinar que é uma ilusão com um teste de Inteligência (Investigação) bem-sucedido contra seu CD de salvamento de magia. Se uma criatura discerne a ilusão pelo que é, a criatura pode ver através da imagem e suas outras qualidades sensoriais se tornam fracas para a criatura.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, true, "Quando você lança essa magia usando um espaço de magia de 6º nível ou superior, a magia dura até ser dissipada, sem exigir sua concentração."),
  sp("Impor Maldição", 3, "Necromancia", "1 ação", "Toque", "Até 1 minuto", true, true, false, "", "Você toca uma criatura, e essa criatura deve fazer um teste de sabedoria ou ficar amaldiçoada pela duração da magia. Quando você lança esta magia, escolha a natureza da maldição entre as seguintes opções: - Escolha uma habilidade. Enquanto amaldiçoada, o alvo tem desvantagem em testes de habilidade e testes de resistência feitos com essa habilidade. - Enquanto amaldiçoada, o alvo tem desvantagem em testes de ataque contra você. - Enquanto amaldiçoada, o alvo deve fazer um teste de sabedoria no início de cada um de seus turnos. Se falhar, desperdiça sua ação naquele turno fazendo nada. - Enquanto o alvo está amaldiçoado, seus ataques e magias causam 1d8 de dano necrótico adicional ao alvo. Uma magia remover maldição encerra este efeito. A critério do mestre, você pode escolher um efeito de maldição alternativo, mas não deve ser mais poderoso do que os descritos acima. O mestre tem a palavra final sobre o efeito da maldição.", ["Bardo", "Clérico", "Mago"], false, true, "Se você lançar esta magia usando um espaço de magia de 4º nível ou superior, a duração é concentração, até 10 minutos. Se usar um espaço de magia de 5º nível ou superior, a duração é 8 horas. Se usar um espaço de magia de 7º nível ou superior, a duração é 24 horas. Se usar um espaço de magia de 9º nível, a magia dura até ser dissipada. Usar um espaço de magia de 5º nível ou superior concede uma duração que não requer concentração."),
  sp("Invocar Raio", 3, "Conjuração", "1 ação", "120 pés", "Até 10 minutos", true, true, false, "", "Uma nuvem de tempestade aparece em forma de cilindro com 10 pés de altura e 60 pés de raio, centrada em um ponto que você pode ver 100 pés diretamente acima de você. O feitiço falha se você não conseguir ver um ponto no ar onde a nuvem de tempestade pudesse aparecer (por exemplo, se você estiver em uma sala que não possa acomodar a nuvem). Quando você lança o feitiço, escolha um ponto que você possa ver dentro do alcance. Um raio de relâmpago pisca da nuvem para aquele ponto. Cada criatura a 5 pés daquele ponto deve fazer um teste de resistência de Destreza. Uma criatura sofre 3d10 de dano de relâmpago com uma falha, ou metade do dano com um sucesso. Em cada um de seus turnos até o feitiço terminar, você pode usar sua ação para invocar um raio dessa forma novamente, atingindo o mesmo ponto ou um diferente. Se você estiver ao ar livre em condições tempestuosas quando lançar este feitiço, o feitiço lhe dá controle sobre a tempestade existente em vez de criar uma nova. Nessas condições, o dano do feitiço aumenta em 1d10.", ["Druida"], false, true, "Quando você lança este feitiço usando um espaço de feitiço de 4º nível ou superior, o dano aumenta em 1d10 para cada nível de espaço acima do 3º."),
  sp("Lentidão", 3, "Transmutação", "1 ação", "120 pés", "Até 1 minuto", true, true, true, "Uma gota de melaço.", "Você altera o tempo ao redor de até seis criaturas de sua escolha em um cubo de 40 pés dentro do alcance. Cada alvo deve ser bem-sucedido em um teste de salvamento de Sabedoria ou ser afetado por essa magia pela duração. A velocidade de um alvo afetado é reduzida pela metade, recebe uma penalidade de -2 em CA e testes de salvamento de Destreza, e não pode usar reações. Em seu turno, pode usar uma ação ou uma ação bônus, não ambas. Independentemente das habilidades da criatura ou itens mágicos, não pode fazer mais de um ataque de corpo a corpo ou à distância durante seu turno. Se a criatura tentar lançar uma magia com tempo de lançamento de 1 ação, role um d20. Com 11 ou superior, a magia não entra em efeito até o próximo turno da criatura, e a criatura deve usar sua ação naquele turno para completar a magia. Se não conseguir, a magia é desperdiçada. Uma criatura afetada por essa magia faz outro teste de salvamento de Sabedoria no final de seu turno. Em um salvamento bem-sucedido, o efeito termina para ela.", ["Feiticeiro", "Mago"], false, true, ""),
  sp("Línguas", 3, "Adivinhação", "1 ação", "Toque", "1 hora", true, false, true, "Um pequeno modelo de argila de um zigurate.", "Esta magia concede à criatura tocada a habilidade de compreender qualquer linguagem falada que ouve. Além disso, quando o alvo fala, qualquer criatura que conhece pelo menos um idioma e pode ouvir o alvo compreende o que ele diz.", ["Bardo", "Clérico", "Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Luz do Dia", 3, "Evocação", "1 ação", "18 metros", "1 hora", true, true, false, "", "Uma esfera de luz com raio de 18 metros se irradia a partir de um ponto à sua escolha dentro do alcance. A esfera emite luz plena e ilumina fracamente por 18 metros adicionais. Se você escolheu um ponto em um objeto que está segurando ou que não está sendo vestido ou carregado, a luz emana do objeto e se move com ele. Cobrir completamente o objeto afetado com um objeto opaco, como uma tigela ou um elmo, bloqueia a luz. Se alguma área deste feitiço se sobrepor a uma área de escuridão criada por um feitiço de 3º nível ou menor, o feitiço que criou a escuridão é dissipado.", ["Clérico", "Druida", "Paladino", "Patrulheiro", "Feiticeiro"], false, false, ""),
  sp("Medo", 3, "Ilusão", "1 ação", "Pessoal", "Até 1 minuto", true, true, true, "Uma pena branca ou o coração de uma galinha", "Você projeta uma imagem fantasmagórica dos piores medos de uma criatura. Cada criatura em um cone de 30 pés deve ser bem-sucedida em um teste de resistência de Sabedoria ou soltar o que estiver segurando e ficar assustada pela duração. Enquanto assustada por esta magia, uma criatura deve realizar a ação de Disparada e se afastar de você pela rota mais segura disponível em cada um de seus turnos, a menos que não haja para onde se mover. Se a criatura terminar seu turno em um local onde não tem linha de visão para você, a criatura pode fazer um teste de resistência de Sabedoria. Em um salvamento bem-sucedido, a magia termina para essa criatura.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, true, ""),
  sp("Mensagem", 3, "Evocação", "1 ação", "Ilimitado", "1 rodada", true, true, true, "Um curto pedaço de fio de cobre fino.", "Você envia uma mensagem curta de vinte e cinco palavras ou menos para uma criatura com a qual você está familiarizado. A criatura ouve a mensagem em sua mente, o reconhece como remetente se o conhecer e pode responder da mesma forma imediatamente. O feitiço permite que criaturas com valores de Inteligência de pelo menos 1 entendam o significado de sua mensagem. Você pode enviar a mensagem a qualquer distância e até para outros planos de existência, mas se o alvo estiver em um plano diferente do seu, há uma chance de 5% de que a mensagem não chegue.", ["Bardo", "Clérico", "Mago"], false, false, ""),
  sp("Muralha de Vento", 3, "Evocação", "1 ação", "120 pés", "Até 1 minuto", true, true, true, "Um minúsculo leque e uma pena de origem exótica.", "Uma muralha de vento forte sobe do chão em um ponto à sua escolha dentro do alcance. Você pode fazer a muralha até 50 pés de comprimento, 15 pés de altura e 1 pé de espessura. Você pode moldar a muralha de qualquer forma que escolher, contanto que faça um caminho contínuo no chão. A muralha dura pela duração. Quando a muralha aparece, cada criatura em sua área deve fazer um teste de salvação de Força. Uma criatura sofre 3d8 de dano de concussão em uma falha, ou metade do dano em uma bem-sucedida. O vento forte mantém nevoeiro, fumaça e outros gases afastados. Criaturas voadoras pequenas ou menores ou objetos não podem passar pela muralha. Materiais soltos e leves trazidos para a muralha voam para cima. Flechas, virotes e outros projéteis ordinários lançados contra alvos atrás da muralha são desviados para cima e automaticamente erram. (Pedregulhos arremessados por gigantes ou máquinas de cerco e projéteis semelhantes não são afetados.) Criaturas em forma gasosa não podem passar por ela.", ["Druida", "Patrulheiro"], false, true, ""),
  sp("Não Detecção", 3, "Abjuração", "1 ação", "Toque", "8 horas", true, true, true, "Um pouco de pó de diamante no valor de 25 po borrifado sobre o alvo, que o feitiço consome.", "Durante a duração, você esconde um alvo que você toca da magia de adivinhação. O alvo pode ser uma criatura disposta ou um lugar ou um objeto não maior que 10 pés em qualquer dimensão. O alvo não pode ser alvo de nenhuma magia de adivinhação ou percebido por sensores de escrutínio mágico.", ["Bardo", "Patrulheiro", "Mago"], false, false, ""),
  sp("Nuvem Fedorenta", 3, "Conjuração", "1 ação", "90 pés", "Até 1 minuto", true, true, true, "Um ovo podre ou várias folhas de raiz-fedorenta.", "Você cria uma esfera de 20 pés de raio de gás amarelo e nauseabundo centrada em um ponto dentro do alcance. A nuvem se espalha ao redor de cantos, e sua área está pesadamente obscurecida. A nuvem permanece no ar pela duração. Cada criatura que está completamente dentro da nuvem no início de seu turno deve fazer um teste de resistência de Constituição contra veneno. Em uma falha, a criatura gasta sua ação naquele turno retching e cambaleando. Criaturas que não precisam respirar ou são imunes a veneno automaticamente sucessos neste teste de resistência. Um vento moderado (pelo menos 10 milhas por hora) dispersa a nuvem depois de 4 rodadas. Um vento forte (pelo menos 20 milhas por hora) a dispersa depois de 1 rodada.", ["Bardo", "Feiticeiro", "Mago"], false, true, ""),
  sp("Padrão Hipnotizante", 3, "Ilusão", "1 ação", "120 pés", "Até 1 minuto", false, true, true, "Uma vara brilhante de incenso ou um frasco de cristal cheio de material fosforescente.", "Você cria um padrão de cores retorcidas que se tecem pelo ar dentro de um cubo de 30 pés ao alcance. O padrão aparece por um momento e desaparece. Cada criatura na área que vê o padrão deve fazer um teste de salvação de Sabedoria. Se falhar, a criatura fica enfeitiçada pela duração. Enquanto enfeitiçada por esta magia, a criatura fica incapacitada e sua velocidade é 0. A magia termina para uma criatura afetada se ela sofrer dano algum ou se outro alguém usar uma ação para despertá-la de seu torpor.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, true, ""),
  sp("Palavra Curativa em Massa", 3, "Evocação", "1 ação de bônus", "60 pés", "Instantâneo", true, false, false, "", "Conforme você pronuncia palavras de restauração, até seis criaturas de sua escolha que você pode ver ao alcance recuperam pontos de vida iguais a 1d4 + seu modificador de capacidade de lançamento de magia. Essa magia não tem efeito em mortos-vivos ou construtos.", ["Clérico"], false, false, "Quando você lança essa magia usando um espaço de magia de 4º nível ou superior, a cura aumenta em 1d4 para cada nível de espaço acima do 3º."),
  sp("Piscar", 3, "Transmutação", "1 ação", "Pessoal", "1 minuto", true, true, false, "", "Role um d20 no final de cada um de seus turnos pela duração do feitiço. Com um resultado de 11 ou superior, você desaparece do seu plano de existência atual e aparece no Plano Etéreo (o feitiço falha e a lançada é desperdiçada se você já estava naquele plano). No início do seu próximo turno, e quando o feitiço termina se você estiver no Plano Etéreo, você retorna a um espaço desocupado à sua escolha que você possa ver dentro de 10 pés do espaço de onde desapareceu. Se nenhum espaço desocupado estiver disponível dentro desse alcance, você aparece no espaço desocupado mais próximo (escolhido aleatoriamente se mais de um espaço estiver igualmente próximo). Você pode descartar este feitiço como uma ação. Enquanto estiver no Plano Etéreo, você pode ver e ouvir o plano de onde veio, que aparece em tons de cinza, e você não pode ver nada lá a mais de 60 pés de distância. Você só pode afetar e ser afetado por outras criaturas no Plano Etéreo. Criaturas que não estão lá não podem percebê-lo ou interagir com você, a menos que tenham a capacidade de fazer isso.", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Proteção contra Energia", 3, "Abjuração", "1 ação", "Toque", "Até 1 hora", true, true, false, "", "Pela duração, a criatura disposta que você toca tem resistência a um tipo de dano de sua escolha: ácido, frio, fogo, relâmpago ou trovão.", ["Clérico", "Druida", "Patrulheiro", "Feiticeiro", "Mago"], false, true, ""),
  sp("Raio", 3, "Evocação", "1 ação", "Pessoal", "Instantâneo", true, true, true, "Um pouco de pelo e uma vara de âmbar, cristal ou vidro.", "Um raio formando uma linha de 30 metros de comprimento e 1,5 metros de largura irrompe de você em uma direção à sua escolha. Cada criatura na linha deve fazer um teste de resistência de Destreza. Uma criatura sofre 8d6 de dano de raio em uma falha, ou metade desse dano em uma bem-sucedida. O raio incendeia objetos inflamáveis na área que não estejam sendo usados ou carregados.", ["Feiticeiro", "Mago"], false, false, "Quando você lança essa magia usando um espaço de magia de 4º nível ou superior, o dano aumenta 1d6 para cada nível acima do 3º."),
  sp("Reavivar", 3, "Conjuração", "1 ação", "Toque", "Instantâneo", true, true, true, "Diamantes no valor de 300 po, que o feitiço consome.", "Você toca uma criatura que morreu nos últimos minutos. Essa criatura volta à vida com 1 ponto de vida. Este feitiço não pode trazer de volta à vida uma criatura que morreu de velhice, nem pode restaurar nenhuma parte do corpo faltante.", ["Clérico", "Paladino"], false, false, ""),
  sp("Remover Maldição", 3, "Abjuração", "1 ação", "Toque", "Instantâneo", true, true, false, "", "Ao seu toque, todas as maldições que afetam uma criatura ou objeto terminam. Se o objeto for um item mágico amaldiçoado, sua maldição permanece, mas a magia quebra a sintonia do seu dono com o objeto para que possa ser removido ou descartado.", ["Clérico", "Paladino", "Bruxo", "Mago"], false, false, ""),
  sp("Respiração Aquática", 3, "Transmutação", "1 ação", "30 pés", "24 horas", true, true, true, "Um curto pedaço de junco ou palha.", "Essa magia concede a um máximo de dez criaturas dispostas dentro do alcance que você pode ver a habilidade de respirar debaixo d\\'água até o fim de sua duração. As criaturas afetadas também retêm seu padrão normal de respiração.", ["Druida", "Patrulheiro", "Feiticeiro", "Mago"], true, false, ""),
  sp("Tempestade de Granizo", 3, "Conjuração", "1 ação", "150 pés", "Até 1 minuto", true, true, true, "Um polegar de pó e algumas gotas de água.", "Até a magia terminar, chuva congelante e granizo caem em um cilindro de 20 pés de altura com raio de 40 pés centrado em um ponto de sua escolha dentro do alcance. A área é fortemente obscurecida, e chamas expostas na área são apagadas. O solo na área é coberto com gelo escorregadio, tornando-o terreno difícil. Quando uma criatura entra na área da magia pela primeira vez em um turno ou começa seu turno lá, deve fazer um teste de salvamento de Destreza. Em uma falha de salvamento, cai de bruços. Se uma criatura estiver se concentrando na área da magia, a criatura deve fazer um teste de salvamento bem-sucedido de Constituição contra sua CD de salvamento de magia ou perder a concentração.", ["Druida", "Feiticeiro", "Mago"], false, true, ""),
  sp("Toque Vampírico", 3, "Necromancia", "1 ação", "Pessoal", "Até 1 minuto", true, true, false, "", "O toque de sua mão envolvida em sombras pode sugar a força vital de outros para curar seus ferimentos. Faça um ataque de feitiço corpo a corpo contra uma criatura ao seu alcance. Em um acerto, o alvo recebe 3d6 de dano necrótico, e você recupera pontos de vida iguais à metade do dano necrótico causado. Até o feitiço terminar, você pode fazer o ataque novamente a cada turno seu como uma ação.", ["Bruxo", "Mago"], false, true, "Quando você lança este feitiço usando um espaço de feitiço de 4º nível ou superior, o dano aumenta em 1d6 para cada nível de espaço acima do 3º."),
  sp("Voo", 3, "Transmutação", "1 ação", "Toque", "Até 10 minutos", true, true, true, "Uma pena de asa de qualquer pássaro.", "Você toca uma criatura disposta. O alvo ganha uma velocidade de voo de 60 pés pela duração. Quando a magia termina, o alvo cai se ainda estiver no ar, a menos que possa impedir a queda.", ["Feiticeiro", "Bruxo", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 4º nível ou superior, você pode visar uma criatura adicional para cada nível de espaço acima do 3º."),
  sp("Adivinhação", 4, "Adivinhação", "1 ação", "Pessoal", "Instantâneo", true, true, true, "Incenso e uma oferenda sacrificial apropriada à sua religião, com valor combinado de pelo menos 25 po, que a magia consome.", "Sua magia e uma oferenda o colocam em contato com um deus ou servos de um deus. Você faz uma única pergunta sobre um objetivo, evento ou atividade específicos que ocorram nos próximos 7 dias. O Mestre oferece uma resposta verdadeira. A resposta pode ser uma frase curta, uma rima enigmática ou um augúrio. A magia não leva em conta circunstâncias possíveis que possam mudar o resultado, como o lançamento de magias adicionais ou a perda ou ganho de um companheiro. Se você lançar a magia duas ou mais vezes antes de terminar seu próximo repouso longo, há uma chance cumulativa de 25% para cada lançamento após o primeiro de você obter uma leitura aleatória. O Mestre faz essa rolagem em segredo.", ["Druida"], true, false, ""),
  sp("Assassino Fantasmagórico", 4, "Ilusão", "1 ação", "120 pés", "Até 1 minuto", true, true, false, "", "Você toca nos pesadelos de uma criatura que pode ver dentro do alcance e cria uma manifestação ilusória de seus medos mais profundos, visível apenas para essa criatura. O alvo deve fazer um teste de resistência de Sabedoria. Em uma falha, o alvo fica assustado pela duração. No início de cada um dos turnos do alvo antes do feitiço terminar, o alvo deve obter sucesso em um teste de resistência de Sabedoria ou sofrer 4d10 de dano psíquico. Em um sucesso, o feitiço termina.", ["Mago"], false, true, "Quando você lança este feitiço usando um espaço de feitiço de 5º nível ou superior, o dano aumenta em 1d10 para cada nível de espaço acima do 4º."),
  sp("Banimento", 4, "Abjuração", "1 ação", "60 pés", "Até 1 minuto", true, true, true, "Um item desagradável para o alvo.", "Você tenta enviar uma criatura que pode ver em alcance para outro plano de existência. O alvo deve ter sucesso em um teste de resistência de Carisma ou ser banido. Se o alvo é nativo do plano de existência em que você está, você o bane para um demiplanar inofensivo. Lá, o alvo fica incapacitado. O alvo permanece lá até a magia terminar, ponto em que o alvo reaparece no espaço que deixou ou no espaço desocupado mais próximo se aquele espaço estiver ocupado. Se o alvo é nativo de um plano de existência diferente daquele em que você está, o alvo é banido com um leve som de estalo, retornando ao seu plano natal. Se a magia terminar antes de 1 minuto ter passado, o alvo reaparece no espaço que deixou ou no espaço desocupado mais próximo se aquele espaço estiver ocupado. Caso contrário, o alvo não retorna.", ["Clérico", "Paladino", "Feiticeiro", "Bruxo", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 5º nível ou superior, você pode alvejar uma criatura adicional para cada nível de espaço acima do 4º."),
  sp("Baú Secreto", 4, "Conjuração", "1 ação", "Toque", "Instantâneo", true, true, true, "Um baú refinado, 3 pés por 2 pés por 2 pés, construído de materiais raros no valor de pelo menos 5.000 po, e uma réplica Minúscula feita dos mesmos materiais no valor de pelo menos 50 po.", "Você esconde um baú e todo o seu conteúdo no Plano Etéreo. Você deve tocar o baú e a réplica em miniatura que serve como componente material do feitiço. O baú pode conter até 12 pés cúbicos de material inanimado (3 pés por 2 pés por 2 pés). Enquanto o baú permanecer no Plano Etéreo, você pode usar uma ação e tocar a réplica para recuperar o baú. Ele aparece em um espaço desocupado no chão a até 1,5 metro de você. Você pode enviar o baú de volta ao Plano Etéreo usando uma ação e tocando tanto o baú quanto a réplica. Após 60 dias, há uma chance cumulativa de 5% por dia de que o efeito do feitiço termine. Este efeito termina se você lançar este feitiço novamente, se o baú réplica menor for destruído ou se você escolher terminar o feitiço como uma ação. Se o feitiço terminar e o baú maior estiver no Plano Etéreo, ele será irremediavelmente perdido.", ["Mago"], false, false, ""),
  sp("Cão Fiel", 4, "Conjuração", "1 ação", "30 pés", "8 horas", true, true, true, "Um pequeno apito de prata, um pedaço de osso e um fio", "Você conjura um cão de guarda fantasmagórico em um espaço desocupado que você possa ver dentro do alcance, onde permanece pela duração, até você dispensá-lo como uma ação, ou até você se mover mais de 100 pés de distância dele. O cão é invisível para todas as criaturas exceto você e não pode ser ferido. Quando uma criatura Pequena ou maior chega a 30 pés de distância sem primeiro falar a senha que você especifica quando lança esta magia, o cão começa a latir alto. O cão vê criaturas invisíveis e consegue ver para o Plano Etéreo. Ele ignora ilusões. No início de cada um de seus turnos, o cão tenta morder uma criatura dentro de 5 pés de distância que seja hostil a você. O bônus de ataque do cão é igual ao seu modificador de habilidade de lançamento de magia + seu bônus de proficiência. Num acerto, causa 4d8 de dano perfurante.", ["Mago"], false, false, ""),
  sp("Compulsão", 4, "Encantamento", "1 ação", "9 metros", "Até 1 minuto", true, true, false, "", "Criaturas de sua escolha que você possa ver dentro do alcance e que possam ouvi-lo devem fazer um teste de resistência de Sabedoria. Um alvo tem sucesso automaticamente neste teste de resistência se não puder ser enfeitiçado. Se o teste falhar, o alvo é afetado por esta magia. Enquanto a magia perdurar, você pode usar uma ação bônus em cada um de seus turnos para designar uma direção que seja horizontal para você. Cada alvo afetado deve usar o máximo possível de seu movimento para se mover nessa direção em seu próximo turno. Pode realizar qualquer ação antes de se mover. Após se mover desta forma, pode fazer outro teste de Sabedoria para tentar encerrar o efeito. Um alvo não é compelido a se mover para um perigo obviamente mortal, como fogo ou um poço, mas provocará ataques de oportunidade para se mover na direção designada.", ["Bardo"], false, true, ""),
  sp("Confusão", 4, "Encantamento", "1 ação", "27 metros", "Até 1 minuto", true, true, true, "Três cascas de noz", "Esta magia ataca e distorce as mentes de criaturas, gerando ilusões e causando ações descontroladas. Cada criatura em uma esfera de raio de 3 metros centrada em um ponto escolhido dentro do alcance da magia deve fazer um teste de resistência de Sabedoria, caso contrário, será afetada pela magia. Um alvo afetado pode reagir e deve começar no início de 1d10 para cada um de seus turnos de jogo para determinar seu comportamento naquele turno. No final de cada turno, uma criatura afetada pode fazer um teste de resistência de Sabedoria. Se bem-sucedido, o efeito da magia termina para este alvo.", ["Bardo", "Druida", "Feiticeiro", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de nível 5 ou superior, o raio da esfera aumenta 1,5 metros para cada nível de espaço acima do 4º."),
  sp("Controlar Água", 4, "Transmutação", "1 ação", "300 pés", "Até 10 minutos", true, true, true, "Uma gota de água e um punhado de pó", "Até a magia terminar, você controla qualquer água independente dentro de uma área que você escolher que seja um cubo de até 100 pés de lado. Você pode escolher um dos seguintes efeitos quando lança essa magia. Como uma ação em seu turno, você pode repetir o mesmo efeito ou escolher um diferente. Inundação. Você faz o nível de água de toda água parada na área subir até 20 pés. Se a área inclui uma costa, a água transborda para terra seca ou cria uma onda de 20 pés de altura que viaja de um lado da área para o outro e depois desaba. Qualquer veículo Enorme ou menor no caminho da onda é carregado com ela para o outro lado. Qualquer veículo Enorme ou menor atingido pela onda tem 25% de chance de virar. O nível da água permanece elevado até a magia terminar ou você escolher um efeito diferente. Se esse efeito produziu uma onda, a onda se repete no início de seu próximo turno enquanto o efeito de inundação dura. Separar Água. Você faz a água na área se separar e criar uma trincheira. A trincheira se estende pela área da magia, e a água separada forma uma parede em cada lado. A trincheira permanece até a magia terminar ou você escolher um efeito diferente. A água então lentamente preenche a trincheira durante o próximo turno até que o nível normal da água seja restaurado. Redirecionar Fluxo. Você faz a água fluindo na área se mover em uma direção que você escolher, mesmo que a água tenha que fluir sobre obstáculos, subir paredes ou em outras direções improváveis. A água na área se move como você direciona, mas uma vez que se move além da área da magia, ela retoma seu fluxo baseado nas condições do terreno. A água continua a se mover na direção que você escolheu até a magia terminar ou você escolher um efeito diferente. Redemoinho. Esse efeito requer um corpo de água com pelo menos 50 pés de largura e 25 pés de profundidade. Você faz um redemoinho se formar no centro da área. O redemoinho forma um vórtice que tem 5 pés de largura na base, até 50 pés de largura no topo e 25 pés de altura. Qualquer criatura ou objeto na água e dentro de 25 pés do vórtice é puxado 10 pés em sua direção. Uma criatura pode nadar para longe do vórtice fazendo um teste de Força (Atletismo) contra seu CD de magia. Quando uma criatura entra no vórtice pela primeira vez em um turno ou começa seu turno lá, ela deve fazer um teste de resistência de Força. Se falhar, a criatura sofre 2d8 de dano de impacto e fica presa no vórtice até a magia terminar. Se conseguir, a criatura sofre metade do dano e não fica presa no vórtice. Uma criatura presa no vórtice pode usar sua ação para tentar nadar para longe do vórtice como descrito acima, mas tem desvantagem no teste de Força (Atletismo) para fazê-lo. A primeira vez a cada turno que um objeto entra no vórtice, o objeto sofre 2d8 de dano de impacto; esse dano ocorre cada turno que permanece no vórtice.", ["Clérico", "Druida", "Mago"], false, true, ""),
  sp("Convocar Elementais Menores", 4, "Conjuração", "1 minuto", "27 metros", "Até 1 hora", true, true, false, "", "Você convoca elementais que aparecem em espaços desocupados que você pode ver dentro do alcance. Você escolhe uma das seguintes opções para o que aparece: - Um elemental com classificação de desafio 2 ou menor - Dois elementais com classificação de desafio 1 ou menor - Quatro elementais com classificação de desafio 1/2 ou menor - Oito elementais com classificação de desafio 1/4 ou menor. Um elemental convocado por esta magia desaparece quando seus pontos de vida chegam a 0 ou quando a magia termina. As criaturas convocadas são amigas suas e de seus companheiros. Role iniciativa para as criaturas convocadas como um grupo, que têm seus próprios turnos. Elas obedecem a qualquer comando verbal que você lhes der (nenhuma ação necessária de sua parte). Se você não der nenhum comando a elas, elas se defendem de criaturas hostis, mas caso contrário não tomam ações. O mestre tem as estatísticas das criaturas.", ["Druida", "Mago"], false, true, "Quando você lança esta magia usando certos espaços de magia de nível superior, você escolhe uma das opções de convocação acima, e mais criaturas aparecem: o dobro com um espaço de 6º nível e o triplo com um espaço de 8º nível."),
  sp("Convocar Seres da Floresta", 4, "Conjuração", "1 ação", "18 metros", "Até 1 hora", true, true, true, "Uma baga de azevinho por criatura convocada.", "Você convoca criaturas feéricas que aparecem em espaços desocupados que você pode ver dentro do alcance. Escolha uma das seguintes opções para o que aparece: - Uma criatura feérica com classificação de desafio 2 ou menor - Duas criaturas feéricas com classificação de desafio 1 ou menor - Quatro criaturas feéricas com classificação de desafio 1/2 ou menor - Oito criaturas feéricas com classificação de desafio 1/4 ou menor. Uma criatura convocada desaparece quando seus pontos de vida chegam a 0 ou quando a magia termina. As criaturas convocadas são amigas suas e de seus companheiros. Role iniciativa para as criaturas convocadas como um grupo, que têm seus próprios turnos. Elas obedecem a qualquer comando verbal que você lhes der (nenhuma ação necessária de sua parte). Se você não der nenhum comando a elas, elas se defendem de criaturas hostis, mas caso contrário não tomam ações. O mestre tem as estatísticas das criaturas.", ["Druida", "Patrulheiro"], false, true, "Quando você lança esta magia usando certos espaços de magia de nível superior, você escolhe uma das opções de convocação acima, e mais criaturas aparecem: o dobro com um espaço de 6º nível e o triplo com um espaço de 8º nível."),
  sp("Dominar Besta", 4, "Encantamento", "1 ação", "60 pés", "Até 1 minuto", true, true, false, "", "Você tenta enganar uma criatura que você possa ver ao alcance. Ela deve ser bem-sucedida em um teste de resistência de Sabedoria ou ser enfeitiçada por você pela duração. Se você ou criaturas que lhe são amigas estão lutando contra ela, ela tem vantagem no teste de resistência. Enquanto a criatura está enfeitiçada, você tem um vínculo telepático com ela contanto que vocês dois estejam no mesmo plano de existência. Você pode usar este vínculo telepático para dar comandos à criatura enquanto você está consciente (nenhuma ação necessária), que ela faz o seu melhor para obedecer. Você pode especificar um curso de ação simples e geral, como \"Ataque aquela criatura\", \"Corra para lá\" ou \"Pegue aquele objeto\". Se a criatura completa a ordem e não recebe direção adicional de você, ela se defende e se preserva o melhor que pode. Você pode usar sua ação para assumir controle total e preciso do alvo. Até o final do seu próximo turno, a criatura realiza apenas as ações que você escolhe e não faz nada que você não permita. Durante este tempo, você também pode fazer a criatura usar uma reação, mas isso requer que você também use sua própria reação. Cada vez que o alvo recebe dano, ele faz um novo teste de resistência de Sabedoria contra a magia. Se o teste de resistência for bem-sucedido, a magia termina.", ["Druida", "Feiticeiro"], false, true, "Quando você lança esta magia usando um espaço de magia de 9º nível, a duração é concentração, até 8 horas."),
  sp("Escudo de Fogo", 4, "Evocação", "1 ação", "Self", "10 minutos", true, true, true, "Um pouco de fósforo ou um vagalume.", "Chamas finas e vaporosas cercam seu corpo pela duração da magia, irradiando luz brilhante em um raio de 10 pés e luz fraca para 10 pés adicionais. Você pode terminar a magia usando uma ação para fazê-la desaparecer. As chamas à sua volta são um escudo de calor ou frio, sua escolha. O escudo de calor lhe concede resistência a dano de frio e o escudo de frio resistência a dano de fogo. Além disso, sempre que uma criatura dentro de 5 pés de você o acerta com um ataque corpo a corpo, chamas brotam do escudo. O atacante então sofre 2d8 de dano de fogo ou frio, dependendo do tipo.", ["Mago"], false, false, ""),
  sp("Esfera Resiliente", 4, "Evocação", "1 ação", "30 pés", "Até 1 minuto", true, true, true, "Um pedaço de cristal transparente hemisférico e um pedaço correspondente de goma arábica hemisférica.", "Uma esfera de força cintilante envolve uma criatura ou objeto de tamanho Grande ou menor dentro do alcance. Uma criatura relutante deve fazer um teste de salvação de Destreza. Se falhar na salvação, a criatura fica envolvida pela duração. Nada - não objetos físicos, energia ou outros efeitos de magia - pode passar pela barreira, nem para dentro nem para fora, embora uma criatura dentro da esfera possa respirar lá. A esfera é imune a todo dano, e uma criatura ou objeto dentro não pode ser danificado por ataques ou efeitos originários de fora, nem uma criatura dentro da esfera pode danificar nada fora dela. A esfera não tem peso e é apenas grande o suficiente para conter a criatura ou objeto dentro. Uma criatura envolvida pode usar sua ação para empurrar contra as paredes da esfera e assim rolar a esfera a até metade da velocidade da criatura. Da mesma forma, a esfera pode ser pegada e movida por outras criaturas. Uma magia desintegração direcionada à esfera a destrói sem prejudicar nada dentro dela.", ["Mago"], false, true, ""),
  sp("Fabricar", 4, "Transmutação", "10 minutos", "120 pés", "Instantâneo", true, true, false, "", "Você converte matérias-primas em produtos do mesmo material. Por exemplo, você pode fabricar uma ponte de madeira a partir de um aglomerado de árvores, uma corda a partir de um pedaço de cânhamo e roupas de linho ou lã. Escolha matérias-primas que você possa ver dentro do alcance. Você pode fabricar um objeto Grande ou menor (contido em um cubo de 10 pés, ou oito cubos de 5 pés conectados), dada uma quantidade suficiente de matéria-prima. Se você estiver trabalhando com metal, pedra ou outra substância mineral, no entanto, o objeto fabricado não pode ser maior que Médio (contido em um único cubo de 5 pés). A qualidade dos objetos feitos pela magia é compatível com a qualidade das matérias-primas. Criaturas ou itens mágicos não podem ser criados ou transmutados por esta magia. Você também não pode usá-la para criar itens que normalmente exigem um alto grau de artesanato, como joias, armas, vidro ou armadura, a menos que você tenha proficiência com o tipo de ferramentas de artesão usadas para criar tais objetos.", ["Mago"], false, false, ""),
  sp("Guardião da Fé", 4, "Conjuração", "1 ação", "30 pés", "8 horas", true, false, false, "", "Um guardião espectral Grande aparece e paira pela duração em um espaço desocupado de sua escolha que você possa ver dentro do alcance. O guardião ocupa esse espaço e é indistinto, exceto por uma espada reluzente e escudo emblazados com o símbolo de sua divindade. Qualquer criatura hostil a você que se mova para um espaço dentro de 10 pés do guardião pela primeira vez em um turno deve ter sucesso em um teste de resistência de Destreza. A criatura sofre 20 de dano radiante em um teste falhado, ou metade do dano em um bem-sucedido. O guardião desaparece quando tiver causado um total de 60 de dano.", ["Clérico", "Paladino"], false, false, ""),
  sp("Inseto Gigante", 4, "Transmutação", "1 ação", "30 pés", "Até 10 minutos", true, true, false, "", "Você transforma até dez centopéias, três aranhas, cinco vespas ou um escorpião dentro do alcance em versões gigantes de suas formas naturais pela duração. Uma centopéia se torna uma centopéia gigante, uma aranha se torna uma aranha gigante, uma vespa se torna uma vespa gigante e um escorpião se torna um escorpião gigante. Cada criatura obedece seus comandos verbais e, em combate, agem em seu turno a cada rodada. O Mestre tem as estatísticas dessas criaturas e resolve suas ações e movimento. Uma criatura permanece em seu tamanho gigante pela duração, até cair para 0 pontos de vida ou até você usar uma ação para dispensar o efeito sobre ela. O Mestre pode permitir que você escolha alvos diferentes. Por exemplo, se você transformar uma abelha, sua versão gigante poderia ter as mesmas estatísticas de uma vespa gigante.", ["Druida"], false, true, ""),
  sp("Invisibilidade Aprimorada", 4, "Ilusão", "1 ação", "Toque", "Até 1 minuto", true, true, false, "", "Você ou uma criatura que você toca se torna invisível até a magia terminar. Qualquer coisa que o alvo esteja vestindo ou carregando é invisível enquanto estiver na pessoa do alvo.", ["Bardo", "Feiticeiro", "Mago"], false, true, ""),
  sp("Liberdade de Movimento", 4, "Abjuração", "1 ação", "Toque", "1 hora", true, true, true, "Uma correia de couro, amarrada ao braço ou membro similar.", "Você toca uma criatura disposta. Pela duração, o movimento do alvo não é afetado por terreno difícil, e magias e outros efeitos mágicos não conseguem reduzir a velocidade do alvo nem o causam ser paralisado ou restringido. O alvo também pode gastar 5 pés de movimento para escapar automaticamente de contenções não-mágicas, como algemas ou de uma criatura que o está agarrando. Finalmente, estar debaixo d\\'água não impõe penalidades no movimento ou ataques do alvo.", ["Bardo", "Clérico", "Druida", "Patrulheiro"], false, false, ""),
  sp("Localizar Criatura", 4, "Adivinhação", "1 ação", "Pessoal", "Até 1 hora", true, true, true, "Um pouco de pelo de um sabujo.", "Descreva ou nomeie uma criatura que lhe é familiar. Você sente a direção da localização da criatura, enquanto essa criatura estiver a até 300 metros de você. Se a criatura estiver se movendo, você saberá a direção de seu movimento. A magia pode localizar uma criatura específica conhecida por você, ou a criatura mais próxima de um tipo específico (como um humano ou um unicórnio), contanto que você tenha visto tal criatura de perto (a até 9 metros) pelo menos uma vez. Se a criatura que você descreveu ou nomeou estiver em uma forma diferente, como sob os efeitos de uma magia polimorfismo, essa magia não localiza a criatura. Essa magia não pode localizar uma criatura se água corrente com pelo menos 3 metros de largura bloqueia um caminho direto entre você e a criatura.", ["Bardo", "Clérico", "Druida", "Paladino", "Patrulheiro", "Mago"], false, true, ""),
  sp("Moldar Pedra", 4, "Transmutação", "1 ação", "Toque", "Instantâneo", true, true, true, "Argila macia, para ser trabalhada grosseiramente na forma desejada para o objeto de pedra.", "Você toca um objeto de pedra de tamanho Médio ou menor ou uma seção de pedra com não mais de 5 pés em qualquer dimensão e a forma em qualquer forma que sirva ao seu propósito. Assim, por exemplo, você poderia moldar uma rocha grande em uma arma, ídolo ou cofre, ou fazer uma pequena passagem através de uma parede, contanto que a parede tenha menos de 5 pés de espessura. Você também pode moldar uma porta de pedra ou seu marco para selar a porta fechada. O objeto que você cria pode ter até duas dobradiças e um trinco, mas detalhes mecânicos mais finos não são possíveis.", ["Clérico", "Druida", "Mago"], false, false, ""),
  sp("Muro de Fogo", 4, "Evocação", "1 ação", "120 pés", "Até 1 minuto", true, true, true, "Um pequeno pedaço de fósforo.", "Você cria um muro de fogo em uma superfície sólida ao alcance. Você pode fazer o muro ter até 60 pés de comprimento, 20 pés de altura e 1 pé de espessura, ou um muro em anel até 20 pés de diâmetro, 20 pés de altura e 1 pé de espessura. O muro é opaco e dura pela duração. Quando o muro aparece, cada criatura dentro de sua área deve fazer um teste de Destreza. Em uma falha, uma criatura recebe 5d8 de dano de fogo, ou metade desse dano em um sucesso. Um lado do muro, escolhido por você quando você lança este feitiço, causa 5d8 de dano de fogo para cada criatura que termina seu turno dentro de 10 pés desse lado ou dentro do muro. Uma criatura recebe o mesmo dano quando entra no muro pela primeira vez em um turno ou termina seu turno lá. O outro lado do muro não causa dano.", ["Druida", "Feiticeiro", "Mago"], false, true, "Quando você lança este feitiço usando um espaço de feitiço de 5º nível ou superior, o dano do feitiço aumenta em 1d8 para cada nível de espaço acima do 4º."),
  sp("Olho Arcano", 4, "Adivinhação", "1 ação", "9 metros", "Até 1 hora", true, true, true, "Um pouco de pelo de morcego.", "Você cria um olho mágico invisível dentro do alcance que flutua no ar pela duração. Você recebe mentalmente informações visuais do olho, que tem visão normal e visão no escuro até 9 metros. O olho pode olhar em todas as direções. Como uma ação, você pode mover o olho até 9 metros em qualquer direção. Não há limite para o quão longe de você o olho pode se mover, mas ele não pode entrar em outro plano de existência. Uma barreira sólida bloqueia o movimento do olho, mas o olho pode passar por uma abertura tão pequena quanto 2,5 centímetros de diâmetro.", ["Clérico", "Mago"], false, true, ""),
  sp("Pele de Pedra", 4, "Abjuração", "1 ação", "Toque", "Até 1 hora", true, true, true, "Pó de diamante no valor de 100 po, que o feitiço consome.", "Este feitiço transforma a carne de uma criatura disposta que você toca tão dura quanto pedra. Até o feitiço terminar, o alvo tem resistência a dano de concussão, perfuração e corte não-mágico.", ["Druida", "Patrulheiro", "Feiticeiro", "Mago"], false, true, ""),
  sp("Polimorfismo", 4, "Transmutação", "1 ação", "60 pés", "Até 1 hora", true, true, true, "Um casulo de lagarta.", "Esta magia transforma uma criatura que você pode ver dentro do alcance em uma nova forma. Uma criatura relutante deve fazer um teste de resistência de sabedoria para evitar o efeito. Um metamorfo obtém sucesso automaticamente neste teste de resistência. A transformação dura pela duração, ou até o alvo cair para 0 pontos de vida ou morrer. A nova forma pode ser qualquer besta cuja classificação de desafio seja igual ou menor que a do alvo (ou o nível do alvo, se não tiver uma classificação de desafio). As estatísticas do jogo do alvo, incluindo os modificadores de habilidade mentais, são substituídas pelas estatísticas da besta escolhida. Ele retém seu alinhamento e personalidade. O alvo assume os pontos de vida de sua nova forma. Quando ele reverte para sua forma normal, a criatura retorna ao número de pontos de vida que tinha antes de se transformar. Se reverterse como resultado de cair a 0 pontos de vida, qualquer dano excedente é transferido para sua forma normal. Desde que o dano excedente não reduza a forma normal da criatura para 0 pontos de vida, ela não é derrubada inconsciente. A criatura é limitada pelas ações que pode realizar pela natureza de sua nova forma, e não pode falar, lançar magias ou realizar qualquer outra ação que exija mãos ou fala. O equipamento do alvo se funde na nova forma. A criatura não pode ativar, usar, empunhar ou se beneficiar de forma alguma de nenhum de seus equipamentos.", ["Bardo", "Druida", "Feiticeiro", "Mago"], false, true, ""),
  sp("Porta Dimensional", 4, "Conjuração", "1 ação", "500 pés", "Instantâneo", true, false, false, "", "Você se teletransporta de sua localização atual para qualquer outro local dentro do alcance. Você chega exatamente no local desejado. Pode ser um local que você pode ver, um que você pode visualizar, ou um que você possa descrever declarando distância e direção, como \"200 pés diretamente para baixo\" ou \"para cima noroeste em um ângulo de 45 graus, 300 pés.\" Você pode trazer objetos desde que seu peso não exceda o que você pode carregar. Você também pode trazer uma criatura disposta de seu tamanho ou menor que está carregando equipamento até sua capacidade de carregamento. A criatura deve estar a 5 pés de você quando lança esta magia. Se chegasse a um local já ocupado por um objeto ou uma criatura, você e qualquer criatura viajando com você sofrem 4d6 de dano de força cada, e a magia falha em teleportá-lo.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Praga", 4, "Necromancia", "1 ação", "30 pés", "Instantâneo", true, true, false, "", "Energia necromântica envolve uma criatura de sua escolha que você pode ver dentro do alcance, drenando umidade e vitalidade dela. O alvo deve fazer um teste de constituição. O alvo sofre 8d8 de dano necrótico em uma falha, ou metade do dano em um sucesso. A magia não tem efeito em mortos-vivos ou constructos. Se você designar uma criatura vegetal ou uma planta mágica, ela faz o teste de resistência com desvantagem, e a magia causa dano máximo a ela. Se você designar uma planta não mágica que não é uma criatura, como uma árvore ou arbusto, ela não faz um teste de resistência; ela simplesmente murcha e morre.", ["Druida", "Feiticeiro", "Bruxo", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 5º nível ou superior, o dano aumenta em 1d8 para cada nível de espaço acima do 4º."),
  sp("Proteção Contra a Morte", 4, "Abjuração", "1 ação", "Toque", "8 horas", true, true, false, "", "Você toca uma criatura e lhe concede uma medida de proteção contra a morte. Na primeira vez que o alvo cairia a 0 pontos de vida como resultado de receber dano, o alvo em vez disso cai a 1 ponto de vida, e o feitiço termina. Se o feitiço ainda estiver em efeito quando o alvo for submetido a um efeito que o mataria instantaneamente sem causar dano, esse efeito é instead negado contra o alvo, e o feitiço termina.", ["Clérico", "Paladino"], false, false, ""),
  sp("Santuário Privado", 4, "Abjuração", "10 minutos", "120 pés", "24 horas", true, true, true, "Uma fina lâmina de chumbo, um pedaço de vidro opaco, um aglomerado de algodão ou tecido e crisólita em pó.", "Você torna uma área ao alcance magicamente segura. A área é um cubo que pode ser tão pequeno quanto 5 pés ou tão grande quanto 100 pés em cada lado. A magia dura pela duração ou até que você use uma ação para dissipá-la. Quando você conjura a magia, você decide que tipo de segurança a magia fornece, escolhendo qualquer ou todas as seguintes propriedades: - O som não pode passar através da barreira na borda da área protegida. - A barreira da área protegida aparece escura e nebulosa, impedindo a visão (incluindo visão no escuro) através dela. - Sensores criados por magias de adivinhação não podem aparecer dentro da área protegida ou passar através da barreira em seu perímetro. - Criaturas na área não podem ser alvo de magias de adivinhação. - Nada pode se teletransportar para dentro ou para fora da área protegida. - Viagem planar é bloqueada dentro da área protegida. Conjurar esta magia no mesmo local todos os dias por um ano torna este efeito permanente.", ["Mago"], false, false, "Quando você conjura esta magia usando um espaço de magia de 5º nível ou superior, você pode aumentar o tamanho do cubo em 100 pés para cada nível de espaço além do 4º. Assim você poderia proteger um cubo de até 200 pés em um lado usando um espaço de magia de 5º nível."),
  sp("Tempestade de Gelo", 4, "Evocação", "1 ação", "300 pés", "Instantâneo", true, true, true, "Uma pitada de pó e algumas gotas de água.", "Uma chuva de gelo duro bate no chão em um cilindro de 20 pés de raio e 40 pés de altura centrado em um ponto ao alcance. Cada criatura no cilindro deve fazer um teste de salvação de Destreza. Uma criatura sofre 2d8 de dano de concussão e 4d6 de dano de frio em um teste falhado, ou metade do dano em um teste bem-sucedido. As pedras de gelo transformam a área de efeito da tempestade em terreno difícil até o final de seu próximo turno.", ["Druida", "Feiticeiro", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 5º nível ou superior, o dano de concussão aumenta em 1d8 para cada nível de espaço acima do 4º."),
  sp("Tentáculos Negros", 4, "Conjuração", "1 ação", "90 pés", "Até 1 minuto", true, true, true, "Um pedaço de tentáculo de um polvo gigante ou uma lula gigante", "Tentáculos retorcidos de ébano preenchem um quadrado de 20 pés no solo que você pode ver dentro do alcance. Pela duração, esses tentáculos transformam o solo na área em terreno difícil. Quando uma criatura entra na área afetada pela primeira vez em um turno ou começa seu turno lá, a criatura deve fazer um teste de destreza ou sofrer 3d6 de dano de impacto e ser agarrada pelos tentáculos até a magia terminar. Uma criatura que começa seu turno na área e já está agarrada pelos tentáculos sofre 3d6 de dano de impacto. Uma criatura agarrada pelos tentáculos pode usar sua ação para fazer um teste de força ou destreza (à sua escolha) contra seu CD de teste de resistência de magia. Se conseguir, ela se liberta.", ["Mago"], false, true, ""),
  sp("Terreno Alucinatório", 4, "Ilusão", "10 minutos", "300 pés", "24 horas", true, true, true, "Uma pedra, um galho e um pouco de planta verde.", "Você faz o terreno natural em um cubo de 150 pés ao alcance parecer, soar e cheirar como algum outro tipo de terreno natural. Assim, campos abertos ou uma estrada podem ser feitos para se parecerem com um pântano, colina, fenda, ou algum outro terreno difícil ou intransponível. Uma lagoa pode parecer um prado gramado, um precipício como uma encosta suave, ou um vale rochoso como uma estrada ampla e lisa. Estruturas manufaturadas, equipamentos e criaturas dentro da área não são alteradas em aparência. As características táteis do terreno não são alteradas, então criaturas entrando na área provavelmente verão através da ilusão. Se a diferença não for óbvia ao toque, uma criatura examinando cuidadosamente a ilusão pode tentar um teste de Inteligência (Investigação) contra seu CD de teste de resistência de magia para desacreditá-la. Uma criatura que discerne a ilusão pelo que é, a vê como uma imagem vaga sobreposta no terreno.", ["Bardo", "Druida", "Bruxo", "Mago"], false, false, ""),
  sp("Afastar o Mal e o Bem", 5, "Abjuração", "1 ação", "Pessoal", "Até 1 minuto", true, true, true, "Água benta ou prata e ferro em pó.", "Energia cintilante o envolve e o protege de feéricos, mortos-vivos e criaturas originárias de além do Plano Material. Pela duração, celestiais, elementais, feéricos, diabos e mortos-vivos têm desvantagem em testes de ataque contra você. Você pode terminar a magia antecipadamente usando uma das seguintes funções especiais. Quebrar Encantamento. Como sua ação, você toca uma criatura que você possa alcançar que esteja enfeitiçada, assustada ou possuída por um celestial, um elemental, um feérico, um diabo ou um morto-vivo. A criatura que você toca não está mais enfeitiçada, assustada ou possuída por tais criaturas. Despedida. Como sua ação, você faz um teste de ataque de magia de corpo a corpo contra um celestial, um elemental, um feérico, um diabo ou um morto-vivo que você possa alcançar. Se acertar, você tenta impulsionar a criatura de volta para seu plano de origem. A criatura deve ser bem-sucedida em um teste de resistência de Carisma ou ser enviada de volta para seu plano de origem (se já não estiver lá). Se não estiverem em seu plano de origem, mortos-vivos são enviados para a Penumbra, e feéricos são enviados para o Reino Feérico.", ["Clérico", "Paladino"], false, true, ""),
  sp("Animar Objetos", 5, "Transmutação", "1 ação", "36 metros", "Até 1 minuto", true, true, false, "", "Objetos ganham vida aos seus comandos. Escolha até dez objetos não mágicos dentro do alcance que não estejam sendo usados ou carregados. Alvos Médios contam como dois objetos, alvos Grandes contam como quatro objetos, alvos Imensos contam como oito objetos. Você não pode animar nenhum objeto maior que Imenso. Cada alvo se anima e se torna uma criatura sob seu controle até que a magia termine ou até ser reduzido a 0 pontos de vida. Como uma ação bônus, você pode comandar mentalmente qualquer criatura que você criou com esta magia se a criatura estiver dentro de 150 metros de você (se você controlar múltiplas criaturas, você pode comandar qualquer ou todas elas ao mesmo tempo, emitindo o mesmo comando para cada uma). Você decide qual ação a criatura realizará e para onde se moverá durante seu próximo turno, ou pode emitir um comando geral, como guardar uma câmara ou corredor específico. Se você não emitir nenhum comando, a criatura apenas se defende contra criaturas hostis. Uma vez recebida uma ordem, a criatura continua a segui-la até que sua tarefa seja concluída. Um objeto animado é um constructo com CA, pontos de vida, ataques, Força e Destreza determinados por seu tamanho. Sua Constituição é 10 e sua Inteligência e Sabedoria são 3, e seu Carisma é 1. Sua velocidade é 9 metros; se o objeto não tem pernas ou outros apêndices que possa usar para locomoção, tem uma velocidade de voo de 9 metros e pode pairar. Se o objeto está fixado com segurança a uma superfície ou um objeto maior, como uma corrente presa a uma parede, sua velocidade é 0. Ele tem visão no escuro com um raio de 9 metros e é cego além dessa distância. Quando o objeto animado cai a 0 pontos de vida, ele reverte para sua forma de objeto original, e qualquer dano restante se transfere para sua forma de objeto original. Se você comandar um objeto a atacar, ele pode fazer um único ataque corpo a corpo contra uma criatura dentro de 1,5 metro dele. Ele faz um ataque de pancada com um bônus de ataque e dano contundente determinado por seu tamanho. O Mestre pode determinar que um objeto específico causa dano cortante ou perfurante baseado em sua forma.", ["Bardo", "Feiticeiro", "Mago"], false, true, "Se você lançar esta magia usando um espaço de magia de 6º nível ou superior, você pode animar dois objetos adicionais para cada nível de espaço acima do 5º."),
  sp("Aparência Ilusória", 5, "Ilusão", "1 ação", "9 metros", "8 horas", true, true, false, "", "Este feitiço permite que você mude a aparência de qualquer número de criaturas que possa ver no alcance. Você dá a cada alvo que escolher uma nova aparência ilusória. Um alvo relutante pode fazer um teste de resistência de Carisma e, se tiver sucesso, não será afetado por este feitiço. O feitiço disfarça a aparência física bem como roupas, armadura, armas e equipamento. Você pode fazer cada criatura parecer 30 centímetros mais curta ou alta e parecer fina, gorda ou em meio-termo. Você não pode mudar o tipo de corpo de um alvo, então deve escolher uma forma que tenha o mesmo arranjo básico de membros. Caso contrário, a extensão da ilusão depende de você. O feitiço dura pela duração, a menos que você use sua ação para dispensá-lo mais cedo. As mudanças causadas por este feitiço não resistem à inspeção física. Por exemplo, se você usar este feitiço para adicionar um chapéu ao traje de uma criatura, objetos passam através do chapéu e qualquer um que o toque não sentiria nada ou sentiria a cabeça e os cabelos da criatura. Se você usar este feitiço para parecer mais fino do que é, a mão de alguém que estendesse para tocá-lo bateria em você enquanto parecia ainda estar no ar. Uma criatura pode usar sua ação para inspecionar um alvo e fazer um teste de Inteligência (Investigação) contra seu CD de teste de resistência de feitiço. Se tiver sucesso, fica ciente de que o alvo está disfarçado.", ["Bardo", "Feiticeiro", "Mago"], false, false, ""),
  sp("Barreira Antivida", 5, "Abjuração", "1 ação", "Pessoal", "Até 1 hora", true, true, false, "", "Uma barreira brilhante se estende a partir de você em um raio de 3 metros e se move com você, permanecendo centrada em você e excluindo criaturas que não sejam mortos-vivos e constructos. A barreira dura pela duração. A barreira impede que uma criatura afetada passe ou alcance através dela. Uma criatura afetada pode lançar magias ou fazer ataques com armas de alcance ou longo alcance através da barreira. Se você se mover de forma que uma criatura afetada seja forçada a passar pela barreira, a magia termina.", ["Druida"], false, true, ""),
  sp("Círculo de Teleportação", 5, "Conjuração", "1 minuto", "3 metros", "1 rodada", true, false, true, "Gizes e tintas raras infundidas com gemas preciosas no valor de 50 po, que o feitiço consome.", "Conforme você lança o feitiço, desenha um círculo de 3 metros de diâmetro no chão inscrito com símbolos que ligam sua localização a um círculo de teleportação permanente de sua escolha cuja sequência de símbolos você conhece e que está no mesmo plano de existência que você. Um portal cintilante se abre dentro do círculo que você desenhou e permanece aberto até o final do seu próximo turno. Qualquer criatura que entre no portal aparece instantaneamente a 1,5 metros do círculo de destino ou no espaço desocupado mais próximo se esse espaço estiver ocupado. Muitos templos principais, guildas e outros lugares importantes têm círculos de teleportação permanentes inscritos em algum lugar dentro de seus confins. Cada círculo inclui uma sequência de símbolos única - uma sequência de runas mágicas arranjadas em um padrão particular. Quando você ganha a capacidade de lançar este feitiço, você aprende as sequências de símbolos para dois destinos no Plano Material, determinados pelo mestre. Você pode aprender sequências de símbolos adicionais durante suas aventuras. Você pode comprometer uma nova sequência de símbolos à memória depois de estudá-la por 1 minuto. Você pode criar um círculo de teleportação permanente lançando este feitiço no mesmo local todos os dias por um ano. Você não precisa usar o círculo para se teleportar quando lança o feitiço desta forma.", ["Bardo", "Feiticeiro", "Mago"], false, false, ""),
  sp("Comunhão", 5, "Adivinhação", "1 minuto", "Self", "1 minuto", true, true, true, "Incenso e um frasco de água sagrada ou profana.", "Você entra em contato com sua deidade ou um proxy divino e faz até três perguntas que podem ser respondidas com sim ou não. Você deve fazer suas perguntas antes da magia terminar. Você recebe uma resposta correta para cada pergunta. Seres divinos não são necessariamente oniscientes, então você pode receber \"pouco claro\" como resposta se uma pergunta disser respeito a informações que estão além do conhecimento da deidade. Em um caso onde uma resposta de uma palavra poderia ser enganosa ou contrária aos interesses da deidade, o Mestre pode oferecer uma frase curta como resposta em vez disso. Se você lançar a magia duas ou mais vezes antes de terminar seu próximo repouso longo, há uma chance cumulativa de 25 por cento para cada lançamento após o primeiro de que você não receba resposta. O Mestre faz esta rolagem em segredo.", ["Clérico"], true, false, ""),
  sp("Comunhão com a Natureza", 5, "Adivinhação", "1 minuto", "Self", "Instantâneo", true, true, false, "", "Você se torna brevemente um com a natureza e ganha conhecimento do território circundante. Ao ar livre, a magia lhe dá conhecimento da terra dentro de 3 milhas de você. Em cavernas e outras configurações naturais subterrâneas, o raio é limitado a 300 pés. A magia não funciona onde a natureza foi substituída por construção, como em masmorras e cidades. Você obtém instantaneamente conhecimento de até três fatos à sua escolha sobre qualquer um dos seguintes assuntos conforme se relacionam com a área: - terreno e corpos de água - plantas prevalentes, minerais, animais ou povos - celestiais poderosos, feéricos, demônios, elementais ou mortos-vivos - influência de outros planos de existência - edifícios Por exemplo, você poderia determinar a localização de mortos-vivos poderosos na área, a localização de principais fontes de água potável segura, e a localização de qualquer cidade próxima.", ["Druida", "Patrulheiro"], true, false, ""),
  sp("Cone de Frio", 5, "Evocação", "1 ação", "Pessoal", "Instantâneo", true, true, true, "Um pequeno cristal ou cone de vidro", "Uma explosão de ar frio irrompe de suas mãos. Cada criatura em um cone de 18 metros deve fazer um teste de resistência de Constituição. Uma criatura sofre 8d8 de dano de frio se falhar no teste, ou sofre metade do dano se obtiver sucesso. Uma criatura morta por esta magia se torna uma estátua congelada até que desconge.", ["Feiticeiro", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 6º nível ou superior, o dano aumenta em 1d8 para cada nível de espaço acima do 5º."),
  sp("Conhecimento Lendário", 5, "Adivinhação", "10 minutos", "Pessoal", "Instantâneo", true, true, true, "Incenso no valor de 250 polegadas que o destino consome e quatro varas de marfim no valor de 50 po cada.", "Nomeie ou descreva uma pessoa, lugar ou objeto. O feitiço traz à sua mente um breve resumo da tradição significativa sobre a coisa que você nomeou. A tradição pode consistir em contos atuais, histórias esquecidas ou até mesmo tradição secreta que nunca foi amplamente conhecida. Se a coisa que você nomeou não é de importância lendária, você não ganha informação. Quanto mais informação você já tem sobre a coisa, mais precisa e detalhada é a informação que você recebe. A informação que você aprende é precisa, mas pode estar revestida em linguagem figurada. Por exemplo, se você tiver uma machada mágica misteriosa à mão, o feitiço pode fornecer esta informação: \"Ai daquele maldoso cuja mão toca a machada, pois mesmo a haste corta a mão dos maus. Apenas uma verdadeira Criança da Pedra, amante e amada de Moradin, pode despertar os verdadeiros poderes da machada, e apenas com a palavra sagrada Rudnogg nos lábios.\"", ["Bardo", "Clérico", "Mago"], false, false, ""),
  sp("Consagração", 5, "Evocação", "24 horas", "Toque", "Até ser dissipado", true, true, true, "Ervas, óleos e incenso no valor de pelo menos 1.000 po, que a magia consome.", "Você toca um ponto e impregna uma área ao seu redor com poder sagrado (ou profano). A área pode ter um raio de até 60 pés, e a magia falha se o raio incluir uma área já sob o efeito de uma magia de Consagração. A área afetada está sujeita aos seguintes efeitos. Primeiro, celestiais, elementais, fey, fiends e mortos-vivos não podem entrar na área, nem tais criaturas podem enfeitiçar, assustar ou possuir criaturas dentro dela. Qualquer criatura enfeitiçada, assustada ou possuída por tal criatura não é mais enfeitiçada, assustada ou possuída ao entrar na área. Você pode excluir um ou mais desses tipos de criaturas deste efeito. Segundo, você pode vincular um efeito adicional à área. Escolha o efeito da seguinte lista, ou escolha um efeito oferecido pelo Mestre. Alguns desses efeitos se aplicam a criaturas na área; você pode designar se o efeito se aplica a todas as criaturas, criaturas que seguem uma deidade ou líder específico, ou criaturas de um tipo específico, como orcs ou trolls. Quando uma criatura que seria afetada entra na área da magia pela primeira vez em um turno ou começa seu turno ali, ela pode fazer um teste de resistência de Carisma. Com sucesso, a criatura ignora o efeito adicional até sair da área. Coragem: Criaturas afetadas não podem ser assustadas enquanto na área. Escuridão: A escuridão preenche a área. Luz normal, bem como luz mágica criada por magias de nível inferior ao espaço usado para lançar esta magia, não pode iluminar a área. Luz do Dia: Luz brilhante preenche a área. Escuridão mágica criada por magias de nível inferior ao espaço usado para lançar esta magia não pode extinguir a luz. Proteção de Energia: Criaturas afetadas na área têm resistência a um tipo de dano de sua escolha, exceto para dano de esmagamento, perfuração ou corte. Vulnerabilidade de Energia: Criaturas afetadas na área têm vulnerabilidade a um tipo de dano de sua escolha, exceto para dano de esmagamento, perfuração ou corte. Descanso Eterno: Corpos mortos enterrados na área não podem ser transformados em mortos-vivos. Interferência Extradimensional: Criaturas afetadas não podem se mover ou viajar usando teleportação ou por meios extradimensionais ou interplanares. Medo: Criaturas afetadas são assustadas enquanto na área. Silêncio: Nenhum som pode emanar de dentro da área, e nenhum som pode alcançá-la. Línguas: Criaturas afetadas podem se comunicar com qualquer outra criatura na área, mesmo que não compartilhem uma língua comum.", ["Clérico"], false, false, ""),
  sp("Contactar Outro Plano", 5, "Adivinhação", "1 minuto", "Você", "1 minuto", true, false, false, "", "Você faz contato mental com um semideus, o espírito de um sábio há muito morto, ou alguma outra entidade misteriosa de outro plano. Contactar essa inteligência extraplanar pode prejudicar ou até quebrar sua mente. Quando você lança esta magia, faça um teste de resistência de Inteligência CD 15. Em uma falha, você recebe 6d6 de dano psíquico e fica insano até terminar um repouso longo. Enquanto insano, você não pode tomar ações, não consegue entender o que outras criaturas dizem, não consegue ler e fala apenas em gibberish. Uma magia de restauração maior lançada em você encerra esse efeito. Em um sucesso, você pode fazer à entidade até cinco perguntas. Você deve fazer suas perguntas antes da magia terminar. O mestre responde cada pergunta com uma palavra, tal como \"sim\", \"não\", \"talvez\", \"nunca\", \"irrelevante\" ou \"pouco claro\" (se a entidade não souber a resposta da pergunta). Se uma resposta de uma palavra seria enganosa, o mestre pode oferecer uma frase curta como resposta.", ["Bruxo", "Mago"], true, false, ""),
  sp("Contágio", 5, "Necromancia", "1 ação", "Toque", "7 dias", true, true, false, "", "Seu toque transmite doença. Faça um ataque de magia corpo a corpo contra uma criatura dentro de seu alcance. Se acertar, você aflige a criatura com uma doença de sua escolha de qualquer uma das descritas abaixo. No final de cada um dos turnos do alvo, ele deve fazer um teste de resistência de Constituição. Depois de falhar em três desses testes de resistência, os efeitos da doença duram pela duração, e a criatura para de fazer esses testes. Depois de suceder em três desses testes de resistência, a criatura se recupera da doença, e a magia termina. Uma vez que essa magia induz uma doença natural em seu alvo, qualquer efeito que remova uma doença ou de outra forma mitigue os efeitos de uma doença se aplica a ela. Cegueira por Doença. A dor agarra a mente da criatura, e seus olhos ficam branco leitoso. A criatura tem desvantagem em testes de Sabedoria e testes de resistência de Sabedoria e está cega. Febre Infecciosa. Uma febre ardente varre o corpo da criatura. A criatura tem desvantagem em testes de Força, testes de resistência de Força e jogadas de ataque que usam Força. Podridão Carnal. A carne da criatura apodrece. A criatura tem desvantagem em testes de Carisma e vulnerabilidade a todos os danos. Fogo Mental. A mente da criatura fica febril. A criatura tem desvantagem em testes de Inteligência e testes de resistência de Inteligência, e a criatura se comporta como se estivesse sob os efeitos da magia confusão durante o combate. Convulsão. A criatura é tomada por tremores. A criatura tem desvantagem em testes de Destreza, testes de resistência de Destreza e jogadas de ataque que usam Destreza. Perdição Viscosa. A criatura começa a sangrar descontroladamente. A criatura tem desvantagem em testes de Constituição e testes de resistência de Constituição. Além disso, sempre que a criatura sofre dano, ela fica atordoada até o final de seu próximo turno.", ["Clérico", "Druida"], false, false, ""),
  sp("Convocar Elemental", 5, "Conjuração", "1 minuto", "27 metros", "Até 1 hora", true, true, true, "Incenso queimando para ar, barro macio para terra, enxofre e fósforo para fogo, ou água e areia para água.", "Você convoca um servo elemental. Escolha uma área de ar, terra, fogo ou água que preencha um cubo de 3 metros dentro do alcance. Um elemental com classificação de desafio 5 ou menor apropriado à área escolhida aparece em um espaço desocupado dentro de 3 metros dela. Por exemplo, um elemental do fogo emerge de uma fogueira, e um elemental da terra sobe do chão. O elemental desaparece quando seus pontos de vida chegam a 0 ou quando a magia termina. O elemental é amigável com você e seus companheiros durante a duração. Role iniciativa para o elemental, que tem seus próprios turnos. Ele obedece a qualquer comando verbal que você lhe der (nenhuma ação necessária de sua parte). Se você não der nenhum comando ao elemental, ele se defende de criaturas hostis, mas caso contrário não toma ações. Se sua concentração for quebrada, o elemental não desaparece. Em vez disso, você perde o controle do elemental, ele se torna hostil com você e seus companheiros, e pode atacar. Um elemental descontrolado não pode ser dispensado por você, e desaparece 1 hora depois que você o convocou. O mestre tem as estatísticas do elemental.", ["Druida", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 6º nível ou superior, a classificação de desafio aumenta em 1 para cada nível de espaço acima do 5º."),
  sp("Criação", 5, "Ilusão", "1 minuto", "30 pés", "Especial", true, true, true, "Um pequeno pedaço de matéria do mesmo tipo do item que você planeja criar.", "Você puxa wisps de material de sombra do Shadowfell para criar um objeto não-vivo de matéria vegetal ao alcance: bens macios, corda, madeira, ou algo similar. Você também pode usar este feitiço para criar objetos minerais como pedra, cristal, ou metal. O objeto criado não deve ser maior que um cubo de 5 pés, e o objeto deve ser de uma forma e material que você já viu antes. A duração depende do material do objeto. Se o objeto é composto de múltiplos materiais, use a duração mais curta. Matéria vegetal 1 dia Pedra ou cristal 12 horas Metais preciosos 1 hora Gemas 10 minutos Adamantina ou mitral 1 minuto Usar qualquer material criado por este feitiço como componente material de outro feitiço faz aquele feitiço falhar.", ["Feiticeiro", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 6º nível ou superior, o cubo aumenta em 5 pés para cada nível de espaço acima do 5º."),
  sp("Cura em Massa", 5, "Conjuração", "1 ação", "60 pés", "Instantâneo", true, true, false, "", "Uma onda de energia curativa emana de um ponto de sua escolha ao alcance. Escolha até seis criaturas em uma esfera de raio de 30 pés centrada naquele ponto. Cada alvo recupera pontos de vida iguais a 3d8 + seu modificador de capacidade de lançamento de magia. Essa magia não tem efeito em mortos-vivos ou construtos.", ["Bardo", "Clérico", "Druida"], false, false, "Quando você lança essa magia usando um espaço de magia de 6º nível ou superior, a cura aumenta em 1d8 para cada nível de espaço acima do 5º."),
  sp("Despertar", 5, "Transmutação", "8 horas", "Toque", "Instantâneo", true, true, true, "Uma ágata no valor de pelo menos 1.000 po, que a magia consome.", "Após gastar o tempo de lançamento traçando caminhos mágicos dentro de uma gema preciosa, você toca uma besta ou planta de tamanho Imenso ou menor. O alvo deve ter uma pontuação de Inteligência nenhuma ou uma Inteligência de 3 ou menos. O alvo ganha uma Inteligência de 10. O alvo também ganha a capacidade de falar um idioma que você conhece. Se o alvo é uma planta, ela ganha a capacidade de mover seus membros, raízes, vinhas, trepadeiras e assim por diante, e ganha sentidos semelhantes aos de um humano. Seu mestre escolhe as estatísticas apropriadas para a planta despertada, como as estatísticas para o arbusto despertado ou a árvore despertada. A besta ou planta despertada é enfeitiçada por você por 30 dias ou até que você ou seus companheiros façam algo prejudicial a ela. Quando a condição enfeitiçada termina, a criatura despertada escolhe se continua amistosa com você, baseando-se em como você a tratou enquanto estava enfeitiçada.", ["Bardo", "Druida"], false, false, ""),
  sp("Dominar Pessoa", 5, "Encantamento", "1 ação", "60 pés", "Até 1 minuto", true, true, false, "", "Você tenta enganar um humanoide que você possa ver dentro do alcance. Ele deve fazer um teste de salvação de Sabedoria ou ser enfeitiçado por você pela duração. Se você ou criaturas que lhe são amigáveis estiverem lutando contra ele, ele terá vantagem no teste de salvação. Enquanto o alvo estiver enfeitiçado, você terá um vínculo telepático com ele desde que vocês dois estejam no mesmo plano de existência. Você pode usar este vínculo telepático para dar comandos à criatura enquanto estiver consciente (nenhuma ação necessária), que ela faz o melhor para obedecer. Você pode especificar um curso de ação simples e geral, como \"Ataque aquela criatura\", \"Corra para lá\" ou \"Traga aquele objeto\". Se a criatura completar a ordem e não receber mais orientações suas, ela se defende e se preserva da melhor forma possível. Você pode usar sua ação para assumir o controle total e preciso do alvo. Até o final do seu próximo turno, a criatura realiza apenas as ações que você escolher e não faz nada que você não permita. Durante este tempo, você também pode fazer a criatura usar uma reação, mas isso exige que você também use sua própria reação. Cada vez que o alvo recebe dano, ele faz um novo teste de salvação de Sabedoria contra a magia. Se o teste de salvação for bem-sucedido, a magia acaba.", ["Bardo", "Feiticeiro", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 6º nível, a duração é concentração, até 10 minutos. Quando você usa um espaço de magia de 7º nível, a duração é concentração, até 1 hora. Quando você usa um espaço de magia de 8º nível ou superior, a duração é concentração, até 8 horas."),
  sp("Enganar", 5, "Ilusão", "1 ação", "Pessoal", "Até 1 hora", false, true, false, "", "Você se torna invisível ao mesmo tempo que um duplo ilusório de você aparece onde você estava em pé. O duplo dura pela duração, mas a invisibilidade termina se você atacar ou lançar um feitiço. Você pode usar sua ação para mover seu duplo ilusório até duas vezes sua velocidade e fazê-lo fazer gestos, falar e se comportar da maneira que escolher. Você pode ver através de seus olhos e ouvir através de seus ouvidos como se estivesse localizado onde ele está. Em cada um de seus turnos como uma ação bônus, você pode mudar de usar seus sentidos para usar seus próprios, ou vice-versa. Enquanto estiver usando seus sentidos, você fica cego e surdo em relação a seus arredores.", ["Bardo", "Mago"], false, true, ""),
  sp("Escrutínio", 5, "Adivinhação", "10 minutos", "Pessoal", "Até 10 minutos", true, true, true, "Um foco que custe pelo menos 1.000 po, como uma bola de cristal, um espelho de prata ou uma pia cheia de água benta.", "Você pode ver e ouvir uma criatura específica que escolher e que esteja no mesmo plano de existência que você. O alvo deve fazer um teste de resistência de Sabedoria, que é modificado por quão bem você conhece o alvo e que tipo de conexão física você tem com ele. Se um alvo sabe que você está lançando este feitiço, pode falhar no teste de resistência voluntariamente se quiser ser observado. Conhecimento & Modificador de Teste de Resistência: Oitiva (você ouviu falar sobre o alvo) +5 Encontro (você conheceu o alvo) +0 Familiar (você conhece o alvo bem) -5 Conexão & Modificador de Teste de Resistência: Semelhança ou figura -2 Posse ou vestiário -4 Parte do corpo, mecha de cabelo, fragmento de unha ou similar -10 Se o alvo conseguir no teste de resistência, ele não será afetado e você não poderá usar este feitiço contra ele novamente por 24 horas. Se falhar no teste de resistência, o feitiço cria um sensor invisível a até 3 metros do alvo. Você pode ver e ouvir através do sensor como se estivesse lá. O sensor se move com o alvo, permanecendo a até 3 metros dele pela duração. Uma criatura que pode ver objetos invisíveis vê o sensor como um orbe luminoso do tamanho de seu punho. Em vez de escolher uma criatura como alvo, você pode escolher um local que tenha visto antes como alvo deste feitiço. Quando fizer isso, o sensor aparece naquele local e não se move.", ["Bardo", "Clérico", "Druida", "Bruxo", "Mago"], false, true, ""),
  sp("Geas", 5, "Encantamento", "1 minuto", "60 pés", "30 dias", true, false, false, "", "Você coloca um comando mágico em uma criatura que você possa ver dentro do alcance, forçando-a a executar algum serviço ou abster-se de alguma ação ou curso de atividade conforme você decidir. Se a criatura puder entendê-lo, ela deve ter sucesso em um teste de resistência de Sabedoria ou ficar enfeitiçada por você pela duração. Enquanto a criatura está enfeitiçada por você, ela sofre 5d10 de dano psíquico cada vez que age de maneira diretamente contrária às suas instruções, mas não mais de uma vez por dia. Uma criatura que não possa entendê-lo não é afetada pela magia. Você pode dar qualquer comando que escolher, exceto uma atividade que resultaria em morte certa. Se você der um comando suicida, a magia termina. Você pode encerrar a magia mais cedo usando uma ação para dispensá-la. Uma magia remover maldição, restauração maior ou desejo também a encerra.", ["Bardo", "Clérico", "Druida", "Paladino", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 7º ou 8º nível, a duração é 1 ano. Quando você lança esta magia usando um espaço de magia de 9º nível, a magia dura até ser encerrada por uma das magias mencionadas acima."),
  sp("Golpe Flamejante", 5, "Evocação", "1 ação", "60 pés", "Instantânea", true, true, true, "Uma pitada de enxofre.", "Uma coluna vertical de fogo divino desce rugindo dos céus em um local que você especifica. Cada criatura em um cilindro de 10 pés de raio e 40 pés de altura centrado em um ponto dentro do alcance deve fazer um teste de resistência de Destreza. Uma criatura recebe 4d6 de dano de fogo e 4d6 de dano radiante em um teste falhado, ou metade do dano em um teste bem-sucedido.", ["Clérico"], false, false, "Quando você lança esta magia usando um espaço de magia de 6º nível ou superior, o dano de fogo ou o dano radiante (sua escolha) aumenta em 1d6 para cada nível de espaço acima do 5º."),
  sp("Ligação Telepática", 5, "Adivinhação", "1 ação", "30 pés", "1 hora", true, true, true, "Pedaços de casca de ovo de dois tipos diferentes de criaturas", "Você forja uma ligação telepática entre até oito criaturas dispostas à sua escolha dentro do alcance, vinculando psiquicamente cada criatura a todas as outras pela duração. Criaturas com escore de Inteligência de 2 ou menos não são afetadas por este feitiço. Até o feitiço terminar, os alvos podem se comunicar telepaticamente através da ligação quer tenham ou não uma língua comum. A comunicação é possível em qualquer distância, embora não possa se estender a outros planos de existência.", ["Mago"], true, false, ""),
  sp("Mão Arcana", 5, "Evocação", "1 ação", "36 metros", "Até 1 minuto", true, true, true, "Uma casca de ovo e uma luva de pele de cobra.", "Você cria uma mão Grande de força cintilante e translúcida em um espaço desocupado que você consegue ver dentro do alcance. A mão dura pela duração da magia, e se move sob seu comando, imitando os movimentos da sua própria mão. A mão é um objeto que tem CA 20 e pontos de vida iguais ao seu máximo de pontos de vida. Se chegar a 0 pontos de vida, a magia termina. Ela tem uma Força de 26 (+8) e Destreza de 10 (+0). A mão não preenche seu espaço. Quando você lança a magia e como uma ação bônus em seus turnos subsequentes, você pode mover a mão até 18 metros e então causar um dos seguintes efeitos com ela. Punho Cerrado. A mão ataca uma criatura ou objeto a 1,5 metros dela. Faça um ataque de magia corpo a corpo para a mão usando suas estatísticas de jogo. Acertando, o alvo sofre 4d8 de dano de força. Mão Poderosa. A mão tenta empurrar uma criatura a 1,5 metros dela em uma direção à sua escolha. Faça uma prova com a Força da mão contestada pelo teste de Força (Atletismo) do alvo. Se o alvo é Médio ou menor, você tem vantagem na prova. Se você suceder, a mão empurra o alvo até 1,5 metros mais um número de metros igual a cinco vezes seu modificador de habilidade de conjuração. A mão se move com o alvo para permanecer a 1,5 metros dele. Mão Agarradora. A mão tenta agarrar uma criatura Gigante ou menor a 1,5 metros dela. Você usa a pontuação de Força da mão para resolver a agarrada. Se o alvo é Médio ou menor, você tem vantagem na prova. Enquanto a mão está agarrando o alvo, você pode usar uma ação bônus para fazer a mão esmagá-lo. Quando você fizer isso, o alvo sofre dano de esmagamento igual a 2d6 + seu modificador de habilidade de conjuração. Mão Interposta. A mão se interpõe entre você e uma criatura à sua escolha até você dar à mão um comando diferente. A mão se move para ficar entre você e o alvo, proporcionando meio-encubrimento contra o alvo. O alvo não pode se mover através do espaço da mão se sua pontuação de Força é menor ou igual à da mão. Se sua pontuação de Força é maior que a da mão, o alvo pode se mover em sua direção através do espaço da mão, mas esse espaço é terreno difícil para o alvo.", ["Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 6º nível ou superior, o dano da opção punho cerrado aumenta em 2d8 e o dano da mão agarradora aumenta em 2d6 para cada nível de espaço acima do 5º."),
  sp("Modificar Memória", 5, "Encantamento", "1 ação", "30 pés", "Até 1 minuto", true, true, false, "", "Você tenta remodelar as memórias de outra criatura. Uma criatura que você possa ver deve fazer um salvamento de Sabedoria. Se você estiver lutando contra a criatura, ela tem vantagem no salvamento. Em um salvamento fracassado, o alvo fica enfeitiçado por você pela duração. O alvo enfeitiçado fica incapacitado e inconsciente de seus arredores, embora ainda possa ouvi-lo. Se sofrer algum dano ou for alvo de outro feitiço, este feitiço termina e nenhuma das memórias do alvo é modificada. Enquanto este encantamento dura, você pode afetar a memória do alvo de um evento que experimentou nos últimos 24 horas e que durou não mais de 10 minutos. Você pode eliminar permanentemente toda a memória do evento, permitir que o alvo se lembre do evento com clareza perfeita e detalhes exatos, alterar sua memória dos detalhes do evento ou criar uma memória de algum outro evento. Você deve falar com o alvo para descrever como suas memórias são afetadas, e ele deve ser capaz de entender sua língua para que as memórias modificadas se enraízem. Sua mente preenche quaisquer lacunas nos detalhes de sua descrição. Se o feitiço terminar antes de você ter terminado de descrever as memórias modificadas, a memória da criatura não é alterada. Caso contrário, as memórias modificadas se enraízem quando o feitiço termina. Uma memória modificada não necessariamente afeta como uma criatura se comporta, particularmente se a memória contradiz suas inclinações naturais, alinhamento ou crenças. Uma memória modificada ilógica, como implantar uma memória de quanto a criatura gostou de se imergir em ácido, é descartada, talvez como um mau sonho. O Mestre pode julgar uma memória modificada muito sem sentido para afetar uma criatura de forma significativa. Um feitiço Remover Maldição ou Restauração Maior lançado no alvo restaura a verdadeira memória da criatura.", ["Bardo", "Mago"], false, true, "Se você lançar este feitiço usando um espaço de feitiço de 6º nível ou superior, você pode alterar as memórias do alvo de um evento que ocorreu até 7 dias atrás (6º nível), 30 dias atrás (7º nível), 1 ano atrás (8º nível) ou a qualquer momento no passado da criatura (9º nível)."),
  sp("Muro de Força", 5, "Evocação", "1 ação", "120 pés", "Até 10 minutos", true, true, true, "Um pouco de pó feito ao esmagar uma pedra preciosa clara.", "Um muro invisível de força aparece em um ponto que você escolhe ao alcance. O muro aparece em qualquer orientação que você escolha, como uma barreira horizontal ou vertical ou em um ângulo. Pode estar flutuando livremente ou apoiado em uma superfície sólida. Você pode formá-lo em um domo hemisférico ou uma esfera com raio de até 10 pés, ou pode moldar uma superfície plana composta por dez painéis de 10 pés por 10 pés. Cada painel deve ser contíguo com outro painel. Em qualquer forma, o muro tem 1/4 de polegada de espessura. Ele dura pela duração. Se o muro corta o espaço de uma criatura quando aparece, a criatura é empurrada para um lado do muro (você escolhe qual lado). Nada pode passar fisicamente através do muro. Ele é imune a todo dano e não pode ser dissipado pela magia de dissipar magia. Um feitiço de desintegração destrói o muro instantaneamente, porém. O muro também se estende para o Plano Etéreo, bloqueando viagem etérea através do muro.", ["Mago"], false, true, ""),
  sp("Muro de Pedra", 5, "Evocação", "1 ação", "120 pés", "Até 10 minutos", true, true, true, "Um pequeno bloco de granito.", "Um muro não mágico de pedra sólida surge à existência em um ponto de sua escolha dentro do alcance. O muro tem 15 centímetros de espessura e é composto por dez painéis de 3 metros por 3 metros. Cada painel deve ser contíguo com pelo menos um outro painel. Alternativamente, você pode criar painéis de 3 metros por 6 metros que têm apenas 7,5 centímetros de espessura. Se o muro cortar o espaço de uma criatura quando aparece, a criatura é empurrada para um lado do muro (de sua escolha). Se uma criatura fosse ser cercada por todos os lados pelo muro (ou pelo muro e outra superfície sólida), essa criatura pode fazer um teste de salvamento de destreza. Em um sucesso, ela pode usar sua reação para se mover até sua velocidade para que não esteja mais cercada pelo muro. O muro pode ter qualquer forma que você desejar, embora não possa ocupar o mesmo espaço que uma criatura ou objeto. O muro não precisa ser vertical ou repousar em nenhuma fundação firme. Deve, no entanto, se fundir com e ser solidamente apoiado por pedra existente. Assim, você pode usar essa magia para atravessar um abismo ou criar uma rampa. Se você criar um vão maior que 6 metros de comprimento, você deve reduzir pela metade o tamanho de cada painel para criar suportes. Você pode moldar crudamente o muro para criar ameias, baluartes e assim por diante. O muro é um objeto feito de pedra que pode ser danificado e assim ser breached. Cada painel tem CA 15 e 30 pontos de vida por polegada de espessura. Reduzir um painel a 0 pontos de vida o destrói e pode fazer com que painéis conectados desabem a critério do MJ. Se você manter sua concentração nessa magia por sua duração inteira, o muro se torna permanente e não pode ser dissipado. Caso contrário, o muro desaparece quando a magia termina.", ["Druida", "Feiticeiro", "Mago"], false, true, ""),
  sp("Nuvem Mortífera", 5, "Conjuração", "1 ação", "120 pés", "Até 10 minutos", true, true, false, "", "Você cria uma esfera de névoa amarelo-esverdeada venenosa com raio de 20 pés, centrada em um ponto à sua escolha dentro do alcance. A névoa se espalha ao redor de cantos. Dura pela duração ou até que um vento forte disperse a névoa, encerrando a magia. Sua área é fortemente obscurecida. Quando uma criatura entra na área da magia pela primeira vez em um turno ou começa seu turno lá, essa criatura deve fazer um teste de resistência de Constituição. A criatura recebe 5d8 de dano venenoso em um teste falhado, ou metade desse dano em um bem-sucedido. Criaturas são afetadas mesmo que prendam a respiração ou não precisem respirar. A névoa se move 10 pés para longe de você no início de cada um de seus turnos, rolando pela superfície do solo. Os vapores, sendo mais pesados que o ar, afundam para o nível mais baixo do terreno, até mesmo fluindo por aberturas.", ["Feiticeiro", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 6º nível ou superior, o dano aumenta em 1d8 para cada nível de espaço acima do 5º."),
  sp("Passada Arbórea", 5, "Conjuração", "1 ação", "Você", "Até 1 minuto", true, true, false, "", "Você ganha a habilidade de entrar em uma árvore e se mover de dentro dela para dentro de outra árvore do mesmo tipo em até 500 pés de distância. Ambas as árvores devem estar vivas e ter pelo menos o mesmo tamanho que você. Você deve usar 5 pés de movimento para entrar em uma árvore. Você sabe instantaneamente a localização de todas as outras árvores do mesmo tipo em até 500 pés e, como parte do movimento usado para entrar na árvore, pode entrar em uma delas ou sair da árvore em que está. Você aparece em um local de sua escolha dentro de 5 pés da árvore de destino, usando outros 5 pés de movimento. Se não tiver movimento restante, você aparece dentro de 5 pés da árvore que entrou. Você pode usar essa habilidade de transporte uma vez por rodada pela duração. Você deve terminar cada turno fora de uma árvore.", ["Druida", "Patrulheiro"], false, true, ""),
  sp("Passagem", 5, "Transmutação", "1 ação", "30 pés", "1 hora", true, true, true, "Um pouco de sementes de gergelim.", "Uma passagem aparece em um ponto de sua escolha que você pode ver em uma superfície de madeira, gesso ou pedra (como uma parede, teto ou piso) dentro do alcance, e dura pela duração. Você escolhe as dimensões da abertura: até 5 pés de largura, 8 pés de altura e 20 pés de profundidade. A passagem não cria instabilidade em uma estrutura ao seu redor. Quando a abertura desaparece, todas as criaturas ou objetos ainda na passagem criada pelo feitiço são ejetados com segurança para um espaço desocupado mais próximo da superfície em que você lançou o feitiço.", ["Mago"], false, false, ""),
  sp("Praga de Insetos", 5, "Conjuração", "1 ação", "300 pés", "Até 10 minutos", true, true, true, "Um punhado de açúcar, alguns grãos de cereal e uma porção de gordura.", "Gafanhotos enxameantes e mordedores preenchem uma esfera de raio de 20 pés centrada em um ponto que você escolhe dentro do alcance. A esfera se espalha pelos cantos. A esfera permanece pela duração e sua área está levemente obscurecida. A área da esfera é terreno difícil. Quando a área aparece, cada criatura nela deve fazer um teste de resistência de constituição. Uma criatura sofre 4d10 de dano perfurante em um falha, ou metade do dano em um sucesso. Uma criatura também deve fazer este teste de resistência quando entra na área da magia pela primeira vez em um turno ou termina seu turno lá.", ["Clérico", "Druida", "Feiticeiro"], false, true, "Quando você lança esta magia usando um espaço de magia de 6º nível ou superior, o dano aumenta em 1d10 para cada nível de espaço acima do 5º."),
  sp("Prender Monstro", 5, "Encantamento", "1 ação", "90 pés", "Até 1 minuto", true, true, true, "Um pequeno pedaço de ferro.", "Escolha uma criatura que você possa ver e alcançar. O alvo deve fazer um teste de resistência de Sabedoria ou ser paralisado pela duração da magia. Essa magia não tem efeito contra mortos-vivos. Ao final de cada rodada, o alvo pode fazer um novo teste de resistência de Sabedoria. Se bem-sucedido, a magia termina para a criatura.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, true, "Quando você conjura essa magia usando um espaço de magia de 6º nível ou superior, você pode atingir uma criatura adicional para cada nível de espaço acima do quinto. As criaturas devem estar a 30 pés uma da outra quando você as atinge."),
  sp("Reencarnação", 5, "Transmutação", "1 hora", "Toque", "Instantâneo", true, true, true, "Óleos e unguentos raros no valor de pelo menos 1.000 po, que a magia consome.", "Você toca um humanóide morto ou uma parte de um humanóide morto. Desde que a criatura esteja morta há no máximo 10 dias, a magia forma um novo corpo adulto para ela e então convoca a alma para entrar naquele corpo. Se a alma do alvo não estiver livre ou disposta a fazer isso, a magia falha. A magia cria um novo corpo para a criatura habitar, o que provavelmente causa a mudança da raça da criatura. O Mestre lança um d100 e consulta a seguinte tabela para determinar que forma a criatura assume quando restaurada à vida, ou o Mestre escolhe uma forma. 01-04 Dracônico 05-13 Anão das colinas 14-21 Anão da montanha 22-25 Elfo negro 26-34 Elfo alto 35-42 Elfo da floresta 43-46 Gnomo da floresta 47-52 Gnomo das rochas 53-56 Meio-elfo 57-60 Meio-orc 61-68 Halfling pé-leve 69-76 Halfling forte 77-96 Humano 97-00 Tiefling A criatura reencarnada se recorda de sua vida anterior e experiências. Ela mantém as capacidades que tinha em sua forma original, exceto que troca sua raça original pela nova e altera seus traços raciais de acordo.", ["Druida"], false, false, ""),
  sp("Ressurreição", 5, "Necromancia", "1 hora", "Toque", "Instantâneo", true, true, true, "Um diamante no valor de pelo menos 500 po, que a magia consome.", "Você traz de volta à vida uma criatura morta que você toca, desde que ela não esteja morta há mais de 10 dias. Se a alma da criatura está disposta e livre para retornar ao corpo, a criatura volta à vida com 1 ponto de vida. Esta magia também neutraliza qualquer veneno e cura doenças não mágicas que afetavam a criatura no momento de sua morte. Esta magia não remove, porém, doenças mágicas, maldições ou efeitos similares; se estes não forem removidos antes de lançar a magia, eles entram em efeito quando a criatura volta à vida. A magia não pode trazer uma criatura morta-viva de volta à vida. Esta magia fecha todas as feridas mortais, mas não restaura partes do corpo faltantes. Se a criatura está faltando partes do corpo ou órgãos integrais para sua sobrevivência -- sua cabeça, por exemplo -- a magia falha automaticamente. Voltar dos mortos é uma provação. O alvo sofre uma penalidade de -4 em todos os testes de ataque, testes de resistência e testes de habilidade. Cada vez que o alvo termina um descanso longo, a penalidade é reduzida em 1 até desaparecer.", ["Bardo", "Clérico", "Paladino"], false, false, ""),
  sp("Restauração Maior", 5, "Abjuração", "1 ação", "Toque", "Instantânea", true, true, true, "Pó de diamante no valor de pelo menos 100 po, que a magia consome.", "Você imbuir uma criatura que você toca com energia positiva para desfazer um efeito debilitante. Você pode reduzir o nível de exaustão do alvo em um, ou encerrar um dos seguintes efeitos no alvo: - Um efeito que enfeitiçou ou petrificou o alvo - Uma maldição, incluindo o atenamento do alvo com um item mágico amaldiçoado - Qualquer redução em um dos escores de habilidade do alvo - Um efeito reduzindo o máximo de pontos de vida do alvo", ["Bardo", "Clérico", "Druida"], false, false, ""),
  sp("Sonho", 5, "Ilusão", "1 minuto", "Especial", "8 horas", true, true, true, "Um punhado de areia, um pouco de tinta e uma pena de escrita arrancada de um pássaro adormecido.", "Esta magia molda os sonhos de uma criatura. Escolha uma criatura que você conhece como alvo desta magia. O alvo deve estar no mesmo plano de existência que você. Criaturas que não dormem, como elfos, não podem ser contatadas por esta magia. Você, ou uma criatura disposta que você toque, entra em um estado de transe, atuando como um mensageiro. Enquanto em transe, o mensageiro está ciente de seus arredores, mas não pode realizar ações ou se mover. Se o alvo estiver dormindo, o mensageiro aparece nos sonhos do alvo e pode conversar com o alvo enquanto ele permanecer dormindo, pela duração da magia. O mensageiro também pode moldar o ambiente do sonho, criando paisagens, objetos e outras imagens. O mensageiro pode sair do transe a qualquer momento, encerrando o efeito da magia antecipadamente. O alvo se lembra perfeitamente do sonho ao acordar. Se o alvo estiver acordado quando você lançar a magia, o mensageiro saberá disso e pode encerrar o transe (e a magia) ou esperar que o alvo adormeça, momento em que o mensageiro aparecerá nos sonhos do alvo. Você pode fazer o mensageiro parecer monstruoso e aterrorizante para o alvo. Se fizer isso, o mensageiro pode entregar uma mensagem com no máximo dez palavras e então o alvo deve fazer um teste de salvação de Sabedoria. Em um salvamento falhado, ecos da monstruosidade fantasmagórica criam um pesadelo que dura pela duração do sono do alvo e evita que o alvo ganhe qualquer benefício daquele descanso. Além disso, quando o alvo acordar, ele sofre 3d6 de dano psíquico. Se você tiver uma parte do corpo, mecha de cabelo, aparador de unha ou porção similar do corpo do alvo, o alvo faz seu teste de salvação com desvantagem.", ["Bardo", "Bruxo", "Mago"], false, false, ""),
  sp("Telecinese", 5, "Transmutação", "1 ação", "60 pés", "Até 10 minutos", true, true, false, "", "Você ganha a capacidade de mover ou manipular criaturas ou objetos através do pensamento. Quando você lança o feitiço e como sua ação a cada turno durante a duração, você pode exercer sua vontade sobre uma criatura ou objeto que você pode ver dentro do alcance, causando o efeito apropriado abaixo. Você pode afetar o mesmo alvo turno após turno ou escolher um novo a qualquer momento. Se você mudar de alvo, o alvo anterior não é mais afetado pelo feitiço. Criatura: Você pode tentar mover uma criatura Colossal ou menor. Faça um teste de habilidade com sua habilidade de lançamento de feitiço contestado pelo teste de Força da criatura. Se você vencer o confronto, você move a criatura até 30 pés em qualquer direção, incluindo para cima, mas não além do alcance deste feitiço. Até o final do seu próximo turno, a criatura fica restringida em sua garra telecinética. Uma criatura levantada para cima fica suspensa no ar. Nos turnos subsequentes, você pode usar sua ação para tentar manter sua garra telecinética na criatura repetindo o confronto. Objeto: Você pode tentar mover um objeto que pesa até 1.000 quilos. Se o objeto não estiver sendo usado ou carregado, você o move automaticamente até 30 pés em qualquer direção, mas não além do alcance deste feitiço. Se o objeto estiver sendo usado ou carregado por uma criatura, você deve fazer um teste de habilidade com sua habilidade de lançamento de feitiço contestado pelo teste de Força da criatura. Se você tiver sucesso, você puxa o objeto dessa criatura e pode movê-lo até 30 pés em qualquer direção, mas não além do alcance deste feitiço. Você pode exercer controle fino em objetos com sua garra telecinética, como manipular uma ferramenta simples, abrir uma porta ou um recipiente, guardar ou recuperar um item de um recipiente aberto ou derramar o conteúdo de um frasco.", ["Feiticeiro", "Mago"], false, true, ""),
  sp("Vinculação Planar", 5, "Abjuração", "1 hora", "60 pés", "24 horas", true, true, true, "Uma joia no valor de pelo menos 1.000 po, que a magia consome.", "Com esta magia, você tenta vincular um celestial, um elemental, um fey ou um fiend ao seu serviço. A criatura deve estar dentro do alcance durante todo o lançamento da magia. (Tipicamente, a criatura é primeiro invocada para o centro de um círculo mágico invertido para mantê-la presa enquanto esta magia é lançada.) Na conclusão do lançamento, o alvo deve fazer um teste de resistência de carisma. Se falhar, ele fica vinculado a servir você pela duração. Se a criatura foi invocada ou criada por outra magia, a duração dessa magia é estendida para corresponder à duração desta magia. Uma criatura vinculada deve seguir suas instruções da melhor forma possível. Você pode ordenar à criatura que o acompanhe em uma aventura, que guarde um local ou que entregue uma mensagem. A criatura obedece à letra de suas instruções, mas se a criatura for hostil a você, ela se esforça para distorcer suas palavras para alcançar seus próprios objetivos. Se a criatura executar suas instruções completamente antes da magia terminar, ela viaja para você para relatar esse fato se você estiver no mesmo plano de existência. Se você estiver em um plano de existência diferente, ela retorna ao lugar onde você a vinculou e permanece lá até a magia terminar.", ["Bardo", "Clérico", "Druida", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de nível superior, a duração aumenta para 10 dias com um espaço de 6º nível, para 30 dias com um espaço de 7º nível, para 180 dias com um espaço de 8º nível e para um ano e um dia com um espaço de magia de 9º nível."),
  sp("Aliança Planar", 6, "Conjuração", "10 minutos", "60 pés", "Instantâneo", true, true, false, "", "Você implora a uma entidade de outro mundo por ajuda. O ser deve ser conhecido por você: um deus, um primordial, um príncipe demônio ou algum outro ser de poder cósmico. Essa entidade envia um celestial, um elemental ou um fiend leal a ela para ajudá-lo, fazendo a criatura aparecer em um espaço desocupado dentro do alcance. Se você conhecer o nome específico de uma criatura, pode falar esse nome quando lançar esta magia para solicitar essa criatura, embora possa obter uma criatura diferente (escolha do Mestre). Quando a criatura aparece, ela não está obrigada a se comportar de forma específica. Você pode pedir à criatura que execute um serviço em troca de pagamento, mas ela não é obrigada a fazê-lo. A tarefa solicitada pode variar de simples (nos voe pelo abismo, ou nos ajude a lutar uma batalha) a complexa (espie nossos inimigos, ou nos proteja durante nossa incursão na masmorra). Você deve ser capaz de se comunicar com a criatura para negociar seus serviços. O pagamento pode assumir várias formas. Um celestial pode exigir uma doação considerável de ouro ou itens mágicos para um templo aliado, enquanto um fiend pode exigir um sacrifício vivo ou um presente de tesouro. Algumas criaturas podem trocar seu serviço por uma missão realizada por você. Como regra geral, uma tarefa que pode ser medida em minutos requer um pagamento de 100 po por minuto. Uma tarefa medida em horas requer 1.000 po por hora. E uma tarefa medida em dias (até 10 dias) requer 10.000 po por dia. O Mestre pode ajustar esses pagamentos com base nas circunstâncias em que você lançou a magia. Se a tarefa estiver alinhada com a ética da criatura, o pagamento pode ser reduzido pela metade ou até dispensado. Tarefas não perigosas normalmente exigem apenas metade do pagamento sugerido, enquanto tarefas especialmente perigosas podem exigir um presente maior. As criaturas raramente aceitam tarefas que parecem suicidas. Depois que a criatura completa a tarefa, ou quando a duração acordada do serviço expira, a criatura retorna ao seu plano natal após se reportar a você, se apropriado à tarefa e se possível. Se você não conseguir concordar sobre um preço pelo serviço da criatura, a criatura retorna imediatamente ao seu plano natal. Uma criatura recrutada para se juntar ao seu grupo conta como membro dele, recebendo uma parte completa dos pontos de experiência concedidos.", ["Clérico"], false, false, ""),
  sp("Barreira de Lâminas", 6, "Evocação", "1 ação", "90 pés", "Até 10 minutos", true, true, false, "", "Você cria uma parede vertical de lâminas giratórias afiadas feitas de energia mágica. A parede aparece dentro do alcance e dura pela duração. Você pode criar uma parede reta de até 100 pés de comprimento, 20 pés de altura e 5 pés de espessura, ou uma parede em anel de até 60 pés de diâmetro, 20 pés de altura e 5 pés de espessura. A parede fornece três quartos de cobertura para criaturas atrás dela, e seu espaço é terreno difícil. Quando uma criatura entra na área da parede pela primeira vez em um turno ou começa seu turno lá, a criatura deve fazer um teste de destreza. Se falhar, a criatura sofre 6d10 de dano cortante. Se conseguir, a criatura sofre metade do dano.", ["Clérico"], false, true, ""),
  sp("Caminhada do Vento", 6, "Transmutação", "1 minuto", "30 pés", "8 horas", true, true, true, "Fogo e água benta.", "Você e até dez criaturas dispostas que você pode ver dentro do alcance assumem uma forma gasosa pela duração, parecendo wisps de nuvem. Enquanto nesta forma de nuvem, uma criatura tem uma velocidade de voo de 300 pés e tem resistência a dano de armas não mágicas. As únicas ações que uma criatura pode tomar nesta forma são a ação Disparada ou reverter para sua forma normal. Reverter leva 1 minuto, durante o qual uma criatura fica incapacitada e não pode se mover. Até que a magia termine, uma criatura pode reverter para forma de nuvem, o que também requer a transformação de 1 minuto. Se uma criatura está em forma de nuvem e voando quando o efeito termina, a criatura desce 60 pés por rodada durante 1 minuto até pousar, o que faz com segurança. Se não conseguir pousar após 1 minuto, a criatura cai pela distância restante.", ["Druida"], false, false, ""),
  sp("Carne em Pedra", 6, "Transmutação", "1 ação", "60 pés", "Até 1 minuto", true, true, true, "Uma pitada de cal, água e terra.", "Você tenta transformar uma criatura que possa ver dentro do alcance em pedra. Se o corpo do alvo é feito de carne, a criatura deve fazer um teste de resistência de Constituição. Em um teste falhado, fica impedida enquanto sua carne começa a endurecer. Em um teste bem-sucedido, a criatura não é afetada. Uma criatura impedida por esta magia deve fazer outro teste de resistência de Constituição no final de cada um de seus turnos. Se conseguir se salvar contra esta magia três vezes, a magia termina. Se falhar em seus testes três vezes, é transformada em pedra e fica sujeita à condição petrificada pela duração. Os sucessos e fracassos não precisam ser consecutivos; acompanhe ambos até que o alvo obtenha três de um tipo. Se a criatura for fisicamente quebrada enquanto petrificada, sofrerá deformidades semelhantes se reverter ao seu estado original. Se você mantiver sua concentração nesta magia pela duração máxima possível, a criatura é transformada em pedra até que o efeito seja removido.", ["Bruxo", "Mago"], false, true, ""),
  sp("Círculo de Morte", 6, "Necromancia", "1 ação", "45 metros", "Instantâneo", true, true, true, "O pó de uma pérola negra esmagada no valor de pelo menos 500 pe.", "Uma esfera de energia negativa se irradia em uma esfera de 18 metros de raio a partir de um ponto dentro do alcance. Cada criatura naquela área deve fazer um teste de salvação de Constituição. Um alvo recebe 8d6 de dano necrótico em uma falha ou metade do dano em um sucesso.", ["Feiticeiro", "Bruxo", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 7º nível ou superior, o dano aumenta em 2d6 para cada nível de espaço acima do 6º."),
  sp("Contingência", 6, "Evocação", "10 minutos", "Pessoal", "10 dias", true, true, true, "Uma estatueta de você esculpida em marfim e decorada com gemas no valor de pelo menos 1.500 po", "Escolha uma magia de 5º nível ou inferior que você possa lançar, que tenha um tempo de lançamento de 1 ação e que possa ter você como alvo. Você lança essa magia — chamada de magia contingente — como parte do lançamento de contingência, gastando espaços de magia para ambas, mas a magia contingente não entra em efeito. Em vez disso, ela entra em efeito quando uma circunstância específica ocorre. Você descreve essa circunstância quando lança as duas magias. Por exemplo, uma contingência lançada com respiração aquática pode estipular que respiração aquática entra em efeito quando você está envolvido por água ou um líquido similar. A magia contingente entra em efeito imediatamente após a circunstância ser atendida pela primeira vez, independentemente de você querer ou não, e então contingência termina. A magia contingente entra em efeito apenas em você, mesmo que normalmente possa ter outros como alvo. Você pode usar apenas uma magia contingente por vez. Se você lançar essa magia novamente, o efeito de outra magia contingente em você termina. Além disso, contingência termina em você se seu componente material nunca estiver em sua pessoa.", ["Mago"], false, false, ""),
  sp("Convocação Instantânea", 6, "Conjuração", "1 minuto", "Toque", "Até ser dissipada", true, true, true, "Uma safira no valor de 1.000 po.", "Você toca um objeto que pesa 10 libras ou menos cuja dimensão mais longa é 6 pés ou menos. A magia deixa uma marca invisível em sua superfície e inscreve invisivelmente o nome do item na safira que você usa como componente material. Cada vez que você lança esta magia, deve usar uma safira diferente. A qualquer momento depois disso, você pode usar sua ação para dizer o nome do item e quebrar a safira. O item aparece instantaneamente em sua mão, independentemente de distâncias físicas ou planares, e a magia termina. Se outra criatura está segurando ou carregando o item, quebrar a safira não transporta o item para você, mas ao invés disso você aprende quem é a criatura que possui o objeto e aproximadamente onde aquela criatura está localizada naquele momento. Dissipar Magia ou um efeito similar aplicado com sucesso na safira termina o efeito desta magia.", ["Mago"], true, false, ""),
  sp("Convocar Fada", 6, "Conjuração", "1 minuto", "27 metros", "Até 1 hora", true, true, false, "", "Você convoca uma criatura feérica com classificação de desafio 6 ou menor, ou um espírito feérico que assume a forma de uma fera com classificação de desafio 6 ou menor. Ela aparece em um espaço desocupado que você pode ver dentro do alcance. A criatura feérica desaparece quando seus pontos de vida chegam a 0 ou quando a magia termina. A criatura feérica é amigável com você e seus companheiros durante a duração. Role iniciativa para a criatura, que tem seus próprios turnos. Ela obedece a qualquer comando verbal que você lhe der (nenhuma ação necessária de sua parte), desde que eles não violem seu alinhamento. Se você não der nenhum comando à criatura feérica, ela se defende de criaturas hostis, mas caso contrário não toma ações. Se sua concentração for quebrada, a criatura feérica não desaparece. Em vez disso, você perde o controle da criatura feérica, ela se torna hostil com você e seus companheiros, e pode atacar. Uma criatura feérica descontrolada não pode ser dispensada por você, e desaparece 1 hora depois que você a convocou. O mestre tem as estatísticas da criatura feérica.", ["Druida", "Bruxo"], false, true, "Quando você lança esta magia usando um espaço de magia de 7º nível ou superior, a classificação de desafio aumenta em 1 para cada nível de espaço acima do 6º."),
  sp("Corrente de Raios", 6, "Evocação", "1 ação", "45 metros", "Instantâneo", true, true, true, "Um pouco de pelo; um pedaço de âmbar, vidro ou uma vara de cristal; e três alfinetes de prata.", "Você cria um raio que se arqueia em direção a um alvo à sua escolha que você possa ver dentro do alcance. Três raios então saltam daquele alvo para até três outros alvos, cada um dos quais deve estar a até 9 metros do primeiro alvo. Um alvo pode ser uma criatura ou um objeto e pode ser alvo de apenas um dos raios. Um alvo deve fazer um teste de salvação de Destreza. O alvo recebe 10d8 de dano de raio em uma falha ou metade do dano em um sucesso.", ["Feiticeiro", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 7º nível ou superior, um raio adicional salta do primeiro alvo para outro alvo para cada nível de espaço acima do 6º."),
  sp("Criar Morto-Vivo", 6, "Necromancia", "1 minuto", "10 pés", "Instantâneo", true, true, true, "Um pote de barro cheio de terra de sepultura, um pote de barro cheio de água salobra, e uma pedra de ônix negra de 150 po para cada cadáver.", "Você só pode lançar este feitiço à noite. Escolha até três cadáveres de humanoides Médios ou Pequenos ao alcance. Cada cadáver se torna um ghoul sob seu controle. (O Mestre tem as estatísticas de jogo para estas criaturas.) Como uma ação bônus em cada um de seus turnos, você pode comandar mentalmente qualquer criatura que você animou com este feitiço se a criatura estiver dentro de 120 pés de você (se você controlar múltiplas criaturas, você pode comandar qualquer uma ou todas elas ao mesmo tempo, emitindo o mesmo comando para cada uma). Você decide qual ação a criatura executará e para onde ela se moverá durante seu próximo turno, ou você pode emitir um comando geral, como guardar uma câmara ou corredor particular. Se você não emitir comandos, a criatura apenas se defende contra criaturas hostis. Uma vez dado um comando, a criatura continua a segui-lo até que sua tarefa seja concluída. A criatura fica sob seu controle por 24 horas, após o qual deixa de obedecer qualquer comando que você tenha dado. Para manter o controle da criatura por outras 24 horas, você deve lançar este feitiço na criatura antes do período atual de 24 horas terminar. Este uso do feitiço reafirma seu controle sobre até três criaturas que você animou com este feitiço, em vez de animar novas.", ["Clérico", "Bruxo", "Mago"], false, false, "Quando você lança este feitiço usando um espaço de feitiço de 7º nível, você pode animar ou reafirmar controle sobre quatro ghouls. Quando você lança este feitiço usando um espaço de feitiço de 8º nível, você pode animar ou reafirmar controle sobre cinco ghouls ou dois ghasts ou wights. Quando você lança este feitiço usando um espaço de feitiço de 9º nível, você pode animar ou reafirmar controle sobre seis ghouls, três ghasts ou wights, ou duas múmias."),
  sp("Curar Ferimentos", 6, "Evocação", "1 ação", "60 pés", "Instantâneo", true, true, false, "", "Escolha uma criatura que você possa ver dentro do alcance. Uma onda de energia positiva passa pela criatura, fazendo com que ela recupere 70 pontos de vida. Esta magia também encerra cegueira, surdez e quaisquer doenças afetando o alvo. Esta magia não tem efeito em constructos ou mortos-vivos.", ["Clérico", "Druida"], false, false, "Quando você lança essa magia usando um espaço de magia de 7º nível ou superior, a quantidade de cura aumenta em 10 para cada nível de espaço acima do 6º."),
  sp("Dança Irresistível", 6, "Encantamento", "1 ação", "30 pés", "Até 1 minuto", true, false, false, "", "Escolha uma criatura que você possa ver dentro do alcance. O alvo começa uma dança cômica no lugar: mexendo-se, batendo os pés e caprichando pela duração. Criaturas que não podem ser enfeitiçadas são imunes a esta magia. Uma criatura dançante deve usar todo seu movimento para dançar sem sair de seu espaço e tem desvantagem em testes de resistência de destreza e testes de ataque. Enquanto o alvo está afetado por esta magia, outras criaturas têm vantagem em testes de ataque contra ele. Como uma ação, uma criatura dançante faz um teste de resistência de sabedoria para recuperar o controle de si mesma. Em um sucesso, a magia termina.", ["Bardo", "Mago"], false, true, ""),
  sp("Desintegração", 6, "Transmutação", "1 ação", "60 pés", "Instantâneo", true, true, true, "Uma pedra-ímã e um pouco de pó.", "Um raio verde fino brota de seu dedo apontado para um alvo que você pode ver dentro do alcance. O alvo pode ser uma criatura, um objeto, ou uma criação de força mágica, como a parede criada por Parede de Força. Uma criatura alvo dessa magia deve fazer um teste de salvação de Destreza. Se falhar, o alvo sofre 10d6 + 40 de dano de força. Se esse dano reduzir o alvo a 0 pontos de vida, ele é desintegrado. Uma criatura desintegrada e tudo que está vestindo e carregando, exceto itens mágicos, são reduzidos a uma pilha de pó cinzento fino. A criatura só pode ser restaurada à vida por meio de uma Ressurreição Verdadeira ou uma magia de Desejo. Esta magia desintegra automaticamente um objeto não mágico Grande ou menor ou uma criação de força mágica. Se o alvo for um objeto Enorme ou maior ou criação de força, esta magia desintegra uma porção de 10 pés cúbicos dela. Um item mágico não é afetado por esta magia.", ["Feiticeiro", "Mago"], false, false, "Quando você lança esta magia usando um espaço de magia de 7º nível ou superior, o dano aumenta em 3d6 para cada nível de espaço acima do 6º."),
  sp("Encontrar o Caminho", 6, "Adivinhação", "1 minuto", "Pessoal", "Até 24 horas", true, true, true, "Um conjunto de ferramentas divinatórias--como ossos, varas de marfim, cartas, dentes ou runas entalhadas--no valor de 100 peças de ouro e um objeto do local que você deseja encontrar.", "Esta magia permite que você encontre a rota física mais curta e direta para um local fixo específico que você conhece no mesmo plano de existência. Se você nomear um destino em outro plano de existência, um destino que se move (como uma fortaleza móvel) ou um destino que não é específico (como \"o covil de um dragão verde\"), a magia falha. Durante a duração, desde que você esteja no mesmo plano de existência que o destino, você sabe a que distância está e em que direção fica. Enquanto você viaja para lá, sempre que lhe é apresentada uma escolha de caminhos no caminho, você automaticamente determina qual caminho é a rota mais curta e direta (mas não necessariamente a mais segura) para o destino.", ["Bardo", "Clérico"], false, true, ""),
  sp("Esfera Congelante", 6, "Evocação", "1 ação", "300 pés", "Instantâneo", true, true, true, "Uma pequena esfera de cristal.", "Uma esfera gelada de energia de frio sai de suas pontas de dedo até um ponto à sua escolha dentro do alcance, onde explode em uma esfera de 60 pés de raio. Cada criatura dentro da área deve fazer um teste de salvação de Constituição. Se falhar, uma criatura sofre 10d6 de dano de frio. Se tiver sucesso, sofre metade do dano. Se a esfera atinge um corpo de água ou um líquido que é principalmente água (não incluindo criaturas baseadas em água), ela congela o líquido a uma profundidade de 6 polegadas sobre uma área de 30 pés quadrados. Este gelo dura 1 minuto. Criaturas que estavam nadando na superfície da água congelada são presas no gelo. Uma criatura presa pode usar uma ação para fazer um teste de Força contra seu CD de salvação de magia para se libertar. Você pode se recusar a disparar a esfera após completar a magia, se desejar. Uma pequena esfera do tamanho aproximado de uma pedra de funda, fria ao toque, aparece em sua mão. A qualquer momento, você ou uma criatura a quem você deu a esfera pode lançá-la (para um alcance de 40 pés) ou arremessá-la com uma funda (para o alcance normal da funda). Ela se parte no impacto, com o mesmo efeito do lançamento normal da magia. Você também pode colocar a esfera no chão sem quebrá-la. Após 1 minuto, se a esfera ainda não tiver se partido, ela explode.", ["Mago"], false, false, "Quando você lança esta magia usando um slot de magia de 7º nível ou superior, o dano aumenta 1d6 para cada nível de slot acima do 6º."),
  sp("Festa dos Heróis", 6, "Conjuração", "10 minutos", "30 pés", "Instantâneo", true, true, true, "Uma tigela cravejada de gemas no valor de pelo menos 1.000 po, que a magia consome.", "Você traz à tona um grande banquete, incluindo comida e bebida magnífica. O banquete leva 1 hora para ser consumido e desaparece ao final desse tempo, e os efeitos benéficos não entram em vigor até essa hora terminar. Até doze outras criaturas podem participar do banquete. Uma criatura que participa do banquete ganha vários benefícios. A criatura é curada de todas as doenças e venenos, se torna imune a veneno e medo, e faz todos os testes de resistência de Sabedoria com vantagem. Seu máximo de pontos de vida também aumenta em 2d10, e ela ganha o mesmo número de pontos de vida. Esses benefícios duram 24 horas.", ["Clérico", "Druida"], false, false, ""),
  sp("Frasco Mágico", 6, "Necromancia", "1 minuto", "Pessoal", "Até ser dissipado", true, true, true, "Uma gema, cristal, relicário ou algum outro recipiente ornamental no valor de pelo menos 500 po.", "Seu corpo cai em um estado catatônico enquanto sua alma sai dele e entra no recipiente que você usou como componente material do feitiço. Enquanto sua alma habita o recipiente, você está ciente de seus arredores como se estivesse no espaço do recipiente. Você não pode se mover ou usar reações. A única ação que você pode realizar é projetar sua alma até 100 pés para fora do recipiente, retornando ao seu corpo vivo (e terminando o feitiço) ou tentando possuir o corpo de um humanoide. Você pode tentar possuir qualquer humanoide dentro de 100 pés de você que você possa ver (criaturas protegidas por um feitiço de proteção contra o mal e o bem ou círculo mágico não podem ser possuídas). O alvo deve fazer um teste de salvação de carisma. Se falhar, sua alma se move para o corpo do alvo, e a alma do alvo fica presa no recipiente. Se tiver sucesso, o alvo resiste aos seus esforços para possuí-lo, e você não pode tentar possuí-lo novamente por 24 horas. Uma vez que você possui o corpo de uma criatura, você o controla. Suas estatísticas de jogo são substituídas pelas estatísticas da criatura, embora você retenha seu alinhamento e suas pontuações de Inteligência, Sabedoria e Carisma. Você retém o benefício de seus próprios traços de classe. Se o alvo tiver níveis de classe, você não pode usar nenhum de seus traços de classe. Enquanto isso, a alma da criatura possuída pode perceber do recipiente usando seus próprios sentidos, mas não pode se mover ou realizar ações. Enquanto possui um corpo, você pode usar sua ação para retornar do corpo do hospedeiro ao recipiente se estiver dentro de 100 pés de você, retornando a alma da criatura hospedeira ao seu corpo. Se o corpo do hospedeiro morrer enquanto você estiver nele, a criatura morre, e você deve fazer um teste de salvação de carisma contra sua própria CD de lançamento de feitiço. Se tiver sucesso, você retorna ao recipiente se estiver dentro de 100 pés de você. Caso contrário, você morre. Se o recipiente for destruído ou o feitiço terminar, sua alma retorna imediatamente ao seu corpo. Se seu corpo estiver a mais de 100 pés de você ou se seu corpo estiver morto quando você tentar retornar a ele, você morre. Se a alma de outra criatura estiver no recipiente quando ele for destruído, a alma da criatura retorna ao seu corpo se o corpo estiver vivo e dentro de 100 pés. Caso contrário, essa criatura morre. Quando o feitiço termina, o recipiente é destruído.", ["Mago"], false, false, ""),
  sp("Globo de Invulnerabilidade", 6, "Abjuração", "1 ação", "Pessoal", "Até 1 minuto", true, true, true, "Uma conta de vidro ou cristal que se quebra quando a magia termina.", "Uma barreira imóvel e levemente cintilante surge em um raio de 10 pés ao seu redor e permanece pela duração. Qualquer magia de 5º nível ou inferior lançada de fora da barreira não pode afetar criaturas ou objetos dentro dela, mesmo se a magia for lançada usando um espaço de magia de nível superior. Tal magia pode visar criaturas e objetos dentro da barreira, mas a magia não tem efeito sobre eles. Da mesma forma, a área dentro da barreira é excluída das áreas afetadas por tais magias.", ["Feiticeiro", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 7º nível ou superior, a barreira bloqueia magias de um nível superior para cada nível de espaço acima do 6º."),
  sp("Ilusão Programada", 6, "Ilusão", "1 ação", "120 pés", "Até ser dissipada", true, true, true, "Um pouco de lã e pó de jade no valor de pelo menos 25 po.", "Você cria uma ilusão de um objeto, uma criatura ou outro fenômeno visível dentro do alcance que se ativa quando uma condição específica ocorre. A ilusão é imperceptível até então. Ela não deve ser maior que um cubo de 30 pés, e você decide quando conjura a magia como a ilusão se comporta e que sons ela faz. Este desempenho programado pode durar até 5 minutos. Quando a condição que você especifica ocorre, a ilusão surge à existência e funciona da maneira que você descreveu. Uma vez que a ilusão termina seu desempenho, ela desaparece e permanece adormecida por 10 minutos. Após este tempo, a ilusão pode ser ativada novamente. A condição de disparo pode ser tão geral ou detalhada quanto você quiser, embora deva ser baseada em condições visuais ou audíveis que ocorram dentro de 30 pés da área. Por exemplo, você poderia criar uma ilusão de si mesmo para aparecer e advertir outros que tentam abrir uma porta com armadilha, ou você poderia definir a ilusão para ativar apenas quando uma criatura diz a palavra ou frase correta. A interação física com a imagem a revela como uma ilusão, porque as coisas podem passar através dela. Uma criatura que usa sua ação para examinar a imagem pode determinar que é uma ilusão com um teste bem-sucedido de Inteligência (Investigação) contra sua CD de teste de resistência de magia. Se uma criatura discerne a ilusão pelo que ela é, a criatura pode ver através da imagem e qualquer ruído que ela faz soa oco para a criatura.", ["Bardo", "Mago"], false, false, ""),
  sp("Interdição", 6, "Abjuração", "10 minutos", "Toque", "24 horas", true, true, true, "Um polvilho de água benta, incenso raro e rubi em pó no valor de pelo menos 1.000 po.", "Você cria uma barreira contra viagem mágica que protege até 40.000 pés quadrados de espaço no chão até uma altura de 30 pés acima do chão. Pela duração, criaturas não conseguem se teletransportar para a área nem usar portais, como os criados pela magia portal, para entrar na área. A magia protege a área contra viagem planar e, portanto, impede criaturas de acessar a área pela Plano Astral, Plano Etéreo, Feywild, Shadowfell ou pela magia deslocamento planar. Além disso, a magia causa dano aos tipos de criaturas que você escolhe quando a lança. Escolha um ou mais dos seguintes: celestiais, elementais, fey, fiends e mortos-vivos. Quando uma criatura escolhida entra na área da magia pela primeira vez em um turno ou começa seu turno lá, a criatura sofre 5d10 de dano radiante ou necrótico (sua escolha quando você lança esta magia). Quando você lança esta magia, pode designar uma senha. Uma criatura que fala a senha enquanto entra na área não sofre dano da magia. A área da magia não pode se sobrepor com a área de outra magia de interdição. Se você lançar interdição todos os dias por 30 dias no mesmo local, a magia dura até ser dissipada, e os componentes materiais são consumidos no último lançamento.", ["Clérico"], true, false, ""),
  sp("Mover Terra", 6, "Transmutação", "1 ação", "120 pés", "Até 2 horas", true, true, true, "Uma lâmina de ferro e uma pequena bolsa contendo uma mistura de solos - argila, terra preta e areia.", "Escolha uma área de terreno não maior que 40 pés de lado dentro do alcance. Você pode remodelar terra, areia ou argila na área da forma que quiser durante a duração. Você pode elevar ou abaixar a elevação da área, criar ou preencher uma trincheira, erguer ou nivelar uma parede, ou formar um pilar. A extensão de qualquer mudança não pode exceder metade da maior dimensão da área. Portanto, se você afetar um quadrado de 40 pés, você pode criar um pilar de até 20 pés de altura, elevar ou abaixar a elevação do quadrado em até 20 pés, cavar uma trincheira de até 20 pés de profundidade, e assim por diante. Leva 10 minutos para essas mudanças serem concluídas. No final de cada 10 minutos que você gasta se concentrando no feitiço, você pode escolher uma nova área de terreno para afetar. Como a transformação do terreno ocorre lentamente, criaturas na área geralmente não podem ser presas ou feridas pelo movimento do solo. Este feitiço não pode manipular pedra natural ou construção de pedra. Rochas e estruturas se deslocam para acomodar o novo terreno. Se a forma como você molda o terreno tornaria uma estrutura instável, ela poderia desabar. Da mesma forma, este feitiço não afeta diretamente o crescimento de plantas. A terra movida carrega todas as plantas junto com ela.", ["Druida", "Feiticeiro", "Mago"], false, true, ""),
  sp("Muro de Espinhos", 6, "Conjuração", "1 ação", "120 pés", "Até 10 minutos", true, true, true, "Um punhado de espinhos.", "Você cria um muro de arbustos resistentes, flexíveis e emaranhados repletos de espinhos afiados como agulhas. O muro aparece dentro do alcance em uma superfície sólida e dura pela duração. Você escolhe fazer o muro de até 18 metros de comprimento, 3 metros de altura e 1,5 metro de espessura ou um círculo que tem 6 metros de diâmetro e até 6 metros de altura e 1,5 metro de espessura. O muro bloqueia a linha de visão. Quando o muro aparece, cada criatura dentro de sua área deve fazer um teste de salvamento de destreza. Em uma falha, uma criatura sofre 7d8 de dano perfurante, ou metade do dano em um sucesso. Uma criatura pode se mover através do muro, embora lentamente e dolorosamente. Para cada 30 centímetros que uma criatura se move através do muro, ela deve gastar 1,2 metros de movimento. Além disso, a primeira vez que uma criatura entra no muro em um turno ou termina seu turno lá, a criatura deve fazer um teste de salvamento de destreza. Ela sofre 7d8 de dano de corte em uma falha, ou metade do dano em um bem-sucedido.", ["Druida"], false, true, "Quando você lança essa magia usando um espaço de magia de 7º nível ou superior, ambos os tipos de dano aumentam em 1d8 para cada nível de espaço acima do 6º."),
  sp("Muro de Gelo", 6, "Evocação", "1 ação", "120 pés", "Até 10 minutos", true, true, true, "Um pequeno pedaço de quartzo.", "Você cria um muro de gelo em uma superfície sólida dentro do alcance. Você pode formá-lo em uma cúpula hemisférica ou uma esfera com raio de até 3 metros, ou pode moldar uma superfície plana feita de dez painéis quadrados de 3 metros. Cada painel deve ser contíguo com outro painel. Em qualquer forma, o muro tem 30 centímetros de espessura e dura pela duração. Se o muro cortar o espaço de uma criatura quando aparece, a criatura dentro de sua área é empurrada para um lado do muro e deve fazer um teste de salvamento de destreza. Em uma falha, a criatura sofre 10d6 de dano de frio, ou metade do dano em um sucesso. O muro é um objeto que pode ser danificado e assim ser breached. Tem CA 12 e 30 pontos de vida por seção de 3 metros, e é vulnerável a dano de fogo. Reduzir uma seção de 3 metros do muro a 0 pontos de vida a destrói e deixa para trás um lençol de ar glacial no espaço que o muro ocupava. Uma criatura que se move através do lençol de ar glacial pela primeira vez em um turno deve fazer um teste de salvamento de constituição. Essa criatura sofre 5d6 de dano de frio em uma falha, ou metade do dano em uma bem-sucedida.", ["Mago"], false, true, "Quando você lança essa magia usando um espaço de magia de 7º nível ou superior, o dano que o muro causa quando aparece aumenta em 2d6, e o dano ao passar pelo lençol de ar glacial aumenta em 1d6, para cada nível de espaço acima do 6º."),
  sp("Olhar Maligno", 6, "Necromancia", "1 ação", "Pessoal", "Até 1 minuto", true, true, false, "", "Pela duração da magia, seus olhos se tornam um vazio tintado imbuído de poder medonho. Uma criatura de sua escolha dentro de 60 pés de você que você possa ver deve ser bem-sucedida em um teste de resistência de Sabedoria ou ser afetada por um dos seguintes efeitos de sua escolha pela duração. Em cada um de seus turnos até a magia terminar, você pode usar sua ação para alvejar outra criatura, mas não pode alvejar uma criatura novamente se ela foi bem-sucedida em um teste de resistência contra esta lançamento de Olhar Maligno. Adormecido. O alvo cai inconsciente. Acorda se sofrer dano ou se outra criatura usar sua ação para acordá-lo. Em Pânico. O alvo fica assustado de você. Em cada um de seus turnos, a criatura assustada deve realizar a ação de Disparada e se afastar de você pela rota mais segura e curta disponível, a menos que não haja para onde se mover. Se o alvo se mover para um lugar a pelo menos 60 pés de distância de você onde não pode mais vê-lo, este efeito termina. Adoecido. O alvo tem desvantagem em testes de ataque e testes de habilidade. No final de cada um de seus turnos, ele pode fazer outro teste de resistência de Sabedoria. Se for bem-sucedido, o efeito termina.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, true, ""),
  sp("Palavra de Retorno", 6, "Conjuração", "1 ação", "5 pés", "Instantâneo", true, false, false, "", "Você e até cinco criaturas dispostas a 5 pés de você se teletransportam instantaneamente para um santuário previamente designado. Você e qualquer criatura que se teletransporte com você aparece no espaço desocupado mais próximo do local que designou quando preparou seu santuário (veja abaixo). Se você lançar esta magia sem primeiro preparar um santuário, a magia não tem efeito. Você deve designar um santuário lançando esta magia dentro de um local, como um templo, dedicado ou fortemente ligado à sua divindade. Se tentar lançar a magia dessa forma em uma área que não seja dedicada à sua divindade, a magia não tem efeito.", ["Clérico"], false, false, ""),
  sp("Praga", 6, "Necromancia", "1 ação", "60 pés", "Instantâneo", true, true, false, "", "Você desencadeia uma doença virulenta sobre uma criatura que você possa ver dentro do alcance. O alvo deve fazer um teste de resistência de Constituição. Se falhar, ele sofre 14d6 de dano necromântico, ou metade desse dano se tiver sucesso. O dano não pode reduzir os pontos de vida do alvo abaixo de 1. Se o alvo falhar no teste de resistência, seu máximo de pontos de vida é reduzido por 1 hora em uma quantidade igual ao dano necromântico sofrido. Qualquer efeito que remova uma doença permite que os pontos de vida máximos de uma criatura retornem ao normal antes desse tempo passar.", ["Clérico"], false, false, ""),
  sp("Proteção e Vigilância", 6, "Abjuração", "10 minutos", "Toque", "24 horas", true, true, true, "Incenso queimando, uma pequena medida de enxofre e óleo, uma corda com nós, uma pequena quantidade de sangue de hulk de sombra, e uma pequena vara de prata no valor de pelo menos 10 po.", "Você cria uma proteção mágica que protege até 2.500 pés quadrados de espaço em piso (uma área de 50 pés quadrados, ou cem quadrados de 5 pés ou vinte e cinco de 10 pés). A área protegida pode ter até 20 pés de altura e ser moldada como desejar. Você pode proteger vários andares de um forte dividindo a área entre eles, contanto que possa caminhar em cada área contígua enquanto lança a magia. Ao lançar esta magia, você pode especificar indivíduos que não são afetados por nenhum ou todos os efeitos que escolher. Você também pode especificar uma senha que, quando dita em voz alta, torna o falante imune a esses efeitos. Proteção e Vigilância cria os seguintes efeitos dentro da área protegida. Corredores: A névoa preenche todos os corredores protegidos, tornando-os muito obscurecidos. Além disso, em cada interseção ou passagem oferecendo uma escolha de direção, há 50% de chance de uma criatura, que não você, acreditar que está indo na direção oposta àquela que escolheu. Portas: Todas as portas na área protegida são magicamente trancadas, como se seladas por uma magia de Fechadura Arcana. Além disso, você pode cobrir até dez portas com uma ilusão (equivalente à função de objeto ilusório da magia Ilusão Menor) para fazê-las parecer seções simples de parede. Escadas: Teias preenchem todas as escadas na área protegida de cima a baixo, como a magia Teia. Essas fitas se regeneram em 10 minutos se forem queimadas ou rasgadas enquanto Proteção e Vigilância durar. Outro Efeito de Magia: Você pode colocar sua escolha de um dos seguintes efeitos mágicos dentro da área protegida do forte. - Coloque Luzes Dançantes em quatro corredores. Você pode designar um programa simples que as luzes repetem enquanto Proteção e Vigilância durar. - Coloque Boca Mágica em dois locais. - Coloque Nuvem Fétida em dois locais. Os vapores aparecem nos locais que você designa; eles retornam dentro de 10 minutos se dispersos pelo vento enquanto Proteção e Vigilância durar. - Coloque um vento constante em um corredor ou sala. - Coloque uma Sugestão em um local. Você seleciona uma área de até 5 pés quadrados, e qualquer criatura que entre ou passe pela área recebe a sugestão mentalmente. A área protegida toda irradia magia. Um Dissipar Magia lançado em um efeito específico, se bem-sucedido, remove apenas esse efeito. Você pode criar uma estrutura permanentemente protegida e vigiada lançando essa magia ali todos os dias durante um ano.", ["Bardo", "Mago"], false, false, ""),
  sp("Raio Solar", 6, "Evocação", "1 ação", "Pessoal", "Até 1 minuto", true, true, true, "Uma lupa.", "Um raio de luz brilhante pisca da sua mão em uma linha de 5 pés de largura e 60 pés de comprimento. Cada criatura na linha deve fazer um teste de resistência de Constituição. Se falhar na resistência, uma criatura sofre 6d8 de dano radiante e fica cega até seu próximo turno. Se passar na resistência, sofre metade do dano e não fica cega por esse feitiço. Mortos-vivos e lodos têm desvantagem nesse teste de resistência. Você pode criar uma nova linha de radiância como sua ação em qualquer turno até o feitiço terminar. Durante a duração, uma mota de radiância brilhante brilha em sua mão. Ela emite luz brilhante em um raio de 30 pés e luz fraca por 30 pés adicionais. Essa luz é luz solar.", ["Druida", "Feiticeiro", "Mago"], false, true, ""),
  sp("Sugestão em Massa", 6, "Encantamento", "1 ação", "60 pés", "24 horas", true, false, true, "A língua de uma cobra e either um pouco de favo de mel ou uma gota de óleo doce.", "Você sugere um curso de ação (limitado a uma frase ou duas) e magicamente influencia até doze criaturas de sua escolha que você pode ver ao alcance e que podem ouvir e entender você. Criaturas que não podem ser enfeitiçadas são imunes a esse efeito. A sugestão deve ser formulada de tal forma que o curso de ação pareça razoável. Pedir à criatura para esfaquear a si mesma, jogar-se em uma lança, imolar-se ou fazer algum outro ato obviamente prejudicial nega automaticamente o efeito da magia. Cada alvo deve fazer um teste de salvamento de Sabedoria. Em uma falha de salvamento, ela persegue o curso de ação que você descreveu o melhor que pode. O curso de ação sugerido pode continuar pela duração inteira. Se a atividade sugerida puder ser concluída em um tempo menor, a magia termina quando o sujeito termina o que foi pedido. Você também pode especificar condições que dispararão uma atividade especial durante a duração. Por exemplo, você pode sugerir que um grupo de soldados dê todo seu dinheiro ao primeiro mendigo que encontrem. Se a condição não for atendida antes da magia terminar, a atividade não é realizada. Se você ou qualquer um de seus companheiros danificar uma criatura afetada por essa magia, a magia termina para aquela criatura.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, false, "Quando você lança essa magia usando um espaço de magia de 7º nível, a duração é 10 dias. Quando você usa um espaço de magia de 8º nível, a duração é 30 dias. Quando você usa um espaço de magia de 9º nível, a duração é um ano e um dia."),
  sp("Transporte por Plantas", 6, "Conjuração", "1 ação", "10 pés", "1 rodada", true, true, false, "", "Esta magia cria um vínculo mágico entre uma planta inanimada Grande ou maior ao seu alcance e outra planta, a qualquer distância, no mesmo plano de existência. Você deve ter visto ou tocado a planta de destino pelo menos uma vez antes. Pela duração, qualquer criatura pode entrar na planta alvo e sair da planta de destino usando 5 pés de movimento.", ["Druida"], false, false, ""),
  sp("Visão Verdadeira", 6, "Adivinhação", "1 ação", "Toque", "1 hora", true, true, true, "Um ungüento para os olhos que custa 25 po; é feito de pó de cogumelo, açafrão e gordura; e é consumido pela magia.", "Esta magia concede à criatura disposta que você toca a habilidade de ver as coisas como realmente são. Pela duração, a criatura tem visão verdadeira, percebe portas secretas ocultas por magia e pode ver para o Plano Etéreo, tudo em um alcance de 120 pés.", ["Bardo", "Clérico", "Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Bola de Fogo com Explosão Retardada", 7, "Evocação", "1 ação", "45 metros", "Até 1 minuto", true, true, true, "Uma pequena bolinha de guano de morcego e enxofre.", "Um raio de luz amarela lampeja do seu dedo apontado, depois se condensa para permanecer em um ponto escolhido dentro do alcance como uma conta brilhante pela duração. Quando o feitiço termina, seja porque sua concentração é quebrada ou porque você decide terminá-lo, a conta floresce com um rugido baixo em uma explosão de chamas que se espalha ao redor de cantos. Cada criatura em uma esfera de raio de 6 metros centrada naquele ponto deve fazer um teste de resistência de Destreza. Uma criatura sofre dano de fogo igual ao dano acumulado total em uma falha na salvação, ou metade desse dano em uma bem-sucedida. O dano base do feitiço é 12d6. Se no final do seu turno a conta ainda não detonou, o dano aumenta em 1d6. Se a conta brilhante for tocada antes do intervalo expirar, a criatura que a tocar deve fazer um teste de resistência de Destreza. Em uma falha na salvação, o feitiço termina imediatamente, causando a conta explodir em chamas. Em uma salvação bem-sucedida, a criatura pode arremessar a conta até 12 metros. Quando ela atingir uma criatura ou um objeto sólido, o feitiço termina, e a conta explode. O fogo danifica objetos na área e ignita objetos inflamáveis que não estão sendo vestidos ou carregados.", ["Feiticeiro", "Mago"], false, true, "Quando você lança este feitiço usando um espaço de feitiço de 8º nível ou superior, o dano base aumenta em 1d6 para cada nível de espaço acima do 7º."),
  sp("Convocar Celestial", 7, "Conjuração", "1 minuto", "27 metros", "Até 1 hora", true, true, false, "", "Você convoca um celestial com nível de desafio 4 ou menor, que aparece em um espaço desocupado que você possa ver dentro do alcance. O celestial desaparece quando cai a 0 pontos de vida ou quando a magia termina. O celestial é amigo seu e de seus companheiros pela duração. Role iniciativa para o celestial, que tem seus próprios turnos. Obedece a qualquer comando verbal que você emita (não requer ação sua), contanto que não violem seu alinhamento. Se não emitir comandos ao celestial, ele se defende de criaturas hostis, mas caso contrário não realiza ações. O Mestre tem as estatísticas do celestial.", ["Clérico"], false, true, "Quando você lança esta magia usando um espaço de magia de 9º nível, convoca um celestial com nível de desafio 5 ou menor."),
  sp("Dedo da Morte", 7, "Necromancia", "1 ação", "60 pés", "Instantâneo", true, true, false, "", "Você envia energia negativa através de uma criatura que você pode ver ao alcance, causando-lhe dor abrasadora. O alvo deve fazer um teste de resistência de Constituição. Ele sofre 7d8 + 30 de dano necrótico em uma falha, ou metade do dano em um sucesso. Um humanoide morto por esta magia se levanta no início do seu próximo turno como um zumbi permanentemente sob seu comando, seguindo suas ordens verbais da melhor forma possível.", ["Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Espada Arcana", 7, "Evocação", "1 ação", "18 metros", "Até 1 minuto", true, true, true, "Uma miniatura de espada de platina com guarda e pomo de cobre e zinco, valendo 2.500 PO.", "Você cria um plano de força em forma de espada que flutua dentro do alcance. Dura pela duração. Quando a espada aparece, você faz um ataque de magia corpo a corpo contra um alvo à sua escolha a 1,5 metros da espada. Acertando, o alvo sofre 3d10 de dano de força. Até a magia terminar, você pode usar uma ação bônus em cada um de seus turnos para mover a espada até 6 metros para um local que você consegue ver e repetir este ataque contra o mesmo alvo ou um diferente.", ["Bardo", "Mago"], false, true, ""),
  sp("Eternalidade", 7, "Transmutação", "1 ação", "Pessoal", "8 horas", true, true, false, "", "Você entra nas regiões fronteiriças do Plano Etéreo, na área onde ele se sobrepõe ao seu plano atual. Você permanece na Fronteira Etérea pela duração ou até usar sua ação para encerrar a magia. Durante esse tempo, você pode se mover em qualquer direção. Se você se mover para cima ou para baixo, cada pé de movimento custa um pé adicional. Você pode ver e ouvir o plano de onde veio, mas tudo lá parece cinzento e você não consegue ver nada a mais de 60 pés de distância. Enquanto no Plano Etéreo, você pode apenas afetar e ser afetado por outras criaturas nesse plano. Criaturas que não estão no Plano Etéreo não conseguem percebê-lo e não conseguem interagir com você, a menos que uma habilidade especial ou magia tenha dado a elas a capacidade de fazer isso. Você ignora todos os objetos e efeitos que não estão no Plano Etéreo, permitindo que você se mova através de objetos que percebe no plano de onde veio. Quando a magia termina, você retorna imediatamente ao plano de onde veio no local que você ocupa atualmente. Se você ocupar o mesmo espaço de um objeto sólido ou criatura quando isso acontecer, você é imediatamente deslocado para o espaço desocupado mais próximo que você possa ocupar e sofre dano de força igual ao dobro do número de pés que você foi deslocado. Essa magia não tem efeito se você a lançar enquanto está no Plano Etéreo ou em um plano que não tem fronteira com ele, como um dos Planos Exteriores.", ["Bardo", "Clérico", "Feiticeiro", "Bruxo", "Mago"], false, false, "Quando você lança essa magia usando um espaço de magia de 8º nível ou superior, você pode atingir até três criaturas dispostas (incluindo você) para cada nível de espaço acima do 7º. As criaturas devem estar a 10 pés de você quando você lança a magia."),
  sp("Gaiola de Força", 7, "Evocação", "1 ação", "100 pés", "1 hora", true, true, true, "Pó de rubi no valor de 1.500 po.", "Uma prisão imóvel e invisível em forma de cubo, composta de força mágica, surge em uma área à sua escolha dentro do alcance. A prisão pode ser uma gaiola ou uma caixa sólida, conforme você escolher. Uma prisão em forma de gaiola pode ter até 20 pés de lado e é feita de barras com diâmetro de 1/2 polegada espaçadas 1/2 polegada entre si. Uma prisão em forma de caixa pode ter até 10 pés de lado, criando uma barreira sólida que impede qualquer matéria de passar e bloqueia qualquer magia lançada para dentro ou para fora da área. Quando você lança a magia, qualquer criatura completamente dentro da área da gaiola fica presa. Criaturas apenas parcialmente dentro da área, ou aquelas muito grandes para caber dentro, são afastadas do centro da área até estarem completamente fora. Uma criatura dentro da gaiola não consegue sair por meios não-mágicos. Se a criatura tentar usar teletransportação ou viagem interplanar para sair da gaiola, ela deve primeiro fazer um teste de salvação de Carisma. Se tiver sucesso, a criatura pode usar essa magia para sair da gaiola. Se falhar, a criatura não consegue sair e desperdiça o uso da magia ou efeito. A gaiola também se estende pelo Plano Etéreo, bloqueando viagem etérea. Esta magia não pode ser dissipada por dissipar magia.", ["Bardo", "Bruxo", "Mago"], false, false, ""),
  sp("Gravidade Invertida", 7, "Transmutação", "1 ação", "100 pés", "Até 1 minuto", true, true, true, "Uma pedra-ímã e limalhas de ferro.", "Este feitiço inverte a gravidade em um cilindro de 50 pés de raio e 100 pés de altura centrado em um ponto dentro do alcance. Todas as criaturas e objetos que não estão de alguma forma ancorados ao solo na área caem para cima e alcançam o topo da área quando você lança este feitiço. Uma criatura pode fazer um teste de salvação de destreza para se agarrar a um objeto fixo que possa alcançar, evitando assim a queda. Se algum objeto sólido (como um teto) for encontrado durante essa queda, objetos e criaturas em queda o atingem da mesma forma que fariam durante uma queda normal para baixo. Se um objeto ou criatura alcançar o topo da área sem bater em nada, permanece lá, oscilando levemente, pela duração. Ao final da duração, objetos e criaturas afetados caem novamente para baixo.", ["Druida", "Feiticeiro", "Mago"], false, true, ""),
  sp("Jato Prismático", 7, "Evocação", "1 ação", "Pessoal", "Instantâneo", true, true, false, "", "Oito raios de luz multicolorida saem da sua mão. Cada raio é uma cor diferente e tem um poder e propósito diferente. Cada criatura em um cone de 60 pés deve fazer um teste de resistência de destreza. Para cada alvo, role um d8 para determinar qual raio colorido o afeta. 1. Vermelho. O alvo sofre 10d6 de dano de fogo em um teste falhado, ou metade do dano em um bem-sucedido. 2. Laranja. O alvo sofre 10d6 de dano de ácido em um teste falhado, ou metade do dano em um bem-sucedido. 3. Amarelo. O alvo sofre 10d6 de dano de raio em um teste falhado, ou metade do dano em um bem-sucedido. 4. Verde. O alvo sofre 10d6 de dano de veneno em um teste falhado, ou metade do dano em um bem-sucedido. 5. Azul. O alvo sofre 10d6 de dano de frio em um teste falhado, ou metade do dano em um bem-sucedido. 6. Anil. Em um teste falhado, o alvo fica restringido. Ele deve então fazer um teste de resistência de constituição no final de cada um de seus turnos. Se salvar com sucesso três vezes, a magia termina. Se falhar três vezes, ele se torna permanentemente pedra e está sujeito à condição petrificado. Os sucessos e fracassos não precisam ser consecutivos; acompanhe ambos até o alvo coletar três iguais. 7. Violeta. Em um teste falhado, o alvo fica cego. Ele deve então fazer um teste de resistência de sabedoria no início do seu próximo turno. Um teste bem-sucedido termina a cegueira. Se falhar nesse teste, a criatura é transportada para outro plano de existência escolhido pelo DM e não está mais cega. (Tipicamente, uma criatura que está em um plano que não é seu plano natal é banida para casa, enquanto outras criaturas geralmente são lançadas nos planos Astral ou Etéreo.) 8. Especial. O alvo é atingido por dois raios. Role mais duas vezes, rerolando qualquer 8.", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Mansão Magnífica", 7, "Conjuração", "1 minuto", "300 pés", "24 horas", true, true, true, "Um pequeno portal em miniatura esculpido em marfim, um pequeno pedaço de mármore polido e uma colher de prata minúscula, cada item valendo pelo menos 5 po.", "Você conjura uma moradia extradimensional ao alcance que dura pela duração. Você escolhe onde sua única entrada está localizada. A entrada brilha levemente e tem 5 pés de largura e 10 pés de altura. Você e qualquer criatura que você designar quando lança a magia pode entrar na moradia extradimensional enquanto o portal permanecer aberto. Você pode abrir ou fechar o portal se estiver a até 30 pés dele. Quando fechado, o portal fica invisível. Além do portal há um magnífico saguão com numerosas câmaras além. A atmosfera é limpa, fresca e quente. Você pode criar qualquer planta baixa que desejar, mas o espaço não pode exceder 50 cubos, cada cubo tendo 10 pés em cada lado. O lugar é mobiliado e decorado conforme você escolher. Contém comida suficiente para servir um banquete de nove pratos para até 100 pessoas. Uma equipe de 100 servos quase transparentes atende a todos que entram. Você decide a aparência visual desses servos e suas roupas. Eles são completamente obedientes aos seus pedidos. Cada servo pode realizar qualquer tarefa que um servo humano normal pudesse realizar, mas não podem atacar ou realizar qualquer ação que prejudicasse diretamente outra criatura. Assim os servos podem buscar coisas, limpar, consertar, dobrar roupas, acender fogueiras, servir comida, derramar vinho e assim por diante. Os servos podem ir a qualquer lugar na mansão mas não podem sair dela. Móveis e outros objetos criados por essa magia se dissipam em fumaça se removidos da mansão. Quando a magia termina, qualquer criatura dentro do espaço extradimensional é expelida para os espaços abertos mais próximos da entrada.", ["Bardo", "Mago"], false, false, ""),
  sp("Mirage Arcano", 7, "Ilusão", "10 minutos", "Visão", "10 dias", true, true, false, "", "Você faz com que o terreno em uma área de até 1 milha quadrada pareça, soe, cheire e até sinta como algum outro tipo de terreno. A forma geral do terreno permanece a mesma, porém. Campos abertos ou uma estrada poderiam ser feitos para se parecerem com um pântano, colina, fenda ou algum outro terreno difícil ou intransponível. Uma lagoa pode ser feita para parecer um prado gramado, um precipício como uma encosta suave, ou um vale rochoso como uma estrada ampla e suave. Da mesma forma, você pode alterar a aparência de estruturas ou adicioná-las onde nenhuma existe. O feitiço não disfarça, oculta ou adiciona criaturas. A ilusão inclui elementos audíveis, visuais, táteis e olfativos, então pode transformar solo limpo em terreno difícil (ou vice-versa) ou de outra forma impedir o movimento através da área. Qualquer peça do terreno ilusório (como uma pedra ou galho) que seja removida da área do feitiço desaparece imediatamente. Criaturas com visão verdadeira podem ver através da ilusão para a forma verdadeira do terreno; porém, todos os outros elementos da ilusão permanecem, então enquanto a criatura está ciente da presença da ilusão, a criatura ainda pode interagir fisicamente com a ilusão.", ["Bardo", "Druida", "Mago"], false, false, ""),
  sp("Mudança Planar", 7, "Conjuração", "1 ação", "Toque", "Instantâneo", true, true, true, "Uma vara de metal bifurcada no valor de pelo menos 250 po, atenta a um plano de existência específico.", "Você e até oito criaturas dispostas que unem as mãos em um círculo são transportadas para um plano de existência diferente. Você pode especificar um destino de alvo em termos gerais, como a Cidade de Bronze no Plano Elemental do Fogo ou o palácio de Dispater no segundo nível dos Nove Infernos, e você aparece dentro ou perto desse destino. Se você está tentando chegar à Cidade de Bronze, por exemplo, você pode chegar em sua Rua do Aço, diante de seu Portão de Cinzas, ou olhando a cidade do outro lado do Mar de Fogo, a critério do Mestre. Alternativamente, se você conhecer a sequência de sigilo de um círculo de teletransporte em outro plano de existência, esta magia pode levá-lo a esse círculo. Se o círculo de teletransporte for muito pequeno para conter todas as criaturas que você transportou, elas aparecem nos espaços desocupados mais próximos perto do círculo. Você pode usar esta magia para banir uma criatura desejosa para outro plano. Escolha uma criatura dentro de seu alcance e faça um ataque de magia corpo a corpo contra ela. Se acertar, a criatura deve fazer um teste de resistência de carisma. Se a criatura falhar neste teste de resistência, ela é transportada para um local aleatório no plano de existência que você especificar. Uma criatura transportada desta forma deve encontrar seu próprio caminho de volta para seu plano de existência atual.", ["Clérico", "Druida", "Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Palavra Divina", 7, "Evocação", "1 ação bônus", "30 pés", "Instantâneo", true, false, false, "", "Você fala uma palavra de Deus, cheia do poder que moldou o mundo no alvorecer da criação. Escolha quantas criaturas você quiser daquelas que você vê, dentro do alcance da magia. Cada criatura que o ouve deve fazer um teste de resistência de Carisma ou sofrer um efeito baseado no valor atual de seus pontos de vida. Criatura com 50 pv ou menos: muda por 1 minuto. Criatura com 40 pv ou menos: surda e cega por 10 minutos. Criatura com 30 pv ou menos: cega, surda e atordoada por 1 hora. Criatura com 20 pv ou menos: morta instantaneamente. Independentemente de seus pontos de vida atuais, um celestial, um elemental, um feérico ou um diabo que falhe em seu teste é devolvido ao seu plano de origem (se já não estiver lá) e não pode retornar ao seu plano por 24 horas, independentemente dos meios, com exceção do desejo.", ["Clérico"], false, false, ""),
  sp("Projetar Imagem", 7, "Ilusão", "1 ação", "500 milhas", "Até 24 horas", true, true, true, "Uma pequena réplica de você feita de materiais no valor de pelo menos 5 po.", "Você cria uma cópia ilusória de si mesmo que dura pela duração. A cópia pode aparecer em qualquer local ao alcance que você tenha visto antes, independentemente de obstáculos intervenientes. A ilusão parece e soa como você, mas é intangível. Se a ilusão sofre qualquer dano, ela desaparece e a magia termina. Você pode usar sua ação para mover esta ilusão até duas vezes sua velocidade e fazê-la gesticular, falar e se comportar da maneira que você escolher. Ela imita seus trejeitos perfeitamente. Você pode ver através de seus olhos e ouvir através de seus ouvidos como se estivesse em seu espaço. No seu turno como uma ação bônus, você pode mudar de usar seus sentidos para usar os seus próprios, ou vice-versa. Enquanto você está usando seus sentidos, você fica cego e surdo em relação ao seu próprio entorno. A interação física com a imagem a revela como uma ilusão, porque as coisas podem passar através dela. Uma criatura que usa sua ação para examinar a imagem pode determinar que é uma ilusão com um teste bem-sucedido de Inteligência (Investigação) contra sua CD de teste de resistência de magia. Se uma criatura discerne a ilusão pelo que ela é, a criatura pode ver através da imagem e qualquer ruído que ela faz soa oco para a criatura.", ["Bardo", "Mago"], false, true, ""),
  sp("Regeneração", 7, "Transmutação", "1 minuto", "Toque", "1 hora", true, true, true, "Uma roda de oração e água benta.", "Você toca uma criatura e estimula sua capacidade natural de cicatrização. O alvo recupera 4d8 + 15 pontos de vida. Pela duração da magia, o alvo recupera 1 ponto de vida no início de cada um de seus turnos (10 pontos de vida a cada minuto). Os membros corporais decepados do alvo (dedos, pernas, caudas e assim por diante), se houver algum, são restaurados após 2 minutos. Se você possuir a parte decepada e a mantiver junto ao coto, a magia instantaneamente faz o membro se unir ao coto.", ["Bardo", "Clérico", "Druida"], false, false, ""),
  sp("Ressurreição", 7, "Necromancia", "1 hora", "Toque", "Instantâneo", true, true, true, "Um diamante no valor de pelo menos 1.000 po, que a magia consome.", "Você toca uma criatura morta que está morta há no máximo um século, que não morreu de velhice e que não é um morto-vivo. Se sua alma estiver livre e disposta, o alvo volta à vida com todos os seus pontos de vida. Esta magia neutraliza quaisquer venenos e cura doenças normais que afligem a criatura quando morreu. Não remove, porém, doenças mágicas, maldições e similares; se tais efeitos não forem removidos antes de lançar a magia, eles afligem o alvo em seu retorno à vida. Esta magia fecha todas as feridas mortais e restaura qualquer parte corporal ausente. Voltar dos mortos é uma provação. O alvo sofre uma penalidade de -4 em todos os testes de ataque, testes de salvação e testes de habilidade. Toda vez que o alvo termina um descanso longo, a penalidade é reduzida em 1 até desaparecer. Lançar esta magia para restaurar a vida de uma criatura que está morta há um ano ou mais a exaure muito. Até você terminar um descanso longo, você não pode lançar magias novamente, e tem desvantagem em todos os testes de ataque, testes de habilidade e testes de salvação.", ["Bardo", "Clérico"], false, false, ""),
  sp("Sequestro", 7, "Transmutação", "1 ação", "Toque", "Até ser dissipado", true, true, true, "Um pó composto de poeira de diamante, esmeralda, rubi e safira no valor de pelo menos 5.000 po, que o feitiço consome.", "Por meio deste feitiço, uma criatura disposta ou um objeto pode ser escondido, seguro da detecção pela duração. Quando você lança o feitiço e toca o alvo, ele se torna invisível e não pode ser alvo de feitiços de adivinhação ou percebido através de sensores de escrutínio criados por feitiços de adivinhação. Se o alvo for uma criatura, ela entra em um estado de animação suspensa. O tempo cessa de fluir para ela e ela não envelhece. Você pode definir uma condição para o feitiço terminar mais cedo. A condição pode ser qualquer coisa que você escolha, mas deve ocorrer ou ser visível dentro de 1,6 quilômetro do alvo. Exemplos incluem \"após 1.000 anos\" ou \"quando o tarasco acorda.\" Este feitiço também termina se o alvo sofrer qualquer dano.", ["Mago"], false, false, ""),
  sp("Símbolo", 7, "Abjuração", "1 minuto", "Toque", "Até ser dissipado", true, true, true, "Mercúrio, fósforo e pó de diamante e opala com um valor total de pelo menos 1.000 po, que o feitiço consome.", "Quando você lança este feitiço, você inscreve um glifo prejudicial em uma superfície (como uma seção de piso, uma parede ou uma mesa) ou dentro de um objeto que pode ser fechado para ocultar o glifo (como um livro, um rolo ou um baú do tesouro). Se você escolher uma superfície, o glifo pode cobrir uma área não maior que 10 pés de diâmetro. Se você escolher um objeto, esse objeto deve permanecer em seu lugar; se o objeto se mover mais de 10 pés de onde você lançou este feitiço, o glifo é quebrado e o feitiço termina sem ser acionado. O glifo é quase invisível, exigindo um teste de Inteligência (Investigação) contra sua CD de feitiço para encontrá-lo. Você decide o que aciona o glifo quando lança o feitiço. Para glifos inscritos em uma superfície, os gatilhos mais típicos incluem tocar ou pisar no glifo, remover outro objeto que o cobre, se aproximar a uma certa distância dele ou manipular o objeto que o contém. Para glifos inscritos em um objeto, os gatilhos mais comuns são abrir o objeto, se aproximar a uma certa distância dele ou ver ou ler o glifo. Você pode refinar ainda mais o gatilho para que o feitiço seja ativado apenas sob certas circunstâncias ou de acordo com as características físicas de uma criatura (como altura ou peso) ou tipo físico (por exemplo, a proteção pode ser definida para afetar bruxas ou metamorfos). Você também pode especificar criaturas que não disparam o glifo, como as que dizem uma certa senha. Quando você inscreve o glifo, escolha uma das opções abaixo para seu efeito. Uma vez acionado, o glifo brilha, preenchendo uma esfera de raio de 60 pés com luz fraca por 10 minutos, após o qual o feitiço termina. Cada criatura na esfera quando o glifo se ativa é alvo de seu efeito, assim como uma criatura que entra na esfera pela primeira vez em um turno ou termina seu turno lá. Morte: Cada alvo deve fazer um teste de resistência de Constituição, sofrendo 10d10 de dano necrótico se falhar, ou metade do dano se passar. Discórdia: Cada alvo deve fazer um teste de resistência de Constituição. Se falhar, um alvo briga e discute com outras criaturas por 1 minuto. Durante este tempo, é incapaz de comunicação significativa e tem desvantagem em testes de ataque e de habilidade. Medo: Cada alvo deve fazer um teste de resistência de Sabedoria e fica assustado por 1 minuto se falhar. Enquanto assustado, o alvo solta o que está segurando e deve se mover pelo menos 30 pés de distância do glifo em cada um de seus turnos, se possível. Desesperança: Cada alvo deve fazer um teste de resistência de Carisma. Se falhar, o alvo é dominado pelo desespero por 1 minuto. Durante este tempo, não pode atacar ou mirar nenhuma criatura com habilidades prejudiciais, feitiços ou outros efeitos mágicos. Loucura: Cada alvo deve fazer um teste de resistência de Inteligência. Se falhar, o alvo enlouquece por 1 minuto. Uma criatura louca não pode fazer ações, não consegue entender o que outras criaturas dizem, não consegue ler e fala apenas em gibberish. O Mestre controla seu movimento, que é errático. Dor: Cada alvo deve fazer um teste de resistência de Constituição e fica incapacitado com dor excruciante por 1 minuto se falhar. Sono: Cada alvo deve fazer um teste de resistência de Sabedoria e fica inconsciente por 10 minutos se falhar. Uma criatura acorda se sofre dano ou se alguém usa uma ação para sacudi-la ou esbofeteá-la para acordar. Atordoamento: Cada alvo deve fazer um teste de resistência de Sabedoria e fica atordoado por 1 minuto se falhar.", ["Bardo", "Clérico", "Mago"], false, false, ""),
  sp("Simulacro", 7, "Ilusão", "12 horas", "Toque", "Até ser dissipado", true, true, true, "Neve ou gelo em quantidades suficientes para fazer uma cópia do tamanho da vida da criatura duplicada; alguns cabelos, aparas de unhas ou outra parte do corpo dessa criatura colocados dentro da neve ou gelo; e rubi em pó no valor de 1.500 po, espalhado sobre o duplicado e consumido pela magia.", "Você molda um duplicado ilusório de uma fera ou humanóide que esteja dentro do alcance por todo o tempo de lançamento da magia. O duplicado é uma criatura, parcialmente real e formada de gelo ou neve, e pode executar ações e ser afetada de outra forma como uma criatura normal. Parece ser igual ao original, mas tem a metade do máximo de pontos de vida da criatura e é formado sem nenhum equipamento. De outra forma, a ilusão usa todas as estatísticas da criatura que duplica. O simulacro é amigável a você e às criaturas que você designar. Obedece seus comandos falados, se movendo e agindo de acordo com seus desejos e agindo em seu turno em combate. O simulacro carece da capacidade de aprender ou se tornar mais poderoso, então nunca aumenta seu nível ou outras habilidades, nem pode recuperar espaços de magia gastos. Se o simulacro sofrer dano, você pode repará-lo em um laboratório alquímico, usando ervas raras e minerais no valor de 100 po por ponto de vida que recupera. O simulacro dura até cair a 0 pontos de vida, momento em que reverte para neve e derrete instantaneamente. Se você lançar essa magia novamente, qualquer duplicado atualmente ativo que você criou com essa magia é instantaneamente destruído.", ["Mago"], false, false, ""),
  sp("Teleportar", 7, "Conjuração", "1 ação", "3 metros", "Instantâneo", true, false, false, "", "Este feitiço transporta instantaneamente você e até oito criaturas dispostas de sua escolha que você possa ver no alcance, ou um único objeto que você possa ver no alcance, para um destino que você seleciona. Se você alvejar um objeto, ele deve caber inteiramente dentro de um cubo de 3 metros, e não pode ser mantido ou carregado por uma criatura não disposta. O destino que você escolhe deve ser conhecido por você, e deve estar no mesmo plano de existência que você. Sua familiaridade com o destino determina se você chega lá com sucesso. O mestre faz um teste de d100 e consulta a tabela.", ["Bardo", "Feiticeiro", "Mago"], false, false, ""),
  sp("Tempestade de Fogo", 7, "Evocação", "1 ação", "150 pés", "Instantâneo", true, true, false, "", "Uma tempestade de folhas de chamas rugidoras aparece em um local que você escolhe ao alcance. A área da tempestade consiste em até dez cubos de 10 pés, que você pode organizar como desejar. Cada cubo deve ter pelo menos uma face adjacente à face de outro cubo. Cada criatura na área deve fazer um teste de resistência de Destreza. Ela sofre 7d10 de dano de fogo em uma falha, ou metade do dano em um sucesso. O fogo danifica objetos na área e incendeia objetos inflamáveis que não estão sendo usados ou carregados. Se desejar, a vida vegetal na área não é afetada por esta magia.", ["Clérico", "Druida", "Feiticeiro"], false, false, ""),
  sp("Antipatia/Simpatia", 8, "Encantamento", "1 hora", "18 metros", "10 dias", true, true, true, "Um pedaço de alúmen embebido em vinagre para o efeito de antipatia ou uma gota de mel para o efeito de simpatia.", "Esta magia atrai ou repele criaturas à sua escolha. Você escolhe como alvo algo dentro do alcance, seja uma criatura ou objeto Gigante ou menor, ou uma área que não seja maior que um cubo de 60 metros. Então especifique um tipo de criatura inteligente, como dragões vermelhos, goblins ou vampiros. Você investe o alvo com uma aura que atrai ou repele as criaturas especificadas pela duração. Escolha antipatia ou simpatia como o efeito da aura. Antipatia. O encantamento faz com que criaturas do tipo que você designou sintam uma urgência intensa de deixar a área e evitar o alvo. Quando tal criatura consegue ver o alvo ou chega a 18 metros dele, a criatura deve ter sucesso em um teste de salvação de Sabedoria ou fica assustada. A criatura permanece assustada enquanto consegue ver o alvo ou está a 18 metros dele. Enquanto assustada pelo alvo, a criatura deve usar seu movimento para se mover para o local seguro mais próximo de onde não consegue ver o alvo. Se a criatura se afasta mais de 18 metros do alvo e não consegue vê-lo, a criatura não fica mais assustada, mas fica assustada novamente se recuperar a visão do alvo ou se mover para 18 metros dele. Simpatia. O encantamento faz com que as criaturas especificadas sintam uma urgência intensa de se aproximar do alvo enquanto estiverem a 18 metros dele ou conseguirem vê-lo. Quando tal criatura consegue ver o alvo ou chega a 18 metros dele, a criatura deve ter sucesso em um teste de salvação de Sabedoria ou usar seu movimento em cada um de seus turnos para entrar na área ou se mover para o alcance do alvo. Quando a criatura tiver feito isso, ela não pode se afastar voluntariamente do alvo. Se o alvo danificar ou prejudicar de outra forma uma criatura afetada, a criatura afetada pode fazer um teste de salvação de Sabedoria para encerrar o efeito, conforme descrito abaixo. Encerrando o Efeito. Se uma criatura afetada termina seu turno enquanto não está a 18 metros do alvo ou não consegue vê-lo, a criatura faz um teste de salvação de Sabedoria. Com um sucesso, a criatura não é mais afetada pelo alvo e reconhece a sensação de repugnância ou atração como mágica. Além disso, uma criatura afetada pela magia pode fazer outro teste de salvação de Sabedoria a cada 24 horas enquanto a magia persiste. Uma criatura que tenha sucesso ao economizar contra este efeito fica imune a ele por 1 minuto, após o qual pode ser afetada novamente.", ["Druida", "Mago"], false, false, ""),
  sp("Aura Sagrada", 8, "Abjuração", "1 ação", "Pessoal", "Até 1 minuto", true, true, true, "Um pequeno relicário no valor de pelo menos 1.000 po contendo uma relíquia sagrada, como um pedaço de tecido da roupa de um santo ou um pedaço de pergaminho de um texto religioso.", "Luz divina emana de você e se coalesce em um brilho suave em um raio de 30 pés ao seu redor. Criaturas à sua escolha nesse raio quando você conjura essa magia emitem luz fraca em um raio de 5 pés e têm vantagem em todos os testes de resistência, e outras criaturas têm desvantagem em testes de ataque contra elas até a magia terminar. Além disso, quando um fiend ou morto-vivo atinge uma criatura afetada com um ataque de corpo a corpo, a aura pisca com luz brilhante. O atacante deve ter sucesso em um teste de resistência de Constituição ou ficar cego até a magia terminar.", ["Clérico"], false, true, ""),
  sp("Campo Antimagia", 8, "Abjuração", "1 ação", "Pessoal", "Até 1 hora", true, true, true, "Uma pitada de pó de ferro ou limalha de ferro", "Uma esfera invisível de antimagia com raio de 3 metros a rodeia. Esta área está divorciada da energia mágica que permeia o multiverso. Dentro da esfera, magias não podem ser lançadas, criaturas invocadas desaparecem, e até mesmo itens mágicos se tornam mundanos. Até que a magia termine, a esfera se move com você, centrada em você. Magias e outros efeitos mágicos, exceto aqueles criados por um artefato ou uma divindade, são suprimidos na esfera e não podem se estender para dentro dela. Um espaço gasto para lançar uma magia suprimida é consumido. Enquanto um efeito é suprimido, ele não funciona, mas o tempo que passa suprimido conta contra sua duração. Efeitos Direcionados. Magias e outros efeitos mágicos, como Míssil Mágico e Enfeitiçar Pessoa, que direcionam uma criatura ou um objeto na esfera não têm efeito naquele alvo. Áreas de Magia. A área de outra magia ou efeito mágico, como Bola de Fogo, não pode se estender para dentro da esfera. Se a esfera se sobrepõe a uma área de magia, a parte da área coberta pela esfera é suprimida. Por exemplo, as chamas criadas por uma Parede de Fogo são suprimidas dentro da esfera, criando uma lacuna na parede se a sobreposição for grande o suficiente. Magias. Qualquer magia ativa ou outro efeito mágico em uma criatura ou objeto na esfera é suprimido enquanto a criatura ou objeto está nela. Itens Mágicos. As propriedades e poderes de itens mágicos são suprimidos na esfera. Por exemplo, uma espada longa +1 na esfera funciona como uma espada longa não mágica. Os poderes e propriedades de uma arma mágica são suprimidos se for usada contra um alvo na esfera ou empunhada por um atacante na esfera. Se uma arma mágica ou uma munição mágica sair completamente da esfera (por exemplo, se você dispara uma flecha mágica ou lança uma lança mágica a um alvo fora da esfera), a magia do item deixa de ser suprimida assim que sai. Viagem Mágica. Teleportação e viagem planar falham em funcionar na esfera, quer a esfera seja o destino ou o ponto de partida para tal viagem mágica. Um portal para outro local, mundo ou plano de existência, bem como uma abertura para um espaço extradimensional como aquele criado pela magia Corda Mágica, fecha temporariamente enquanto está na esfera. Criaturas e Objetos. Uma criatura ou objeto invocado ou criado por magia pisca temporariamente fora de existência na esfera. Tal criatura reaparece instantaneamente uma vez que o espaço que a criatura ocupava não está mais dentro da esfera. Dissipar Magia. Magias e efeitos mágicos como Dissipar Magia não têm efeito na esfera. Da mesma forma, as esferas criadas por diferentes magias de Campo Antimagia não se anulam mutuamente.", ["Clérico", "Mago"], false, true, ""),
  sp("Clone", 8, "Necromancia", "1 hora", "Toque", "Instantâneo", true, true, true, "Um diamante no valor de no mínimo 1.000 gp e no mínimo 1 polegada cúbica de carne da criatura a ser clonada, que a magia consome, e um recipiente no valor de no mínimo 2.000 gp que tenha uma tampa selável e seja grande o suficiente para conter uma criatura Média, como uma urna enorme, caixão, cisto preenchido com lama no solo, ou recipiente de cristal preenchido com água salgada.", "Esta magia cultiva uma duplicação inerte de uma criatura viva como salvaguarda contra a morte. Este clone se forma dentro de um recipiente selado e cresce até o tamanho e maturidade plenos após 120 dias; você também pode escolher fazer o clone ser uma versão mais jovem da mesma criatura. Permanece inerte e perdura indefinidamente, contanto que seu recipiente permaneça intacto. A qualquer momento após o clone amadurecer, se a criatura original morrer, sua alma se transfere para o clone, desde que a alma esteja livre e disposta a retornar. O clone é fisicamente idêntico ao original e possui a mesma personalidade, memórias e habilidades, mas nenhum dos equipamentos do original. Os restos físicos da criatura original, se ainda existirem, tornam-se inertes e não podem ser restaurados à vida, pois a alma da criatura está em outro lugar.", ["Mago"], false, false, ""),
  sp("Controlar Clima", 8, "Transmutação", "10 minutos", "Pessoal", "Até 8 horas", true, true, true, "Incenso queimado e pedaços de terra e madeira misturados em água", "Você toma controle do clima dentro de 5 milhas de você pela duração. Você deve estar ao ar livre para lançar essa magia. Se mover para um lugar onde você não tem um caminho desobstruído para o céu encerra a magia cedo. Quando você lança a magia, você muda as condições climáticas atuais, que são determinadas pelo Mestre baseado no clima e estação. Você pode mudar precipitação, temperatura e vento. Leva 1d4 x 10 minutos para as novas condições entrarem em efeito. Uma vez que isso aconteça, você pode mudar as condições novamente. Quando a magia termina, o clima gradualmente retorna ao normal. Quando você muda as condições climáticas, encontre uma condição atual nas tabelas a seguir e mude seu estágio por um, para cima ou para baixo. Quando mudar o vento, você pode mudar sua direção.", ["Clérico", "Druida", "Mago"], false, true, ""),
  sp("Demiplanode", 8, "Conjuração", "1 ação", "18 metros", "1 hora", false, true, false, "", "Você cria uma porta sombria em uma superfície plana e sólida que você pode ver dentro do alcance. A porta é grande o suficiente para permitir que criaturas Médias passem por ela sem impedimentos. Quando aberta, a porta leva a um demiplanode que parece ser uma sala vazia com 9 metros em cada dimensão, feita de madeira ou pedra. Quando o feitiço termina, a porta desaparece, e quaisquer criaturas ou objetos dentro do demiplanode permanecem presos lá, pois a porta também desaparece do outro lado. Cada vez que você lança este feitiço, você pode criar um novo demiplanode, ou fazer a porta sombria se conectar a um demiplanode que você criou com uma lançada anterior deste feitiço. Além disso, se você conhece a natureza e o conteúdo de um demiplanode criado por uma lançada deste feitiço por outra criatura, você pode fazer a porta sombria se conectar ao seu demiplanode.", ["Bruxo", "Mago"], false, false, ""),
  sp("Dominar Monstro", 8, "Encantamento", "1 ação", "60 pés", "Até 1 hora", true, true, false, "", "Você tenta enganar uma criatura que você possa ver dentro do alcance. Ela deve fazer um teste de salvação de Sabedoria ou ser enfeitiçada por você pela duração. Se você ou criaturas que lhe são amigáveis estiverem lutando contra ela, ela terá vantagem no teste de salvação. Enquanto a criatura estiver enfeitiçada, você terá um vínculo telepático com ela desde que vocês dois estejam no mesmo plano de existência. Você pode usar este vínculo telepático para dar comandos à criatura enquanto estiver consciente (nenhuma ação necessária), que ela faz o melhor para obedecer. Você pode especificar um curso de ação simples e geral, como \"Ataque aquela criatura\", \"Corra para lá\" ou \"Traga aquele objeto\". Se a criatura completar a ordem e não receber mais orientações suas, ela se defende e se preserva da melhor forma possível. Você pode usar sua ação para assumir o controle total e preciso do alvo. Até o final do seu próximo turno, a criatura realiza apenas as ações que você escolher e não faz nada que você não permita. Durante este tempo, você também pode fazer a criatura usar uma reação, mas isso exige que você também use sua própria reação. Cada vez que o alvo recebe dano, ele faz um novo teste de salvação de Sabedoria contra a magia. Se o teste de salvação for bem-sucedido, a magia acaba.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, true, "Quando você lança esta magia usando um espaço de magia de 9º nível, a duração é concentração, até 8 horas."),
  sp("Eloquência", 8, "Transmutação", "1 ação", "Pessoal", "1 hora", true, false, false, "", "Até o final da magia, quando você faz uma teste de Carisma, você pode substituir o número que você rolou por um 15. Além disso, não importa o que você diga, magia que determinaria se você está dizendo a verdade indica que você está sendo veraz.", ["Bardo", "Bruxo"], false, false, ""),
  sp("Enfraquecimento Mental", 8, "Encantamento", "1 ação", "45 metros", "Instantâneo", true, true, true, "Um punhado de argila, cristal, vidro ou esferas minerais.", "Você ataca a mente de uma criatura que você pode ver dentro do alcance, tentando despedaçar seu intelecto e personalidade. O alvo sofre 4d6 de dano psíquico e deve fazer um teste de salvação de Inteligência. Se falhar, os atributos de Inteligência e Carisma da criatura se tornam 1. A criatura não pode lançar magias, ativar itens mágicos, entender linguagem ou se comunicar de forma inteligível. A criatura pode, no entanto, identificar seus amigos, segui-los e até protegê-los. Ao final de cada 30 dias, a criatura pode repetir o teste de salvação contra essa magia. Se conseguir, a magia termina. A magia também pode ser encerrada por restauração maior, cura ou desejo.", ["Bardo", "Druida", "Bruxo", "Mago"], false, false, ""),
  sp("Explosão Solar", 8, "Evocação", "1 ação", "150 pés", "Instantâneo", true, true, true, "Fogo e um pedaço de pedra solar.", "A luz solar brilhante pisca em um raio de 60 pés centrado em um ponto que você escolhe dentro do alcance. Cada criatura naquela luz deve fazer um teste de resistência de Constituição. Se falhar na resistência, uma criatura sofre 12d6 de dano radiante e fica cega por 1 minuto. Se passar na resistência, sofre metade do dano e não fica cega por esse feitiço. Mortos-vivos e lodos têm desvantagem nesse teste de resistência. Uma criatura cegada por esse feitiço faz outro teste de resistência de Constituição ao final de cada um de seus turnos. Se passar na resistência, não fica mais cega. Este feitiço dissipa qualquer escuridão em sua área que foi criada por um feitiço.", ["Druida", "Feiticeiro", "Mago"], false, false, ""),
  sp("Formas Animais", 8, "Transmutação", "1 ação", "9 metros", "Até 24 horas", true, true, false, "", "Sua magia transforma outros em bestas. Escolha qualquer número de criaturas dispostas que você possa ver dentro do alcance. Você transforma cada alvo na forma de uma besta Grande ou menor com uma classificação de desafio de 4 ou inferior. Nos turnos subsequentes, você pode usar sua ação para transformar criaturas afetadas em novas formas. A transformação dura pela duração para cada alvo, ou até que o alvo caia a 0 pontos de vida ou morra. Você pode escolher uma forma diferente para cada alvo. As estatísticas do jogo de um alvo são substituídas pelas estatísticas da besta escolhida, embora o alvo retenha seu alinhamento e pontuações de Inteligência, Sabedoria e Carisma. O alvo assume os pontos de vida de sua nova forma, e quando volta à sua forma normal, retorna ao número de pontos de vida que tinha antes de se transformar. Se reverter como resultado de cair a 0 pontos de vida, qualquer dano excessivo se transfere para sua forma normal. Contanto que o dano excessivo não reduza a forma normal da criatura a 0 pontos de vida, ela não fica inconsciente. A criatura é limitada nas ações que pode executar pela natureza de sua nova forma, e não pode falar ou lançar magias. O equipamento do alvo se funde com a nova forma. O alvo não pode ativar, empunhar ou se beneficiar de nenhum de seus equipamentos.", ["Druida"], false, true, ""),
  sp("Labirinto", 8, "Conjuração", "1 ação", "60 pés", "Até 10 minutos", true, true, false, "", "Você desterro uma criatura que possa ver dentro do alcance para um semiplano labiríntico. O alvo permanece lá durante a duração ou até escapar do labirinto. O alvo pode usar sua ação para tentar escapar. Quando faz isso, ele faz uma teste de Inteligência CD 20. Se obtiver sucesso, escapa e a magia termina (um minotauro ou demônio goristro obtém sucesso automaticamente). Quando a magia termina, o alvo reaparece no espaço que deixou ou, se esse espaço estiver ocupado, no espaço desocupado mais próximo.", ["Mago"], false, true, ""),
  sp("Mente em Branco", 8, "Abjuração", "1 ação", "Toque", "24 horas", true, true, false, "", "Até a magia terminar, uma criatura desejosa que você toca é imune a dano psíquico, qualquer efeito que sentiria suas emoções ou leria seus pensamentos, magias de adivinhação e a condição enfeitiçada. A magia até frustra magias de desejo e magias ou efeitos de poder similar usados para afetar a mente do alvo ou para ganhar informação sobre o alvo.", ["Bardo", "Mago"], false, false, ""),
  sp("Nuvem Incandescente", 8, "Conjuração", "1 ação", "150 pés", "Até 1 minuto", true, true, false, "", "Uma nuvem turbilhonante de fumaça atravessada por brasas branco-quentes aparece em uma esfera de raio de 20 pés centrada em um ponto dentro do alcance. A nuvem se espalha pelos cantos e está muito obscurecida. Dura pela duração ou até que um vento de velocidade moderada ou maior (pelo menos 10 milhas por hora) a disperse. Quando a nuvem aparece, cada criatura nela deve fazer um teste de resistência de destreza. Uma criatura sofre 10d8 de dano de fogo em um falha, ou metade do dano em um sucesso. Uma criatura também deve fazer este teste de resistência quando entra na área da magia pela primeira vez em um turno ou termina seu turno lá. A nuvem se move 10 pés diretamente para longe de você em uma direção que você escolhe no início de cada um de seus turnos.", ["Feiticeiro", "Mago"], false, true, ""),
  sp("Palavra de Poder: Atordoar", 8, "Encantamento", "1 ação", "60 pés", "Instantâneo", true, false, false, "", "Você fala uma palavra de poder que pode sobrecarregar a mente de uma criatura que você pode ver dentro do alcance, deixando-a atordoada. Se o alvo tiver 150 pontos de vida ou menos, ele fica atordoado. Caso contrário, a magia não tem efeito. O alvo atordoado deve fazer um teste de resistência de constituição no final de cada um de seus turnos. Em um teste bem-sucedido, este efeito de atordoamento termina.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Terremoto", 8, "Evocação", "1 ação", "500 pés", "Até 1 minuto", true, true, true, "Um polegar de terra, um pedaço de rocha e um nódulo de argila.", "Você cria uma perturbação sísmica em um ponto no solo que você possa ver dentro do alcance. Pela duração, um tremor intenso rasgará o solo em um círculo de raio de 100 pés centrado naquele ponto e sacudirá criaturas e estruturas em contato com o solo naquela área. O solo na área se torna terreno difícil. Cada criatura no solo que está se concentrando deve fazer um teste de salvação de Constituição. Em um salvamento falhado, a concentração da criatura é quebrada. Quando você lança esta magia e no final de cada turno em que você gasta concentrando nela, cada criatura no solo na área deve fazer um teste de salvação de Destreza. Em um salvamento falhado, a criatura é derrubada. Esta magia pode ter efeitos adicionais dependendo do terreno na área, conforme determinado pelo Mestre. Fissuras. Fissuras se abrem pela área da magia no início do seu próximo turno após você lançar a magia. Um total de 1d6 tais fissuras se abrem em locais escolhidos pelo Mestre. Cada uma tem 1d10 x 10 pés de profundidade, 10 pés de largura e se estende de uma borda da área da magia para o lado oposto. Uma criatura em pé em um local onde uma fissura se abre deve fazer um teste de salvação de Destreza ou cair dentro. Uma criatura que salva com sucesso se move com a borda da fissura conforme se abre. Uma fissura que se abre sob uma estrutura faz com que ela desabe automaticamente (veja abaixo). Estruturas. O tremor causa 50 de dano de concussão a qualquer estrutura em contato com o solo na área quando você lança a magia e no início de cada um de seus turnos até a magia acabar. Se uma estrutura cair para 0 pontos de vida, ela desaba e potencialmente danifica criaturas próximas. Uma criatura dentro de metade da distância da altura de uma estrutura deve fazer um teste de salvação de Destreza. Em um salvamento falhado, a criatura sofre 5d6 de dano de concussão, é derrubada e é enterrada nos escombros, exigindo um teste de Força (Atletismo) DC 20 como uma ação para escapar. O Mestre pode ajustar o DC mais alto ou mais baixo, dependendo da natureza dos escombros. Em um salvamento bem-sucedido, a criatura sofre metade do dano e não cai ou fica enterrada.", ["Clérico", "Druida", "Feiticeiro"], false, true, ""),
  sp("Aprisionamento", 9, "Abjuração", "1 minuto", "30 pés", "Até ser dissipada", true, true, true, "Uma representação em velinho ou uma estatueta esculpida à semelhança do alvo, e um componente especial que varia de acordo com a versão da magia que você escolher, no valor de pelo menos 500 po por Dado de Vida do alvo.", "Você cria uma restrição mágica para manter uma criatura que possa ver ao alcance. O alvo deve ter sucesso em um teste de salvação de Sabedoria ou fica vinculado pela magia; se tiver sucesso, fica imune a esta magia se você a lançar novamente. Enquanto afetada por esta magia, a criatura não precisa respirar, comer ou beber, e não envelhece. Magias de adivinhação não podem localizar ou perceber o alvo. Quando você lança a magia, escolhe uma das seguintes formas de aprisionamento. Enterro. O alvo é enterrado muito abaixo da terra em uma esfera de força mágica que é apenas grande o suficiente para contê-lo. Nada pode passar pela esfera, nem criatura alguma pode se teleportar ou usar viagem planar para entrar ou sair dela. O componente especial para esta versão da magia é uma pequena esfera de mitral. Correntes. Correntes pesadas, firmemente enraizadas no solo, mantêm o alvo no lugar. O alvo fica contido até a magia terminar, e não pode se mover ou ser movido de forma alguma até então. O componente especial para esta versão da magia é uma corrente fina de metal precioso. Prisão Coberta. A magia transporta o alvo para um diminuto semiplano que é protegido contra teleportação e viagem planar. O semiplano pode ser um labirinto, uma gaiola, uma torre ou qualquer estrutura confinada ou área similar de sua escolha. O componente especial para esta versão da magia é uma representação em miniatura da prisão feita de jade. Contenção Mínima. O alvo encolhe para uma altura de 1 polegada e é aprisionado dentro de uma pedra preciosa ou objeto similar. A luz pode passar normalmente pela pedra preciosa (permitindo que o alvo veja para fora e outras criaturas vejam para dentro), mas nada mais pode passar, nem mesmo por teleportação ou viagem planar. A pedra preciosa não pode ser cortada ou quebrada enquanto a magia permanecer em efeito. O componente especial para esta versão da magia é uma grande pedra preciosa transparente, como um coríndon, diamante ou rubi. Adormecimento. O alvo adormece e não pode ser despertado. O componente especial para esta versão da magia consiste em ervas soporíferas raras. Terminando a Magia. Durante o lançamento da magia, em qualquer de suas versões, você pode especificar uma condição que causará o término da magia e libertará o alvo. A condição pode ser tão específica ou elaborada quanto você escolher, mas o DM deve concordar que a condição é razoável e tem probabilidade de acontecer. As condições podem ser baseadas no nome, identidade ou divindade de uma criatura, mas caso contrário devem ser baseadas em ações ou qualidades observáveis e não em intangíveis como nível, classe ou pontos de vida. Uma magia Dissipar Magia pode terminar a magia apenas se for lançada como uma magia de 9º nível, visando a prisão ou o componente especial usado para criá-la. Você pode usar um componente especial particular para criar apenas uma prisão por vez. Se lançar a magia novamente usando o mesmo componente, o alvo do primeiro lançamento é imediatamente libertado de sua ligação.", ["Bruxo", "Mago"], false, false, ""),
  sp("Chuva de Meteoros", 9, "Evocação", "1 ação", "1 milha", "Instantânea", true, true, false, "", "Esferas de fogo incandescente caem do céu em quatro pontos diferentes que você consegue ver dentro do alcance. Cada criatura em uma esfera de raio de 40 pés centrada em cada ponto que você escolher deve fazer um teste de salvação de Destreza. A esfera se espalha ao redor de esquinas. Uma criatura recebe 20d6 de dano de fogo e 20d6 de dano de concussão em um teste de salvação fracassado, ou metade do dano em um sucesso. Uma criatura na área de mais de uma explosão ígnia é afetada apenas uma vez. A magia danifica objetos na área e incendeia objetos inflamáveis que não estão sendo usados ou carregados.", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Cura em Massa Maior", 9, "Conjuração", "1 ação", "60 pés", "Instantâneo", true, true, false, "", "Uma enxurrada de energia curativa flui de você para as criaturas feridas ao seu redor. Você restaura até 700 pontos de vida, divididos como você escolher entre qualquer número de criaturas que você pode ver ao alcance. Criaturas curadas por essa magia também são curadas de todas as doenças e qualquer efeito deixando-as cegas ou surdas. Essa magia não tem efeito em mortos-vivos ou construtos.", ["Clérico"], false, false, ""),
  sp("Desejo", 9, "Conjuração", "1 ação", "Pessoal", "Instantâneo", true, false, false, "", "Desejo é a magia mais poderosa que uma criatura mortal pode lançar. Simplesmente falando em voz alta, você pode alterar os próprios fundamentos da realidade de acordo com seus desejos. O uso básico desta magia é duplicar qualquer outra magia de 8º nível ou inferior. Você não precisa atender a nenhum requisito naquela magia, incluindo componentes caros. A magia simplesmente toma efeito. Alternativamente, você pode criar um dos seguintes efeitos à sua escolha: - Você cria um objeto de até 25.000 po de valor que não seja um item mágico. O objeto não pode ter mais de 300 pés em qualquer dimensão e aparece em um espaço desocupado que você pode ver no chão. - Você permite que até vinte criaturas que você pode ver recuperem todos os pontos de vida e você encerra todos os efeitos nelas descritos na magia restauração maior. - Você concede a até dez criaturas que você pode ver resistência a um tipo de dano que escolher. - Você concede a até dez criaturas que você pode ver imunidade a uma única magia ou outro efeito mágico por 8 horas. Por exemplo, você poderia fazer você e todos seus companheiros imunes ao ataque de drenagem de vida de um lich. - Você desfaz um único evento recente forçando um relançamento de qualquer rolagem feita no último turno (incluindo seu último turno). A realidade se reforma para acomodar o novo resultado. Por exemplo, uma magia desejo poderia desfazer um salvamento bem-sucedido de um oponente, um golpe crítico de um inimigo ou um salvamento falhado de um aliado. Você pode forçar o relançamento a ser feito com vantagem ou desvantagem e pode escolher se usa o relançamento ou a rolagem original. Você pode conseguir algo além do escopo dos exemplos acima. Declare seu desejo ao Mestre o mais precisamente possível. O Mestre tem grande liberdade em decidir o que ocorre em tal situação; quanto maior o desejo, maior a probabilidade de algo dar errado. Esta magia pode simplesmente falhar, o efeito desejado pode ser apenas parcialmente alcançado ou você pode sofrer alguma consequência imprevista como resultado de como você expressou o desejo. Por exemplo, desejar que um vilão estivesse morto pode propulsioná-lo adiante no tempo para um período quando esse vilão não está mais vivo, removendo-o efetivamente do jogo. Similarmente, desejar um item mágico lendário ou artefato pode transportá-lo instantaneamente para a presença do proprietário atual do item. O estresse de lançar esta magia para produzir qualquer efeito que não seja duplicar outra magia o enfraquece. Após suportar esse estresse, cada vez que você lança uma magia até terminar um repouso longo, você sofre 1d10 de dano necrótico por nível dessa magia. Este dano não pode ser reduzido ou prevenido de forma alguma. Além disso, sua Força cai para 3, se já não for 3 ou menor, por 2d4 dias. Para cada um desses dias que você gasta descansando e fazendo nada mais do que atividade leve, seu tempo de recuperação restante diminui em 2 dias. Finalmente, há uma chance de 33 por cento de que você seja incapaz de lançar desejo novamente se sofrer esse estresse.", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Estranho", 9, "Ilusão", "1 ação", "120 pés", "Até 1 minuto", true, true, false, "", "Invocando os medos mais profundos de um grupo de criaturas, você cria criaturas ilusórias em suas mentes, visíveis apenas para elas. Cada criatura em uma esfera de 30 pés de raio centrada em um ponto à sua escolha dentro do alcance deve fazer um teste de salvação de Sabedoria. Em uma falha, uma criatura fica assustada pela duração. A ilusão invoca os medos mais profundos da criatura, manifestando seus piores pesadelos como uma ameaça implacável. No início de cada turno da criatura assustada, ela deve ter sucesso em um teste de salvação de Sabedoria ou sofrer 4d10 de dano psíquico. Em um salvamento bem-sucedido, a magia termina para aquela criatura.", ["Mago"], false, true, ""),
  sp("Mudar de Forma", 9, "Transmutação", "1 ação", "Pessoal", "Até 1 hora", true, true, true, "Um círculo de jade no valor de pelo menos 1.500 po, que você deve colocar na cabeça antes de lançar a magia.", "Você assume a forma de uma criatura diferente pela duração. A nova forma pode ser de qualquer criatura com uma classificação de desafio igual ao seu nível ou menor. A criatura não pode ser um constructo ou morto-vivo, e você deve ter visto esse tipo de criatura pelo menos uma vez. Você se transforma em um exemplar médio dessa criatura, sem quaisquer níveis de classe ou a característica Lançamento de Magia. Suas estatísticas de jogo são substituídas pelas estatísticas da criatura escolhida, embora você retenha seu alinhamento e suas pontuações de Inteligência, Sabedoria e Carisma. Você também retém todas as suas proficiências em perícias e testes de resistência, além de ganhar as da criatura. Se a criatura tiver a mesma proficiência que você e o bônus listado em suas estatísticas for maior que o seu, use o bônus da criatura no lugar do seu. Você não pode usar nenhuma ação lendária ou ação de covil da nova forma. Você assume os pontos de vida e Dados de Vida da nova forma. Quando você volta à sua forma normal, retorna ao número de pontos de vida que tinha antes de se transformar. Se você reverter como resultado de cair a 0 pontos de vida, qualquer dano excedente é transferido para sua forma normal. Contanto que o dano excedente não reduza sua forma normal a 0 pontos de vida, você não fica inconsciente. Você retém o benefício de quaisquer características de sua classe, raça ou outra fonte e pode usá-las, desde que sua nova forma seja fisicamente capaz de fazê-lo. Você não pode usar nenhum sentido especial que possui (por exemplo, visão no escuro) a menos que sua nova forma também tenha esse sentido. Você só pode falar se a criatura normalmente puder falar. Quando você se transforma, escolhe se seu equipamento cai no chão, se funde à nova forma ou é usado por ela. O equipamento usado funciona normalmente. O Mestre determina se é prático que a nova forma use uma peça de equipamento, com base na forma e tamanho da criatura. Seu equipamento não muda de forma ou tamanho para corresponder à nova forma, e qualquer equipamento que a nova forma não possa usar deve cair no chão ou se fundir à sua nova forma. O equipamento que se funde não tem efeito nesse estado. Durante a duração desta magia, você pode usar sua ação para assumir uma forma diferente seguindo as mesmas restrições e regras da forma original, com uma exceção: se sua nova forma tiver mais pontos de vida que a atual, seus pontos de vida permanecem em seu valor atual.", ["Druida", "Mago"], false, true, ""),
  sp("Muro Prismático", 9, "Abjuração", "1 ação", "60 pés", "10 minutos", true, true, false, "", "Um plano cintilante e multicolorido de luz forma uma parede opaca vertical -- de até 90 pés de comprimento, 30 pés de altura e 1 polegada de espessura -- centrada em um ponto que você pode ver ao alcance. Alternativamente, você pode moldar a parede em uma esfera de até 30 pés de diâmetro centrada em um ponto que você escolhe ao alcance. A parede permanece no lugar pela duração. Se você posicionar a parede para que ela passe por um espaço ocupado por uma criatura, a magia falha e sua ação e o espaço de magia são desperdiçados. A parede emite luz brilhante até um alcance de 100 pés e luz fraca por mais 100 pés. Você e as criaturas que você designar no momento em que conjura a magia podem passar através e permanecer perto da parede sem sofrer dano. Se outra criatura que pode ver a parede se move para dentro de 20 pés dela ou inicia seu turno lá, a criatura deve fazer um teste de resistência de Constituição ou ficar cega por 1 minuto. A parede consiste em sete camadas, cada uma com uma cor diferente. Quando uma criatura tenta alcançar ou passar através da parede, ela o faz uma camada por vez através de todas as camadas da parede. Conforme passa ou alcança cada camada, a criatura deve fazer um teste de resistência de Destreza ou ser afetada pelas propriedades dessa camada conforme descrito abaixo. A parede pode ser destruída, também uma camada por vez, em ordem de vermelho a violeta, por meios específicos de cada camada. Uma vez que uma camada é destruída, ela permanece assim pela duração da magia. Uma vara de cancelamento destrói um muro prismático, mas um campo antimagia não tem efeito sobre ele. 1. Vermelho. A criatura sofre 10d6 de dano de fogo em um teste falhado, ou metade desse dano em um bem-sucedido. Enquanto esta camada estiver no lugar, ataques à distância não mágicos não podem passar através da parede. A camada pode ser destruída causando pelo menos 25 de dano de frio a ela. 2. Laranja. A criatura sofre 10d6 de dano de ácido em um teste falhado, ou metade desse dano em um bem-sucedido. Enquanto esta camada estiver no lugar, ataques mágicos à distância não podem passar através da parede. A camada é destruída por um vento forte. 3. Amarelo. A criatura sofre 10d6 de dano de relâmpago em um teste falhado, ou metade desse dano em um bem-sucedido. Esta camada pode ser destruída causando pelo menos 60 de dano de força a ela. 4. Verde. A criatura sofre 10d6 de dano de veneno em um teste falhado, ou metade desse dano em um bem-sucedido. Uma magia passagem mural, ou outra magia de nível igual ou maior que possa abrir um portal em uma superfície sólida, destrói esta camada. 5. Azul. A criatura sofre 10d6 de dano de frio em um teste falhado, ou metade desse dano em um bem-sucedido. Esta camada pode ser destruída causando pelo menos 25 de dano de fogo a ela. 6. Índigo. Em um teste falhado, a criatura fica contida. Ela deve então fazer um teste de resistência de Constituição no final de cada um de seus turnos. Se ela salva com sucesso três vezes, a magia termina. Se ela falhar em seu teste três vezes, ela se transforma permanentemente em pedra e fica sujeita à condição petrificada. Os sucessos e fracassos não precisam ser consecutivos; acompanhe ambos até a criatura coletar três do mesmo tipo. Enquanto esta camada estiver no lugar, magias não podem ser lançadas através da parede. A camada é destruída por luz brilhante emitida por uma magia luz do dia ou uma magia similar de nível igual ou superior. 7. Violeta. Em um teste falhado, a criatura fica cega. Ela deve então fazer um teste de resistência de Sabedoria no início do seu próximo turno. Um teste bem-sucedido termina a cegueira. Se ela falhar nesse teste, a criatura é transportada para outro plano à escolha do Mestre e não fica mais cega. (Normalmente, uma criatura que está em um plano que não é seu plano natal é banida para casa, enquanto outras criaturas geralmente são lançadas nos planos Astral ou Etéreo.) Esta camada é destruída por uma magia dissipar magia ou uma magia similar de nível igual ou superior que possa terminar magias e efeitos mágicos.", ["Mago"], false, false, ""),
  sp("Palavra de Poder: Morte", 9, "Encantamento", "1 ação", "60 pés", "Instantâneo", true, false, false, "", "Você pronuncia uma palavra de poder que pode compelir uma criatura que você pode ver dentro do alcance a morrer instantaneamente. Se a criatura que você escolher tiver 100 pontos de vida ou menos, ela morre. Caso contrário, a magia não tem efeito.", ["Bardo", "Feiticeiro", "Bruxo", "Mago"], false, false, ""),
  sp("Parada do Tempo", 9, "Transmutação", "1 ação", "Pessoal", "Instantâneo", true, false, false, "", "Você para brevemente o fluxo do tempo para todos exceto você mesmo. Nenhum tempo passa para outras criaturas, enquanto você faz 1d4 + 1 turnos seguidos, durante os quais você pode usar ações e se mover normalmente. Este feitiço termina se uma das ações que você usa durante este período, ou qualquer efeito que você cria durante este período, afeta uma criatura que não seja você ou um objeto sendo usado ou carregado por alguém que não seja você. Além disso, o feitiço termina se você se mover para um local a mais de 300 metros de distância do local onde você lançou.", ["Feiticeiro", "Mago"], false, false, ""),
  sp("Polimorfismo Verdadeiro", 9, "Transmutação", "1 ação", "30 pés", "Até 1 hora", true, true, true, "Uma gota de mercúrio, um pouco de goma-arábica e um fio de fumaça.", "Escolha uma criatura ou um objeto não mágico que você possa ver ao seu alcance. Você transforma a criatura em uma criatura diferente, a criatura em um objeto, ou o objeto em uma criatura (o objeto não deve estar sendo vestido nem carregado por outra criatura). A transformação dura pela duração, ou até o alvo cair para 0 pontos de vida ou morrer. Se você se concentrar nesta magia pela duração completa, a transformação se torna permanente. Metamorfos não são afetados por esta magia. Uma criatura relutante pode fazer um teste de resistência de Sabedoria e, se obtiver sucesso, não é afetada por esta magia. Criatura em Criatura: Se você transformar uma criatura em outro tipo de criatura, a nova forma pode ser qualquer tipo que você escolha cuja classificação de desafio seja igual ou menor que a do alvo (ou seu nível, se o alvo não tiver classificação de desafio). As estatísticas do jogo do alvo, incluindo pontuações de habilidades mentais, são substituídas pelas estatísticas da nova forma. Retém seu alinhamento e personalidade. O alvo assume os pontos de vida de sua nova forma, e quando reverte para sua forma normal, a criatura retorna ao número de pontos de vida que tinha antes de se transformar. Se reverteu como resultado de cair a 0 pontos de vida, qualquer dano excedente se transfere para sua forma normal. Desde que o dano excedente não reduza a forma normal da criatura a 0 pontos de vida, ela não é deixada inconsciente. A criatura é limitada nas ações que pode realizar pela natureza de sua nova forma, e não pode falar, lançar magias ou realizar qualquer outra ação que exija mãos ou fala, a menos que sua nova forma seja capaz de tais ações. O equipamento do alvo se funde à nova forma. A criatura não pode ativar, usar, empunhar ou se beneficiar de nenhum de seus equipamentos. Objeto em Criatura: Você pode transformar um objeto em qualquer tipo de criatura, desde que o tamanho da criatura não seja maior que o tamanho do objeto e a classificação de desafio da criatura seja 9 ou menor. A criatura é amigável com você e seus companheiros. Ela age em cada um de seus turnos. Você decide qual ação ela realiza e como se move. O Mestre tem as estatísticas da criatura e resolve todas as suas ações e movimentos. Se a magia se torna permanente, você não controla mais a criatura. Ela pode permanecer amigável com você, dependendo de como a tratou. Criatura em Objeto: Se você transformar uma criatura em um objeto, ela se transforma junto com tudo o que está vestindo e carregando naquela forma. As estatísticas da criatura se tornam as do objeto, e a criatura não tem memória do tempo gasto nesta forma, após a magia terminar e ela retornar à sua forma normal.", ["Bardo", "Bruxo", "Mago"], false, true, ""),
  sp("Portal", 9, "Conjuração", "1 ação", "60 pés", "Até 1 minuto", true, true, true, "Um diamante no valor de pelo menos 5.000 po.", "Você conjura um portal que liga um espaço desocupado que você possa ver dentro do alcance a um local preciso em um plano de existência diferente. O portal é uma abertura circular, que você pode fazer com diâmetro de 5 a 20 pés. Você pode orientar o portal na direção que escolher. O portal dura pela duração. O portal tem uma frente e uma traseira em cada plano onde aparece. É possível viajar pelo portal apenas movendo-se através de sua frente. Qualquer coisa que o faça é instantaneamente transportada para o outro plano, aparecendo no espaço desocupado mais próximo do portal. Deidades e outros governantes planares podem impedir que portais criados por esta magia se abram em sua presença ou em qualquer lugar dentro de seus domínios. Quando você lança esta magia, pode falar o nome de uma criatura específica (um pseudônimo, título ou apelido não funciona). Se essa criatura estiver em um plano diferente daquele em que você está, o portal se abre nas imediações da criatura nomeada e a atrai através dele para o espaço desocupado mais próximo do seu lado do portal. Você não ganha poder especial sobre a criatura, e ela é livre para agir como o Mestre julgar apropriado. Ela pode partir, atacá-lo ou ajudá-lo.", ["Clérico", "Feiticeiro", "Mago"], false, true, ""),
  sp("Previsão", 9, "Adivinhação", "1 minuto", "Toque", "8 horas", true, true, true, "Uma pena de beija-flor.", "Você toca uma criatura disposta e lhe concede a capacidade limitada de ver o futuro imediato. Pela duração, o alvo não consegue ser surpreendido e tem vantagem em testes de ataque, testes de habilidade e testes de salvação. Adicionalmente, outras criaturas têm desvantagem em testes de ataque contra o alvo pela duração. Esta magia termina imediatamente se você a lançar novamente antes de sua duração terminar.", ["Bardo", "Druida", "Bruxo", "Mago"], false, false, ""),
  sp("Projeção Astral", 9, "Necromancia", "1 hora", "10 pés", "Especial", true, true, true, "Para cada criatura que você afeta com esta magia, você deve fornecer um jacinto no valor de pelo menos 1.000 po e uma barra de prata ornamentada no valor de pelo menos 100 po, todos os quais a magia consome.", "Você e até oito criaturas dispostas em alcance projetam seus corpos astrais para o Plano Astral (a magia falha e o lançamento é desperdiçado se você já estiver naquele plano). O corpo material que você deixa para trás fica inconsciente e em estado de animação suspensa; ele não precisa de comida ou ar e não envelhece. Seu corpo astral se assemelha à sua forma mortal em quase todos os sentidos, replicando suas estatísticas de jogo e posses. A principal diferença é a adição de um cordão prateado que se estende de entre suas omoplatas e fica atrás de você, desaparecendo invisível após 1 pé. Este cordão é sua ligação com seu corpo material. Enquanto a ligação permanecer intacta, você pode encontrar seu caminho para casa. Se o cordão for cortado -- algo que só pode acontecer quando um efeito especificamente afirma que faz isso -- sua alma e corpo se separam, matando-o instantaneamente. Sua forma astral pode viajar livremente pelo Plano Astral e pode passar por portais lá levando a qualquer outro plano. Se você entrar em um novo plano ou retornar ao plano em que estava ao lançar esta magia, seu corpo e posses são transportados ao longo do cordão prateado, permitindo que você volte a entrar em seu corpo ao entrar no novo plano. Sua forma astral é uma encarnação separada. Qualquer dano ou outro efeito que se aplique a ela não tem efeito em seu corpo físico, nem persistem quando você retorna a ele. A magia termina para você e seus companheiros quando você usa sua ação para dispensá-la. Quando a magia termina, a criatura afetada retorna a seu corpo físico e acorda. A magia também pode terminar cedo para você ou um de seus companheiros. Uma magia Dissipar Magia lançada com sucesso contra um corpo astral ou físico termina a magia para aquela criatura. Se o corpo original de uma criatura ou sua forma astral cair a 0 pontos de vida, a magia termina para aquela criatura. Se a magia termina e o cordão prateado está intacto, o cordão puxa a forma astral da criatura de volta para seu corpo, terminando seu estado de animação suspensa. Se você for devolvido a seu corpo prematuramente, seus companheiros permanecem em suas formas astrais e devem encontrar seu próprio caminho de volta aos seus corpos, geralmente caindo a 0 pontos de vida.", ["Clérico", "Bruxo", "Mago"], false, false, ""),
  sp("Ressurreição Verdadeira", 9, "Necromancia", "1 hora", "Toque", "Instantânea", true, true, true, "Um polvilho de água benta e diamantes no valor de pelo menos 25.000 po, que a magia consome.", "Você toca uma criatura que está morta há no máximo 200 anos e que morreu por qualquer razão exceto idade avançada. Se a alma da criatura está livre e disposta, a criatura é restaurada à vida com todos os seus pontos de vida. Esta magia fecha todas as feridas, neutraliza qualquer veneno, cura todas as doenças e remove qualquer maldição afetando a criatura quando morreu. A magia substitui órgãos e membros danificados ou faltantes. A magia pode até fornecer um novo corpo se o original não existir mais, caso em que você deve falar o nome da criatura. A criatura então aparece em um espaço desocupado de sua escolha a até 10 pés de você.", ["Clérico", "Druida"], false, false, ""),
  sp("Tempestade da Vingança", 9, "Conjuração", "1 ação", "Visão", "Até 1 minuto", true, true, false, "", "Uma nuvem de tempestade turbilhonante se forma, centrada em um ponto que você pode ver e se espalhando para um raio de 360 pés. Relâmpagos piscam na área, trovões rugem e ventos fortes bramir. Cada criatura sob a nuvem (não mais de 5.000 pés abaixo da nuvem) quando ela aparece deve fazer um teste de resistência de Constituição. Em uma falha, uma criatura sofre 2d6 de dano de trovão e fica surda por 5 minutos. Cada rodada que você mantém concentração neste feitiço, a tempestade produz efeitos adicionais em seu turno. Rodada 2. Chuva ácida cai da nuvem. Cada criatura e objeto sob a nuvem sofre 1d6 de dano ácido. Rodada 3. Você convoca seis raios de relâmpago da nuvem para atingir seis criaturas ou objetos de sua escolha abaixo da nuvem. Uma criatura ou objeto dado não pode ser atingido por mais de um raio. Uma criatura atingida deve fazer um teste de resistência de Destreza. A criatura sofre 10d6 de dano de relâmpago em uma falha, ou metade disso em um sucesso. Rodada 4. Pedras de granizo chove da nuvem. Cada criatura sob a nuvem sofre 2d6 de dano de concussão. Rodada 5-10. Rajadas e chuva congelante atacam a área sob a nuvem. A área se torna terreno difícil e está pesadamente obscurecida. Cada criatura lá sofre 1d6 de dano de frio. Ataques de arma à distância na área são impossíveis. O vento e a chuva contam como uma distração severa para os propósitos de manter concentração em feitiços. Finalmente, rajadas de vento forte (variando de 20 a 50 milhas por hora) dispersam automaticamente névoa, brumas e fenômenos semelhantes na área, sejam mundanos ou mágicos.", ["Druida"], false, true, ""),
];
